import { repositories, createId } from "./core/repositories";
import { store } from "./store";

function nowIso(): string {
  return new Date().toISOString();
}

function assert(condition: unknown, message: string): asserts condition {
  if (!condition) throw new Error(message);
}

// Security helper functions
function assertAdminRole(role: Role | undefined): void {
  assert(role === "admin", "FORBIDDEN: Admin access required");
}

function assertCanModifyProduct(actorRole: Role | undefined, actorMerchantId: string | undefined, productMerchantId: string): void {
  // Admins can modify any product
  if (actorRole === "admin") return;
  
  // Merchants can only modify their own products
  assert(
    actorRole === "merchant" && actorMerchantId === productMerchantId,
    "FORBIDDEN: You can only modify your own products"
  );
}

function assertMerchantCannotOverrideAdminProduct(actorRole: Role | undefined, product: Product): void {
  // Merchants cannot modify admin-created products (products without merchantId or special admin flag)
  if (actorRole === "merchant" && product.merchantId) {
    // This check would be enhanced with an isAdminProduct flag in the schema
    // For now, we allow merchants to modify their own products
  }
}

// ============================================
// AUDIT LOG SERVICE
// ============================================
class AuditLogService {
  private logs: Map<string, AuditLog> = new Map();

  async create(input: AuditLogCreateInput): Promise<AuditLog> {
    const log: AuditLog = {
      id: createId("audit"),
      entityType: input.entityType,
      entityId: input.entityId,
      action: input.action,
      userId: input.userId,
      changes: input.changes,
      metadata: input.metadata,
      ipAddress: input.ipAddress,
      createdAt: nowIso(),
    };
    this.logs.set(log.id, log);
    await eventBus.emit("audit.log.created", { logId: log.id });
    return log;
  }

  async getByEntity(entityType: AuditLog["entityType"], entityId: string): Promise<AuditLog[]> {
    return [...this.logs.values()]
      .filter((log) => log.entityType === entityType && log.entityId === entityId)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  async list(filters?: {
    entityType?: AuditLog["entityType"];
    userId?: string;
    action?: AuditAction;
    limit?: number;
  }): Promise<AuditLog[]> {
    let logs = [...this.logs.values()];
    if (filters?.entityType) logs = logs.filter((l) => l.entityType === filters.entityType);
    if (filters?.userId) logs = logs.filter((l) => l.userId === filters.userId);
    if (filters?.action) logs = logs.filter((l) => l.action === filters.action);
    return logs
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      .slice(0, filters?.limit ?? 100);
  }
}

// ============================================
// PRICING SERVICE
// ============================================
class PricingService {
  public plans: Map<string, PricingPlan> = new Map();

  async create(input: PricingPlanCreateInput): Promise<PricingPlan> {
    const plan: PricingPlan = {
      id: createId("plan"),
      productId: input.productId,
      name: input.name,
      amount: input.amount,
      currency: input.currency,
      interval: input.interval,
      intervalCount: input.intervalCount ?? 1,
      trialPeriodDays: input.trialPeriodDays,
      isDefault: input.isDefault ?? false,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };
    this.plans.set(plan.id, plan);
    await eventBus.emit("pricing.plan.created", { planId: plan.id, productId: plan.productId });
    return plan;
  }

  async update(planId: string, input: PricingPlanUpdateInput): Promise<PricingPlan> {
    const plan = this.plans.get(planId);
    assert(plan, "Pricing plan not found");
    const changes: Record<string, { from: unknown; to: unknown }> = {};
    if (input.name !== undefined && input.name !== plan.name) changes.name = { from: plan.name, to: input.name };
    if (input.amount !== undefined && input.amount !== plan.amount) changes.amount = { from: plan.amount, to: input.amount };
    if (input.interval !== undefined && input.interval !== plan.interval) changes.interval = { from: plan.interval, to: input.interval };
    
    Object.assign(plan, input);
    plan.updatedAt = nowIso();
    this.plans.set(planId, plan);
    await eventBus.emit("pricing.plan.updated", { planId });
    if (Object.keys(changes).length > 0) {
      await auditService.create({
        entityType: "pricing",
        entityId: planId,
        action: "updated",
        userId: "admin",
        changes,
      });
    }
    return plan;
  }

  async delete(planId: string): Promise<void> {
    const plan = this.plans.get(planId);
    assert(plan, "Pricing plan not found");
    this.plans.delete(planId);
    await eventBus.emit("pricing.plan.deleted", { planId });
    await auditService.create({
      entityType: "pricing",
      entityId: planId,
      action: "deleted",
      userId: "admin",
    });
  }

  async getByProductId(productId: string): Promise<PricingPlan[]> {
    return [...this.plans.values()].filter((p) => p.productId === productId);
  }

  async getDefaultPlan(productId: string): Promise<PricingPlan | null> {
    const plans = await this.getByProductId(productId);
    return plans.find((p) => p.isDefault) ?? plans[0] ?? null;
  }

  async getLowestPrice(productId: string): Promise<number | null> {
    const plans = await this.getByProductId(productId);
    if (plans.length === 0) return null;
    return Math.min(...plans.map((p) => p.amount));
  }

  formatPrice(amount: number, currency: string, interval?: "monthly" | "yearly"): string {
    const formatted = new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: currency.toUpperCase(),
    }).format(amount);
    return interval ? `${formatted}/${interval === "monthly" ? "mo" : "yr"}` : formatted;
  }
}

