  getReportFlags(): ReportFlag[] {
    return Array.from(this.reportFlags.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  getReportFlagsByStatus(status: FlagStatus): ReportFlag[] {
    return this.getReportFlags().filter((f) => f.status === status);
  }

  getReportFlagsBySeverity(severity: "low" | "medium" | "high"): ReportFlag[] {
    return this.getReportFlags().filter((f) => f.severity === severity);
  }

  getReportFlagsByItem(itemId: string): ReportFlag[] {
    return this.getReportFlags().filter((f) => f.itemId === itemId);
  }

  getReportFlagsByAuthor(authorId: string): ReportFlag[] {
    return this.getReportFlags().filter((f) => f.authorId === authorId);
  }

  getFlagKPI(): { open: number; underReview: number; actionTaken: number; dismissed: number; escalated: number } {
    const flags = this.getReportFlags();
    return {
      open: flags.filter((f) => f.status === "open").length,
      underReview: flags.filter((f) => f.status === "under_review").length,
      actionTaken: flags.filter((f) => f.status === "action_taken").length,
      dismissed: flags.filter((f) => f.status === "dismissed").length,
      escalated: flags.filter((f) => f.status === "escalated").length,
    };
  }

  // Auto-generate system flags
  async autoGenerateFlags(): Promise<void> {
    const items = Array.from(this.items.values());

    for (const item of items) {
      // Check for high refund rate
      const itemRefunds = Array.from(this.refunds.values()).filter((r) => r.itemId === item.id && r.status === "refunded");
      const itemOrders = Array.from(this.orders.values()).filter((o) => o.itemId === item.id && o.status === "completed");
      const refundRate = itemOrders.length > 0 ? itemRefunds.length / itemOrders.length : 0;

      if (refundRate > 0.3 && itemOrders.length >= 5) {
        // High refund rate - create system flag
        const existingFlag = Array.from(this.reportFlags.values()).find(
          (f) => f.itemId === item.id && f.isSystemGenerated && f.reason === "High refund rate"
        );
        if (!existingFlag) {
          const flag: ReportFlag = {
            id: createId("flag"),
            itemId: item.id,
            itemName: item.name,
            authorId: item.authorId,
            authorName: item.authorName,
            reporterId: "system",
            reporterName: "System",
            reporterEmail: "system@vala.com",
            severity: "medium",
            status: "open",
            reason: "High refund rate",
            description: `Item has ${(refundRate * 100).toFixed(1)}% refund rate (${itemRefunds.length}/${itemOrders.length} refunds)`,
            warningCount: 0,
            reporterTrustScore: 100,
            isSystemGenerated: true,
            createdAt: nowIso(),
            updatedAt: nowIso(),
          };
          this.reportFlags.set(flag.id, flag);
        }
      }

      // Check for abnormal sales spike
      const recentOrders = itemOrders.filter((o) => new Date(o.createdAt) >= new Date(Date.now() - 7 * 24 * 60 * 60 * 1000));
      const olderOrders = itemOrders.filter((o) => new Date(o.createdAt) < new Date(Date.now() - 7 * 24 * 60 * 60 * 1000));
      if (recentOrders.length > 10 && olderOrders.length > 0 && recentOrders.length / olderOrders.length > 5) {
        const existingFlag = Array.from(this.reportFlags.values()).find(
          (f) => f.itemId === item.id && f.isSystemGenerated && f.reason === "Abnormal sales spike"
        );
        if (!existingFlag) {
          const flag: ReportFlag = {
            id: createId("flag"),
            itemId: item.id,
            itemName: item.name,
            authorId: item.authorId,
            authorName: item.authorName,
            reporterId: "system",
            reporterName: "System",
            reporterEmail: "system@vala.com",
            severity: "high",
            status: "open",
            reason: "Abnormal sales spike",
            description: `Item has ${recentOrders.length} recent sales vs ${olderOrders.length} older sales (${(recentOrders.length / olderOrders.length).toFixed(1)}x increase)`,
            warningCount: 0,
            reporterTrustScore: 100,
            isSystemGenerated: true,
            createdAt: nowIso(),
            updatedAt: nowIso(),
          };
          this.reportFlags.set(flag.id, flag);
        }
      }
    }
  }

  // Self-healing for flags
  async healIfNoActionSLA(): Promise<void> {
    const now = new Date();
    const slaHours = 48; // 48 hours SLA
    const slaTime = new Date(now.getTime() - slaHours * 60 * 60 * 1000).toISOString();

    const staleFlags = Array.from(this.reportFlags.values()).filter(
      (f) => f.status === "open" && f.createdAt < slaTime
    );

    for (const flag of staleFlags) {
      await this.escalateFlag(flag.id, "Auto-escalated: SLA exceeded", "system");
    }
  }

  // ============================================
  // MICRO LOGIC - SEVERITY AUTO VALIDATION
  // ============================================

  async upgradeSeverityOnRepeat(flagId: string, userId: string): Promise<void> {
    const flag = this.reportFlags.get(flagId);
    assert(flag, "Flag not found");

    const itemReports = Array.from(this.reportFlags.values()).filter(
      (f) => f.itemId === flag.itemId && f.status !== "dismissed"
    );
    const uniqueReporters = new Set(itemReports.map((f) => f.reporterId)).size;

    // Upgrade if multiple reports from different users
    if (uniqueReporters >= 3 && flag.severity === "low") {
      flag.severity = "medium";
      flag.updatedAt = nowIso();
      this.reportFlags.set(flagId, flag);
      await this.auditService.create({
        entityType: "marketplace",
        entityId: flagId,
        action: "updated",
        userId,
      });
    } else if (uniqueReporters >= 5 && flag.severity === "medium") {
      flag.severity = "high";
      flag.updatedAt = nowIso();
      this.reportFlags.set(flagId, flag);
      await this.auditService.create({
        entityType: "marketplace",
        entityId: flagId,
        action: "updated",
        userId,
      });
    }
  }

  // ============================================
  // MICRO LOGIC - REPORT GROUPING
  // ============================================

  getGroupedReports(itemId: string): { totalReports: number; uniqueReporters: number; flags: ReportFlag[] } {
    const flags = Array.from(this.reportFlags.values()).filter((f) => f.itemId === itemId && f.status !== "dismissed");
    const uniqueReporters = new Set(flags.map((f) => f.reporterId)).size;
    return {
      totalReports: flags.length,
      uniqueReporters,
      flags,
    };
  }

