  async requestFixFromAuthor(flagId: string, deadlineHours: number, userId: string): Promise<void> {
    const flag = this.reportFlags.get(flagId);
    assert(flag, "Flag not found");
    assert(flag.status === "under_review" || flag.status === "escalated", "Flag must be in review or escalated status");

    const deadline = new Date(Date.now() + deadlineHours * 60 * 60 * 1000).toISOString();

    flag.status = "awaiting_fix";
    flag.fixDeadline = deadline;
    flag.fixRequestedAt = nowIso();
    flag.updatedAt = nowIso();
    this.reportFlags.set(flagId, flag);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: flagId,
      action: "updated",
      userId,
    });

    await eventBus.emit("fix_requested", { flagId });
  }

  async submitAuthorFix(flagId: string, userId: string): Promise<void> {
    const flag = this.reportFlags.get(flagId);
    assert(flag, "Flag not found");
    assert(flag.status === "awaiting_fix", "Flag must be in awaiting_fix status");

    flag.status = "fixed";
    flag.fixCompletedAt = nowIso();
    flag.updatedAt = nowIso();
    this.reportFlags.set(flagId, flag);

    // Trigger auto retest
    await this.autoRetestFix(flagId, userId);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: flagId,
      action: "updated",
      userId,
    });
  }

  async ignoreAuthorFix(flagId: string, userId: string): Promise<void> {
    const flag = this.reportFlags.get(flagId);
    assert(flag, "Flag not found");
    assert(flag.status === "awaiting_fix", "Flag must be in awaiting_fix status");

    flag.status = "ignored";
    flag.updatedAt = nowIso();
    this.reportFlags.set(flagId, flag);

    // Escalate back to review
    await this.escalateFlag(flagId, "Author ignored fix request", userId);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: flagId,
      action: "updated",
      userId,
    });
  }

