  getSecurityIncidentKPI(): { detected: number; blocked: number; patchRequested: number; resolved: number; forceTakedown: number } {
    const incidents = this.getSecurityIncidents();
    return {
      detected: incidents.filter((i) => i.status === "detected").length,
      blocked: incidents.filter((i) => i.status === "blocked").length,
      patchRequested: incidents.filter((i) => i.status === "patch_requested").length,
      resolved: incidents.filter((i) => i.status === "resolved").length,
      forceTakedown: incidents.filter((i) => i.status === "force_takedown").length,
    };
  }

