  async createTaxRule(input: TaxRuleCreateInput, userId: string): Promise<TaxRule> {
    const existingRule = Array.from(this.taxRules.values()).find(
      (r) => r.countryCode === input.countryCode && r.status === "active"
    );
    if (existingRule) {
      // Version the old rule
      existingRule.status = "inactive";
      existingRule.effectiveTo = nowIso();
      this.taxRules.set(existingRule.id, existingRule);
    }

    const rule: TaxRule = {
      id: createId("tax"),
      country: input.country,
      countryCode: input.countryCode,
      type: input.type,
      rate: input.rate,
      reverseCharge: input.reverseCharge,
      status: "active",
      version: existingRule ? existingRule.version + 1 : 1,
      effectiveFrom: nowIso(),
      stateTax: input.stateTax,
      digitalServiceTax: input.digitalServiceTax,
      roundingRule: input.roundingRule || "round_half_up",
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.taxRules.set(rule.id, rule);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: rule.id,
      action: "created",
      userId,
    });

    return rule;
  }

  getTaxRules(): TaxRule[] {
    return Array.from(this.taxRules.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  getActiveTaxRule(countryCode: string): TaxRule | null {
    return Array.from(this.taxRules.values()).find(
      (r) => r.countryCode === countryCode && r.status === "active"
    ) || null;
  }

  calculateTax(
    baseAmount: number,
    countryCode: string,
    isB2B: boolean,
    taxId?: string
  ): TaxCalculation {
    const rule = this.getActiveTaxRule(countryCode);
    const settings = this.getCurrentSettings();

    if (!rule) {
      // Fallback to default (no tax)
      return {
        baseAmount,
        countryTax: 0,
        stateTax: 0,
        digitalServiceTax: 0,
        totalTax: 0,
        finalAmount: baseAmount,
        taxRate: 0,
        isReverseCharge: false,
        taxMode: settings.taxMode,
        country: "Unknown",
        countryCode,
      };
    }

    // Check for reverse charge (B2B with valid tax ID)
    const isReverseCharge = isB2B && rule.reverseCharge && taxId && this.validateTaxId(taxId, countryCode).isValid;

    let countryTax = 0;
    let stateTax = 0;
    let digitalServiceTax = 0;

    if (!isReverseCharge) {
      countryTax = this.roundAmount(baseAmount * (rule.rate / 100), rule.roundingRule);
      if (rule.stateTax) {
        stateTax = this.roundAmount(baseAmount * (rule.stateTax / 100), rule.roundingRule);
      }
      if (rule.digitalServiceTax) {
        digitalServiceTax = this.roundAmount(baseAmount * (rule.digitalServiceTax / 100), rule.roundingRule);
      }
    }

    const totalTax = countryTax + stateTax + digitalServiceTax;
    const finalAmount = settings.taxMode === "inclusive" ? baseAmount : baseAmount + totalTax;
    const taxRate = isReverseCharge ? 0 : rule.rate + (rule.stateTax || 0) + (rule.digitalServiceTax || 0);

    return {
      baseAmount,
      countryTax,
      stateTax,
      digitalServiceTax,
      totalTax,
      finalAmount,
      taxRate,
      isReverseCharge,
      taxMode: settings.taxMode,
      country: rule.country,
      countryCode,
    };
  }

  roundAmount(amount: number, rule: TaxRule["roundingRule"]): number {
    const factor = Math.pow(10, 2);
    const rounded = Math.round(amount * factor) / factor;

    switch (rule) {
      case "round_half_up":
        return Math.round(amount * factor) / factor;
      case "round_half_down":
        return Math.floor((amount * factor + 0.5) - 1) / factor;
      case "round_up":
        return Math.ceil(amount * factor) / factor;
      case "round_down":
        return Math.floor(amount * factor) / factor;
      default:
        return rounded;
    }
  }

  validateTaxId(taxId: string, countryCode: string): TaxValidation {
    // Simulated validation - in real implementation would call external tax validation APIs
    const euCountries = ["DE", "FR", "IT", "ES", "NL", "BE", "AT", "PL", "CZ", "HU", "GR", "PT", "SE", "DK", "FI", "IE", "LU", "BG", "RO", "HR", "SI", "SK", "CY", "MT", "LV", "LT", "EE"];
    const isVATFormat = euCountries.includes(countryCode) && taxId.toUpperCase().startsWith(countryCode) && taxId.length >= 9;
    const isGSTFormat = countryCode === "IN" && taxId.length === 15;

    if (isVATFormat) {
      return { isValid: true, taxId, taxType: "VAT", validationMessage: "Valid VAT ID" };
    }
    if (isGSTFormat) {
      return { isValid: true, taxId, taxType: "GST", validationMessage: "Valid GST number" };
    }

    return { isValid: false, validationMessage: "Invalid tax ID format" };
  }

