  async createCommissionTier(name: "non_exclusive" | "exclusive" | "elite", rate: number, minSales: number, minRevenue: number, userId: string): Promise<CommissionTier> {
    const tier: CommissionTier = {
      id: createId("tier"),
      name,
      rate,
      minSales,
      minRevenue,
      autoUpgrade: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.commissionTiers.set(tier.id, tier);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: tier.id,
      action: "created",
      userId,
    });

    return tier;
  }

  getCommissionTiers(): CommissionTier[] {
    return Array.from(this.commissionTiers.values());
  }

  calculateCommission(
    saleAmount: number,
    authorId: string,
    categoryId: string,
    taxAmount: number
  ): CommissionCalculation {
    const settings = this.getCurrentSettings();
    const author = this.authors.get(authorId);
    const authorSales = Array.from(this.orders.values()).filter(
      (o) => o.authorId === authorId && o.status === "completed"
    ).length;
    const authorRevenue = Array.from(this.orders.values())
      .filter((o) => o.authorId === authorId && o.status === "completed")
      .reduce((sum, o) => sum + o.amount, 0);

    // Determine commission rate with priority: author override > category override > tier > default
    let commissionRate = settings.defaultCommission;

    const authorOverride = this.authorCommissionOverrides.get(authorId);
    if (authorOverride) {
      commissionRate = authorOverride.commissionRate;
    } else {
      const categoryOverride = this.categoryCommissionOverrides.get(categoryId);
      if (categoryOverride) {
        commissionRate = categoryOverride.commissionRate;
      } else {
        // Auto tier upgrade
        const tiers = this.getCommissionTiers().sort((a, b) => b.rate - a.rate);
        for (const tier of tiers) {
          if (authorSales >= tier.minSales && authorRevenue >= tier.minRevenue && tier.autoUpgrade) {
            commissionRate = tier.rate;
            break;
          }
        }
      }
    }

    const buyerFee = this.roundAmount(saleAmount * (settings.buyerFee / 100), "round_half_up");
    const platformFee = this.roundAmount(saleAmount * (commissionRate / 100), "round_half_up");
    const commissionAmount = platformFee;
    const authorEarnings = saleAmount - taxAmount - commissionAmount;

    return {
      saleAmount,
      taxAmount,
      platformFee,
      buyerFee,
      commissionRate,
      commissionAmount,
      authorEarnings,
      tier: authorSales >= 100 ? "elite" : authorSales >= 50 ? "exclusive" : "non_exclusive",
      isLocked: false,
    };
  }

  async setAuthorCommissionOverride(authorId: string, commissionRate: number, userId: string): Promise<void> {
    const override: AuthorCommissionOverride = {
      authorId,
      commissionRate,
    };
    this.authorCommissionOverrides.set(authorId, override);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: authorId,
      action: "updated",
      userId,
    });
  }

  async setCategoryCommissionOverride(categoryId: string, commissionRate: number, userId: string): Promise<void> {
    const override: CategoryCommissionOverride = {
      categoryId,
      commissionRate,
    };
    this.categoryCommissionOverrides.set(categoryId, override);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: categoryId,
      action: "updated",
      userId,
    });
  }

