  getCurrentSettings(): MarketplaceSettings {
    const settings = Array.from(this.marketplaceSettings.values()).sort((a, b) => b.version - a.version)[0];
    if (!settings) {
      // Return default safe settings
      return {
        id: "default",
        version: 1,
        effectiveFrom: nowIso(),
        defaultCommission: 30,
        buyerFee: 10,
        extendedLicenseMultiplier: 10,
        minimumItemPrice: 2,
        refundClearanceWindow: 30,
        minWithdrawalThreshold: 100,
        reviewSLA: 48,
        maxSoftRejectCycles: 3,
        baseCurrency: "USD",
        useLiveRates: false,
        taxMode: "exclusive",
        applyEU_MOSS: false,
        applyWithholdingTax: false,
        safeMode: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      };
    }
    return settings;
  }

  async updateSettings(input: MarketplaceSettingsUpdateInput, userId: string): Promise<MarketplaceSettings> {
    const currentSettings = this.getCurrentSettings();

    // Validation
    if (input.defaultCommission !== undefined && (input.defaultCommission < 0 || input.defaultCommission > 100)) {
      throw new Error("Default commission must be between 0 and 100");
    }
    if (input.buyerFee !== undefined && (input.buyerFee < 0 || input.buyerFee > 100)) {
      throw new Error("Buyer fee must be between 0 and 100");
    }
    if (input.minimumItemPrice !== undefined && input.minimumItemPrice < 0) {
      throw new Error("Minimum item price cannot be negative");
    }
    if (input.refundClearanceWindow !== undefined && input.refundClearanceWindow < 0) {
      throw new Error("Refund clearance window cannot be negative");
    }
    if (input.minWithdrawalThreshold !== undefined && input.minWithdrawalThreshold < 0) {
      throw new Error("Minimum withdrawal threshold cannot be negative");
    }

    // Dependency check
    const newCommission = input.defaultCommission ?? currentSettings.defaultCommission;
    const newBuyerFee = input.buyerFee ?? currentSettings.buyerFee;
    if (newCommission + newBuyerFee > 100) {
      throw new Error("Commission + buyer fee cannot exceed 100%");
    }

    // Version the old settings
    const changes: Record<string, { old: any; new: any }> = {};
    for (const key in input) {
      if (input[key as keyof MarketplaceSettingsUpdateInput] !== undefined) {
        changes[key] = {
          old: currentSettings[key as keyof MarketplaceSettings],
          new: input[key as keyof MarketplaceSettingsUpdateInput],
        };
      }
    }

    const auditLog: SettingsAuditLog = {
      id: createId("audit"),
      settingId: currentSettings.id,
      version: currentSettings.version + 1,
      changedBy: userId,
      changes,
      timestamp: nowIso(),
    };
    this.settingsAuditLogs.set(auditLog.id, auditLog);

    // Create new settings version
    const newSettings: MarketplaceSettings = {
      id: createId("settings"),
      version: currentSettings.version + 1,
      effectiveFrom: nowIso(),
      defaultCommission: input.defaultCommission ?? currentSettings.defaultCommission,
      buyerFee: input.buyerFee ?? currentSettings.buyerFee,
      extendedLicenseMultiplier: input.extendedLicenseMultiplier ?? currentSettings.extendedLicenseMultiplier,
      minimumItemPrice: input.minimumItemPrice ?? currentSettings.minimumItemPrice,
      refundClearanceWindow: input.refundClearanceWindow ?? currentSettings.refundClearanceWindow,
      minWithdrawalThreshold: input.minWithdrawalThreshold ?? currentSettings.minWithdrawalThreshold,
      reviewSLA: input.reviewSLA ?? currentSettings.reviewSLA,
      maxSoftRejectCycles: input.maxSoftRejectCycles ?? currentSettings.maxSoftRejectCycles,
      baseCurrency: input.baseCurrency ?? currentSettings.baseCurrency,
      useLiveRates: input.useLiveRates ?? currentSettings.useLiveRates,
      taxMode: input.taxMode ?? currentSettings.taxMode,
      applyEU_MOSS: input.applyEU_MOSS ?? currentSettings.applyEU_MOSS,
      applyWithholdingTax: input.applyWithholdingTax ?? currentSettings.applyWithholdingTax,
      safeMode: input.safeMode ?? currentSettings.safeMode,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.marketplaceSettings.set(newSettings.id, newSettings);

    await this.auditService.create({
      entityType: "marketplace",
      entityId: newSettings.id,
      action: "created",
      userId,
    });

    return newSettings;
  }

  getSettingsAuditLogs(): SettingsAuditLog[] {
    return Array.from(this.settingsAuditLogs.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  calculateFinalPrice(basePrice: number, isExtended: boolean): number {
    const settings = this.getCurrentSettings();
    const multiplier = isExtended ? settings.extendedLicenseMultiplier : 1;
    const finalPrice = basePrice * multiplier;

    if (finalPrice < settings.minimumItemPrice) {
      throw new Error(`Price cannot be below minimum of ${settings.minimumItemPrice}`);
    }

    return finalPrice;
  }

  canWithdraw(authorId: string): { canWithdraw: boolean; reason?: string } {
    const settings = this.getCurrentSettings();
    const author = this.authors.get(authorId);
    if (!author) {
      return { canWithdraw: false, reason: "Author not found" };
    }

    const authorBalance = author.balance || 0;
    if (authorBalance < settings.minWithdrawalThreshold) {
      return { canWithdraw: false, reason: `Balance below minimum threshold of ${settings.minWithdrawalThreshold}` };
    }

    // Check for pending refunds
    const pendingRefunds = Array.from(this.refunds.values()).filter(
      (r) => r.authorId === authorId && r.status === "pending"
    );
    if (pendingRefunds.length > 0) {
      return { canWithdraw: false, reason: "Pending refunds must be resolved" };
    }

    return { canWithdraw: true };
  }

  canRefund(orderId: string): { canRefund: boolean; reason?: string } {
    const settings = this.getCurrentSettings();
    const order = this.orders.get(orderId);
    if (!order) {
      return { canRefund: false, reason: "Order not found" };
    }

    const orderDate = new Date(order.createdAt);
    const now = new Date();
    const daysSinceOrder = Math.floor((now.getTime() - orderDate.getTime()) / (1000 * 60 * 60 * 24));

    if (daysSinceOrder > settings.refundClearanceWindow) {
      return { canRefund: false, reason: `Refund window of ${settings.refundClearanceWindow} days has expired` };
    }

    return { canRefund: true };
  }

