  getComplianceAlerts(): ComplianceAlert[] {
    return Array.from(this.complianceAlerts.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  getPendingAlerts(): ComplianceAlert[] {
    return this.getComplianceAlerts().filter((a) => a.status === "pending");
  }

  async resolveAlert(alertId: string, userId: string): Promise<void> {
    const alert = this.complianceAlerts.get(alertId);
    if (!alert) throw new Error("Alert not found");

    alert.status = "resolved";
    alert.resolvedAt = nowIso();
    alert.resolvedBy = userId;
    alert.updatedAt = nowIso();

    this.complianceAlerts.set(alertId, alert);

    await this.logComplianceHistory("alert", alertId, `Resolved alert: ${alert.title}`, userId);
  }

  async escalateAlert(alertId: string, userId: string): Promise<void> {
    const alert = this.complianceAlerts.get(alertId);
    if (!alert) throw new Error("Alert not found");

    alert.status = "escalated";
    alert.escalatedAt = nowIso();
    alert.updatedAt = nowIso();

    this.complianceAlerts.set(alertId, alert);

    await this.logComplianceHistory("alert", alertId, `Escalated alert: ${alert.title}`, userId);
  }

  calculateComplianceScore(): ComplianceScore {
    const alerts = this.getComplianceAlerts();
    const pendingAlerts = alerts.filter((a) => a.status === "pending");
    const criticalAlerts = pendingAlerts.filter((a) => a.priority === "critical");
    const highAlerts = pendingAlerts.filter((a) => a.priority === "high");

    // Tax accuracy: based on successful tax calculations vs total
    const taxAccuracy = 95; // Simulated - in real implementation would track actual accuracy

    // Filing status: based on reports filed vs required
    const reports = Array.from(this.complianceReports.values());
    const filedReports = reports.filter((r) => r.filingStatus === "accepted" || r.filingStatus === "submitted").length;
    const filingStatus = reports.length > 0 ? (filedReports / reports.length) * 100 : 100;

    // Pending alerts impact
    const pendingAlertsScore = Math.max(0, 100 - (pendingAlerts.length * 10) - (criticalAlerts.length * 20) - (highAlerts.length * 10));

    // Overall score (weighted)
    const overallScore = (taxAccuracy * 0.4) + (filingStatus * 0.3) + (pendingAlertsScore * 0.3);

    let riskLevel: "low" | "medium" | "high" | "critical";
    if (overallScore >= 95) riskLevel = "low";
    else if (overallScore >= 85) riskLevel = "medium";
    else if (overallScore >= 70) riskLevel = "high";
    else riskLevel = "critical";

    const score: ComplianceScore = {
      id: createId("score"),
      overallScore: Math.round(overallScore),
      taxAccuracy,
      filingStatus,
      pendingAlerts: pendingAlerts.length,
      riskLevel,
      calculatedAt: nowIso(),
      factors: [
        { factor: "Tax Accuracy", score: taxAccuracy, weight: 0.4 },
        { factor: "Filing Status", score: filingStatus, weight: 0.3 },
        { factor: "Pending Alerts", score: pendingAlertsScore, weight: 0.3 },
      ],
    };

    this.complianceScores.set(score.id, score);

    return score;
  }

  getComplianceScore(): ComplianceScore {
    const scores = Array.from(this.complianceScores.values());
    if (scores.length === 0) {
      return this.calculateComplianceScore();
    }
    return scores.sort((a, b) => new Date(b.calculatedAt).getTime() - new Date(a.calculatedAt).getTime())[0];
  }

  async createTaxDeadline(
    country: string,
    countryCode: string,
    filingType: string,
    dueDate: string,
    userId: string
  ): Promise<TaxDeadline> {
    const deadline: TaxDeadline = {
      id: createId("deadline"),
      country,
      countryCode,
      filingType,
      dueDate,
      status: "upcoming",
      alertSent: false,
      reminderSent: false,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.taxDeadlines.set(deadline.id, deadline);

    await this.logComplianceHistory("deadline", deadline.id, `Created deadline: ${filingType} for ${country}`, userId);

    return deadline;
  }

  getTaxDeadlines(): TaxDeadline[] {
    return Array.from(this.taxDeadlines.values()).sort((a, b) =>
      new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime()
    );
  }

  updateDeadlineStatuses(): void {
    const now = new Date();
    const deadlines = this.getTaxDeadlines();

    deadlines.forEach((deadline) => {
      const dueDate = new Date(deadline.dueDate);
      const daysUntilDue = Math.floor((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));

      if (daysUntilDue < 0) {
        deadline.status = "overdue";
      } else if (daysUntilDue <= 7) {
        deadline.status = "due_soon";
      } else {
        deadline.status = "upcoming";
      }

      deadline.updatedAt = nowIso();
      this.taxDeadlines.set(deadline.id, deadline);
    });
  }

  async generateComplianceReport(
    period: string,
    countryCode: string,
    reportType: "vat" | "gst" | "sales_tax" | "1099",
    userId: string
  ): Promise<ComplianceReport> {
    const country = this.taxRules.get(countryCode)?.country || countryCode;

    // Calculate tax collected for the period
    const orders = Array.from(this.orders.values()).filter(
      (o) => o.status === "completed" && o.createdAt.startsWith(period)
    );

    const totalSales = orders.reduce((sum, o) => sum + o.amount, 0);
    const totalTaxCollected = orders.reduce((sum, o) => sum + (o.taxAmount || 0), 0);

    // Calculate refunds
    const refunds = Array.from(this.refunds.values()).filter(
      (r) => r.status === "approved" && r.createdAt.startsWith(period)
    );
    const totalTaxRefunded = refunds.reduce((sum, r) => sum + (r.taxRefunded || 0), 0);

    const report: ComplianceReport = {
      id: createId("report"),
      period,
      country,
      countryCode,
      reportType,
      totalSales,
      totalTaxCollected,
      totalTaxRefunded,
      netTax: totalTaxCollected - totalTaxRefunded,
      transactionCount: orders.length,
      filingStatus: "not_filed",
      generatedAt: nowIso(),
    };

    this.complianceReports.set(report.id, report);

    await this.logComplianceHistory("report", report.id, `Generated ${reportType} report for ${country}`, userId);

    return report;
  }

  getComplianceReports(): ComplianceReport[] {
    return Array.from(this.complianceReports.values()).sort((a, b) =>
      new Date(b.generatedAt).getTime() - new Date(a.generatedAt).getTime()
    );
  }

  async logComplianceHistory(
    entityType: "alert" | "report" | "deadline" | "rule",
    entityId: string,
    description: string,
    performedBy: string
  ): Promise<void> {
    const history: ComplianceHistory = {
      id: createId("history"),
      action: "update",
      entityType,
      entityId,
      description,
      performedBy,
      timestamp: nowIso(),
    };

    this.complianceHistory.set(history.id, history);
  }

  getComplianceHistory(): ComplianceHistory[] {
    return Array.from(this.complianceHistory.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  getTaxCollectedMTD(): number {
    const now = new Date();
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

    return Array.from(this.orders.values())
      .filter((o) => o.status === "completed" && o.createdAt >= monthStart)
      .reduce((sum, o) => sum + (o.taxAmount || 0), 0);
  }

  getTaxRegionsCount(): number {
    return new Set(Array.from(this.taxRegions.values()).map((r) => r.countryCode)).size;
  }

