  getCachedTaxRule(countryCode: string): TaxRule | null {
    const cacheKey = countryCode;
    const cached = this.taxRuleCache.get(cacheKey);
    const expiry = this.taxCacheExpiry.get(cacheKey);

    if (cached && expiry && Date.now() < expiry) {
      return cached;
    }

    // Cache miss or expired, fetch fresh
    const rule = this.getActiveTaxRule(countryCode);
    if (rule) {
      this.taxRuleCache.set(cacheKey, rule);
      this.taxCacheExpiry.set(cacheKey, Date.now() + 3600000); // 1 hour cache
    }

    return rule;
  }

  clearTaxCache(): void {
    this.taxRuleCache.clear();
    this.taxCacheExpiry.clear();
  }

  detectTaxRisks(): ComplianceAlert[] {
    const risks: ComplianceAlert[] = [];
    const now = new Date();

    // Check for overdue deadlines
    const overdueDeadlines = this.getTaxDeadlines().filter((d) => d.status === "overdue");
    overdueDeadlines.forEach((deadline) => {
      risks.push({
        id: createId("alert"),
        type: "deadline",
        priority: "critical",
        status: "pending",
        title: `Overdue Filing: ${deadline.filingType}`,
        description: `Filing deadline for ${deadline.country} has passed`,
        region: deadline.country,
        countryCode: deadline.countryCode,
        dueDate: deadline.dueDate,
        actionRequired: "File immediately to avoid penalties",
        createdAt: now.toISOString(),
        updatedAt: now.toISOString(),
      });
    });

    // Check for high pending alerts
    const highPendingAlerts = this.getPendingAlerts().filter((a) => a.priority === "high" || a.priority === "critical");
    if (highPendingAlerts.length > 5) {
      risks.push({
        id: createId("alert"),
        type: "risk_detected",
        priority: "high",
        status: "pending",
        title: "Multiple High Priority Alerts",
        description: `${highPendingAlerts.length} high priority alerts require attention`,
        actionRequired: "Review and resolve pending alerts",
        createdAt: now.toISOString(),
        updatedAt: now.toISOString(),
      });
    }

    return risks;
  }

  selfHealTaxRules(): void {
    // Resolve conflicts by deactivating older rules
    const countryCodeGroups = new Map<string, TaxRule[]>();
    Array.from(this.taxRules.values()).forEach((rule) => {
      if (!countryCodeGroups.has(rule.countryCode)) {
        countryCodeGroups.set(rule.countryCode, []);
      }
      countryCodeGroups.get(rule.countryCode)!.push(rule);
    });

    countryCodeGroups.forEach((rules, countryCode) => {
      const activeRules = rules.filter((r) => r.status === "active");
      if (activeRules.length > 1) {
        // Keep the newest, deactivate others
        activeRules.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
        const toKeep = activeRules[0];
        const toDeactivate = activeRules.slice(1);

        toDeactivate.forEach((rule) => {
          rule.status = "inactive";
          rule.effectiveTo = nowIso();
          this.taxRules.set(rule.id, rule);
        });
      }
    });
  }

