  getConsentRecords(userId: string): ConsentRecord[] {
    return Array.from(this.consentRecords.values())
      .filter((c) => c.userId === userId)
      .sort((a, b) => new Date(b.grantedAt).getTime() - new Date(a.grantedAt).getTime());
  }

  hasActiveConsent(userId: string, consentType: ConsentType): boolean {
    const latestConsent = this.getConsentRecords(userId).find((c) => c.consentType === consentType);
    return latestConsent?.granted && !latestConsent.revokedAt;
  }

  // ============================================
  // LEGAL HOLD SYSTEM
  // ============================================

  async applyLegalHold(userId: string, reason: string, adminUserId: string): Promise<LegalHold> {
    const hold: LegalHold = {
      id: createId("legal_hold"),
      userId,
      reason,
      appliedBy: adminUserId,
      appliedAt: nowIso(),
      isActive: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.legalHolds.set(hold.id, hold);

    // Mark any pending requests for this user
    const userRequests = Array.from(this.dataRequests.values()).filter((r) => r.userId === userId);
    userRequests.forEach((request) => {
      request.legalHold = true;
      this.dataRequests.set(request.id, request);
    });

    await this.logComplianceAudit("legal_hold", hold.id, "applied", adminUserId, {
      userId,
      reason,
    });

    return hold;
  }

  async releaseLegalHold(holdId: string, adminUserId: string): Promise<void> {
    const hold = this.legalHolds.get(holdId);
    if (!hold) throw new Error("Legal hold not found");

    hold.isActive = false;
    hold.releasedAt = nowIso();
    hold.releasedBy = adminUserId;
    hold.updatedAt = nowIso();
    this.legalHolds.set(holdId, hold);

    // Unmark requests for this user
    const userRequests = Array.from(this.dataRequests.values()).filter((r) => r.userId === hold.userId);
    userRequests.forEach((request) => {
      request.legalHold = false;
      this.dataRequests.set(request.id, request);
    });

    await this.logComplianceAudit("legal_hold", holdId, "released", adminUserId, {
      userId: hold.userId,
    });
  }

  getLegalHoldForUser(userId: string): LegalHold | null {
    return Array.from(this.legalHolds.values()).find(
      (h) => h.userId === userId && h.isActive
    ) || null;
  }

  getLegalHolds(): LegalHold[] {
    return Array.from(this.legalHolds.values()).sort((a, b) =>
      new Date(b.appliedAt).getTime() - new Date(a.appliedAt).getTime()
    );
  }

  // ============================================
  // COMPLIANCE AUDIT
  // ============================================

  async logComplianceAudit(
    entityType: "data_request" | "policy" | "consent" | "legal_hold",
    entityId: string,
    action: string,
    performedBy: string,
    details: Record<string, any>,
    ipAddress?: string
  ): Promise<void> {
    const audit: ComplianceAudit = {
      id: createId("audit"),
      entityType,
      entityId,
      action,
      performedBy,
      details,
      ipAddress,
      timestamp: nowIso(),
    };

    this.complianceAudits.set(audit.id, audit);
  }

  getComplianceAudits(): ComplianceAudit[] {
    return Array.from(this.complianceAudits.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  getComplianceScore(): number {
    const requests = this.getDataRequests();
    const pendingRequests = requests.filter((r) => r.status === "pending" || r.status === "processing");
    const overdueRequests = requests.filter((r) => r.status === "overdue");

    if (overdueRequests.length > 0) return 0;
    if (pendingRequests.length > 5) return 80;
    if (pendingRequests.length > 0) return 90;

    return 100;
  }

  detectUserRegion(userId: string): RequestRegion {
    const user = this.users.get(userId);
    if (!user) return "global";

    // Simulated region detection based on user data
    // In real implementation, would use IP geolocation or billing address
    const email = user.email.toLowerCase();
    if (email.endsWith(".eu") || email.includes("europe")) return "eu";
    if (email.includes("california") || email.endsWith(".ca")) return "us_ca";
    if (email.endsWith(".us")) return "us_other";

    return "global";
  }

