// ============================================
// SYSTEM HEALTH SERVICE
// ============================================
class SystemHealthService {
  private serviceHealth: Map<string, ServiceHealth> = new Map();
  private jobQueueHealth: Map<string, JobQueueHealth> = new Map();
  private paymentGatewayHealth: Map<string, PaymentGatewayHealth> = new Map();
  private sloValidations: Map<string, SLOValidation> = new Map();
  private auditService: AuditLogService;
  private healthCheckInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditService;
  }

  // Update Service Health
  async updateServiceHealth(input: {
    serviceName: string;
    currentLatency: number;
    status?: ServiceStatus;
  }): Promise<ServiceHealth> {
    const existing = Array.from(this.serviceHealth.values()).find((s) => s.serviceName === input.serviceName);

    const health: ServiceHealth = {
      id: existing?.id || createId("service-health"),
      serviceName: input.serviceName,
      status: input.status || (existing?.status || "active"),
      currentLatency: input.currentLatency,
      latencyHistory: existing ? [...existing.latencyHistory.slice(-11), input.currentLatency] : [input.currentLatency],
      uptime: existing?.uptime || 100,
      uptimeSince: existing?.uptimeSince || nowIso(),
      failureCount: existing?.failureCount || 0,
      autoRestartCount: existing?.autoRestartCount || 0,
      isStuck: false,
      dependencyStatus: [],
      createdAt: existing?.createdAt || nowIso(),
      updatedAt: nowIso(),
    };

    // Validate status - no false "Active"
    if (health.status === "active" && input.currentLatency > 5000) {
      health.status = "degraded";
    }

    // Check for stuck state
    if (health.status === "active" && health.currentLatency > 10000) {
      health.isStuck = true;
      health.stuckDetectedAt = nowIso();
      await this.autoRestartService(health.id);
    }

    this.serviceHealth.set(health.id, health);
    return health;
  }

  // Auto Restart Service
  private async autoRestartService(serviceId: string): Promise<void> {
    const health = this.serviceHealth.get(serviceId);
    if (!health) return;

    health.autoRestartCount++;
    health.lastRestart = nowIso();
    health.status = "active";
    health.isStuck = false;
    this.serviceHealth.set(serviceId, health);

    await this.auditService.create({
      entityType: "service_health",
      entityId: serviceId,
      action: "auto_restarted",
      userId: "system",
      changes: {
        status: { from: "stuck", to: "active" },
        autoRestartCount: { from: (health.autoRestartCount - 1).toString(), to: health.autoRestartCount.toString() },
      },
    });
  }

  // Update Job Queue Health
  async updateJobQueueHealth(input: {
    queueName: string;
    pendingJobs: number;
    processingJobs: number;
    completedJobs: number;
    failedJobs: number;
  }): Promise<JobQueueHealth> {
    const existing = Array.from(this.jobQueueHealth.values()).find((q) => q.queueName === input.queueName);

    const queueHealth: JobQueueHealth = {
      id: existing?.id || createId("queue-health"),
      queueName: input.queueName,
      status: existing?.status || "active",
      pendingJobs: input.pendingJobs,
      processingJobs: input.processingJobs,
      completedJobs: input.completedJobs,
      failedJobs: input.failedJobs,
      stuckJobs: existing?.stuckJobs || 0,
      deadJobs: existing?.deadJobs || 0,
      queueDepth: input.pendingJobs + input.processingJobs,
      workerCount: existing?.workerCount || 5,
      maxWorkers: existing?.maxWorkers || 10,
      autoScaled: existing?.autoScaled || false,
      jobLossPrevention: true,
      avgProcessingTime: existing?.avgProcessingTime || 1000,
      createdAt: existing?.createdAt || nowIso(),
      updatedAt: nowIso(),
    };

    // Auto scale if load high
    if (queueHealth.queueDepth > 50 && queueHealth.workerCount < queueHealth.maxWorkers) {
      await this.autoScaleQueue(queueHealth.id);
    }

    // Detect stuck jobs
    if (queueHealth.processingJobs > 0 && queueHealth.avgProcessingTime > 30000) {
      queueHealth.stuckJobs = queueHealth.processingJobs;
      await this.handleStuckJobs(queueHealth.id);
    }

    this.jobQueueHealth.set(queueHealth.id, queueHealth);
    return queueHealth;
  }

  // Auto Scale Queue
  private async autoScaleQueue(queueId: string): Promise<void> {
    const queue = this.jobQueueHealth.get(queueId);
    if (!queue) return;

    queue.workerCount++;
    queue.autoScaled = true;
    queue.lastAutoScale = nowIso();
    this.jobQueueHealth.set(queueId, queue);

    await this.auditService.create({
      entityType: "job_queue",
      entityId: queueId,
      action: "auto_scaled",
      userId: "system",
      changes: {
        workerCount: { from: (queue.workerCount - 1).toString(), to: queue.workerCount.toString() },
      },
    });
  }

  // Handle Stuck Jobs
  private async handleStuckJobs(queueId: string): Promise<void> {
    const queue = this.jobQueueHealth.get(queueId);
    if (!queue) return;

    // Move stuck jobs to retry
    queue.processingJobs -= queue.stuckJobs;
    queue.pendingJobs += queue.stuckJobs;
    queue.stuckJobs = 0;
    this.jobQueueHealth.set(queueId, queue);

    await this.auditService.create({
      entityType: "job_queue",
      entityId: queueId,
      action: "stuck_jobs_retried",
      userId: "system",
      changes: {
        stuckJobs: { from: "detected", to: "retried" },
      },
    });
  }

  // Update Payment Gateway Health
  async updatePaymentGatewayHealth(input: {
    gatewayName: string;
    isPrimary: boolean;
    totalRequests: number;
    successfulPayments: number;
    failedPayments: number;
    currentLatency: number;
  }): Promise<PaymentGatewayHealth> {
    const existing = Array.from(this.paymentGatewayHealth.values()).find((g) => g.gatewayName === input.gatewayName);

    const successRate = input.totalRequests > 0 ? (input.successfulPayments / input.totalRequests) * 100 : 100;
    const gatewayHealth: PaymentGatewayHealth = {
      id: existing?.id || createId("gateway-health"),
      gatewayName: input.gatewayName,
      status: successRate < 95 ? "degraded" : "active",
      isPrimary: input.isPrimary,
      totalRequests: input.totalRequests,
      successfulPayments: input.successfulPayments,
      failedPayments: input.failedPayments,
      successRate,
      currentLatency: input.currentLatency,
      avgLatency: existing?.avgLatency || input.currentLatency,
      failoverCount: existing?.failoverCount || 0,
      retryCount: existing?.retryCount || 0,
      fallbackUsed: existing?.fallbackUsed || false,
      isFastest: true,
      createdAt: existing?.createdAt || nowIso(),
      updatedAt: nowIso(),
    };

    // Auto failover if primary fails
    if (gatewayHealth.isPrimary && gatewayHealth.successRate < 80) {
      await this.autoFailoverGateway(gatewayHealth.id);
    }

    this.paymentGatewayHealth.set(gatewayHealth.id, gatewayHealth);
    return gatewayHealth;
  }

  // Auto Failover Gateway
  private async autoFailoverGateway(gatewayId: string): Promise<void> {
    const gateway = this.paymentGatewayHealth.get(gatewayId);
    if (!gateway) return;

    gateway.failoverCount++;
    gateway.lastFailover = nowIso();
    gateway.fallbackUsed = true;
    this.paymentGatewayHealth.set(gatewayId, gateway);

    await this.auditService.create({
      entityType: "payment_gateway",
      entityId: gatewayId,
      action: "auto_failover",
      userId: "system",
      changes: {
        failoverCount: { from: (gateway.failoverCount - 1).toString(), to: gateway.failoverCount.toString() },
      },
    });
  }

  // Validate SLO
  async validateSLO(serviceName: string, latencyThreshold: number, uptimeThreshold: number): Promise<SLOValidation> {
    const service = Array.from(this.serviceHealth.values()).find((s) => s.serviceName === serviceName);
    if (!service) {
      throw new Error("Service not found");
    }

    const validation: SLOValidation = {
      id: createId("slo-validation"),
      serviceName,
      latencyThreshold,
      uptimeThreshold,
      currentLatency: service.currentLatency,
      currentUptime: service.uptime,
      latencyBreach: service.currentLatency > latencyThreshold,
      uptimeBreach: service.uptime < uptimeThreshold,
      lastValidated: nowIso(),
    };

    if (validation.latencyBreach || validation.uptimeBreach) {
      validation.breachDetectedAt = nowIso();
    }

    this.sloValidations.set(validation.id, validation);
    return validation;
  }

  // Start Health Monitoring
  startHealthMonitoring(): void {
    if (this.healthCheckInterval) return;

    this.healthCheckInterval = setInterval(async () => {
      // Simulate health checks
      const services = ["api-service", "database", "job-queue", "payment-gateway"];
      for (const service of services) {
        const latency = Math.floor(Math.random() * 2000) + 50;
        await this.updateServiceHealth({ serviceName: service, currentLatency: latency });
      }
    }, 10000); // Check every 10 seconds
  }

  // Stop Health Monitoring
  stopHealthMonitoring(): void {
    if (this.healthCheckInterval) {
      clearInterval(this.healthCheckInterval);
      this.healthCheckInterval = null;
    }
  }

  // Getters
  listServiceHealth(): ServiceHealth[] {
    return Array.from(this.serviceHealth.values());
  }

  listJobQueueHealth(): JobQueueHealth[] {
    return Array.from(this.jobQueueHealth.values());
  }

  listPaymentGatewayHealth(): PaymentGatewayHealth[] {
    return Array.from(this.paymentGatewayHealth.values());
  }

  getKPI(): SystemHealthKPI {
    const services = Array.from(this.serviceHealth.values());
    const queues = Array.from(this.jobQueueHealth.values());
    const gateways = Array.from(this.paymentGatewayHealth.values());

    return {
      totalServices: services.length,
      activeServices: services.filter((s) => s.status === "active").length,
      degradedServices: services.filter((s) => s.status === "degraded").length,
      downServices: services.filter((s) => s.status === "down").length,
      avgLatency: services.length > 0 ? services.reduce((sum, s) => sum + s.currentLatency, 0) / services.length : 0,
      avgUptime: services.length > 0 ? services.reduce((sum, s) => sum + s.uptime, 0) / services.length : 100,
      totalJobs: queues.reduce((sum, q) => sum + q.pendingJobs + q.processingJobs, 0),
      stuckJobs: queues.reduce((sum, q) => sum + q.stuckJobs, 0),
      paymentSuccessRate: gateways.length > 0 ? gateways.reduce((sum, g) => sum + g.successRate, 0) / gateways.length : 100,
      autoRecoveryCount: services.reduce((sum, s) => sum + s.autoRestartCount, 0),
    };
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock service health
    const mockServices: ServiceHealth[] = [
      {
        id: createId("service-health"),
        serviceName: "api-service",
        status: "active",
        currentLatency: 150,
        latencyHistory: [120, 130, 140, 150, 160, 155, 150, 145, 140, 135, 130, 150],
        uptime: 99.9,
        uptimeSince: nowIso(),
        failureCount: 0,
        autoRestartCount: 0,
        isStuck: false,
        dependencyStatus: ["database:active", "cache:active"],
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("service-health"),
        serviceName: "database",
        status: "active",
        currentLatency: 50,
        latencyHistory: [45, 48, 50, 52, 50, 48, 45, 47, 50, 52, 50, 50],
        uptime: 100,
        uptimeSince: nowIso(),
        failureCount: 0,
        autoRestartCount: 0,
        isStuck: false,
        dependencyStatus: [],
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockServices.forEach((s) => this.serviceHealth.set(s.id, s));

    // Mock job queue health
    const mockQueues: JobQueueHealth[] = [
      {
        id: createId("queue-health"),
        queueName: "email-queue",
        status: "active",
        pendingJobs: 25,
        processingJobs: 5,
        completedJobs: 1000,
        failedJobs: 2,
        stuckJobs: 0,
        deadJobs: 0,
        queueDepth: 30,
        workerCount: 5,
        maxWorkers: 10,
        autoScaled: false,
        jobLossPrevention: true,
        avgProcessingTime: 500,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockQueues.forEach((q) => this.jobQueueHealth.set(q.id, q));

    // Mock payment gateway health
    const mockGateways: PaymentGatewayHealth[] = [
      {
        id: createId("gateway-health"),
        gatewayName: "stripe",
        status: "active",
        isPrimary: true,
        totalRequests: 5000,
        successfulPayments: 4950,
        failedPayments: 50,
        successRate: 99,
        currentLatency: 200,
        avgLatency: 180,
        failoverCount: 0,
        retryCount: 0,
        fallbackUsed: false,
        isFastest: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockGateways.forEach((g) => this.paymentGatewayHealth.set(g.id, g));
  }
}

