// ============================================
// CIRCUIT BREAKER SERVICE
// ============================================
class CircuitBreakerService {
  private circuitBreakers: Map<string, CircuitBreaker> = new Map();
  private circuitConfigs: Map<string, CircuitBreakerConfig> = new Map();
  private circuitMetrics: Map<string, CircuitBreakerMetrics> = new Map();
  private auditService: AuditLogService;
  private checkInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditService;
  }

  // Create Circuit Breaker
  async createCircuitBreaker(input: {
    name: string;
    service: CircuitBreakerService;
    failureThreshold: number;
    errorRateThreshold: number;
    latencyThreshold: number;
    cooldownPeriod: number;
  }): Promise<CircuitBreaker> {
    const breaker: CircuitBreaker = {
      id: createId("circuit-breaker"),
      name: input.name,
      service: input.service,
      state: "closed",
      failureThreshold: input.failureThreshold,
      currentFailures: 0,
      errorRate: 0,
      errorRateThreshold: input.errorRateThreshold,
      latencyThreshold: input.latencyThreshold,
      currentLatency: 0,
      totalCalls: 0,
      rejectedCalls: 0,
      cooldownPeriod: input.cooldownPeriod,
      lastStateChange: nowIso(),
      manualResetCount: 0,
      isStuck: false,
      autoHealScore: 100,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.circuitBreakers.set(breaker.id, breaker);

    // Create config
    const config: CircuitBreakerConfig = {
      id: createId("circuit-config"),
      breakerId: breaker.id,
      failureThreshold: input.failureThreshold,
      errorRateThreshold: input.errorRateThreshold,
      latencyThreshold: input.latencyThreshold,
      cooldownPeriod: input.cooldownPeriod,
      halfOpenMaxCalls: 5,
      enabled: true,
      updatedAt: nowIso(),
    };

    this.circuitConfigs.set(config.id, config);

    return breaker;
  }

  // Record Call
  async recordCall(breakerId: string, success: boolean, latency: number): Promise<void> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker) return;

    breaker.totalCalls++;
    breaker.currentLatency = latency;

    if (!success) {
      breaker.currentFailures++;
    }

    // Calculate error rate
    const totalCalls = breaker.totalCalls;
    const failedCalls = breaker.currentFailures;
    breaker.errorRate = totalCalls > 0 ? (failedCalls / totalCalls) * 100 : 0;

    // Check if should trip
    if (breaker.state === "closed") {
      if (breaker.currentFailures >= breaker.failureThreshold ||
          breaker.errorRate >= breaker.errorRateThreshold ||
          latency >= breaker.latencyThreshold) {
        await this.tripBreaker(breakerId);
      }
    }

    breaker.updatedAt = nowIso();
    this.circuitBreakers.set(breakerId, breaker);
  }

  // Trip Breaker
  private async tripBreaker(breakerId: string): Promise<void> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker) return;

    breaker.state = "open";
    breaker.lastTrip = nowIso();
    breaker.lastStateChange = nowIso();
    this.circuitBreakers.set(breakerId, breaker);

    await this.auditService.create({
      entityType: "circuit_breaker",
      entityId: breakerId,
      action: "tripped",
      userId: "system",
      changes: {
        state: { from: "closed", to: "open" },
        reason: { from: null, to: "threshold_exceeded" },
      },
    });

    // Schedule recovery probe
    setTimeout(() => this.attemptRecovery(breakerId), breaker.cooldownPeriod * 1000);
  }

  // Attempt Recovery
  private async attemptRecovery(breakerId: string): Promise<void> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker || breaker.state !== "open") return;

    breaker.state = "half_open";
    breaker.lastStateChange = nowIso();
    this.circuitBreakers.set(breakerId, breaker);

    await this.auditService.create({
      entityType: "circuit_breaker",
      entityId: breakerId,
      action: "recovery_attempt",
      userId: "system",
      changes: {
        state: { from: "open", to: "half_open" },
      },
    });
  }

  // Record Half-Open Result
  async recordHalfOpenResult(breakerId: string, success: boolean): Promise<void> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker || breaker.state !== "half_open") return;

    if (success) {
      breaker.state = "closed";
      breaker.currentFailures = 0;
      breaker.errorRate = 0;
      breaker.lastRecovery = nowIso();
      breaker.autoHealScore = Math.min(100, breaker.autoHealScore + 10);
    } else {
      breaker.state = "open";
      breaker.lastTrip = nowIso();
      breaker.autoHealScore = Math.max(0, breaker.autoHealScore - 10);
    }

    breaker.lastStateChange = nowIso();
    breaker.updatedAt = nowIso();
    this.circuitBreakers.set(breakerId, breaker);

    await this.auditService.create({
      entityType: "circuit_breaker",
      entityId: breakerId,
      action: success ? "recovered" : "recovery_failed",
      userId: "system",
      changes: {
        state: { from: "half_open", to: breaker.state },
      },
    });
  }

  // Manual Reset
  async manualReset(breakerId: string, userId: string): Promise<CircuitBreaker> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker) {
      throw new Error("Circuit breaker not found");
    }

    breaker.state = "closed";
    breaker.currentFailures = 0;
    breaker.errorRate = 0;
    breaker.lastStateChange = nowIso();
    breaker.manualResetCount++;
    breaker.lastManualReset = nowIso();
    breaker.isStuck = false;
    this.circuitBreakers.set(breakerId, breaker);

    await this.auditService.create({
      entityType: "circuit_breaker",
      entityId: breakerId,
      action: "manual_reset",
      userId,
      changes: {
        state: { from: "open", to: "closed" },
      },
    });

    return breaker;
  }

  // Detect Stuck State
  async detectStuckState(): Promise<void> {
    for (const breaker of this.circuitBreakers.values()) {
      if (breaker.state === "open") {
        const timeSinceTrip = breaker.lastTrip ? Date.now() - new Date(breaker.lastTrip).getTime() : Infinity;
        if (timeSinceTrip > breaker.cooldownPeriod * 1000 * 5) { // 5x cooldown
          breaker.isStuck = true;
          breaker.stuckDetectedAt = nowIso();
          this.circuitBreakers.set(breaker.id, breaker);

          // Force probe
          await this.attemptRecovery(breaker.id);
        }
      }
    }
  }

  // Calculate Metrics
  async calculateMetrics(breakerId: string, period: "1h" | "24h" | "7d"): Promise<CircuitBreakerMetrics> {
    const breaker = this.circuitBreakers.get(breakerId);
    if (!breaker) {
      throw new Error("Circuit breaker not found");
    }

    const metrics: CircuitBreakerMetrics = {
      id: createId("circuit-metrics"),
      breakerId,
      period,
      totalCalls: breaker.totalCalls,
      successfulCalls: breaker.totalCalls - breaker.currentFailures,
      failedCalls: breaker.currentFailures,
      rejectedCalls: breaker.rejectedCalls,
      avgLatency: breaker.currentLatency,
      tripCount: breaker.lastTrip ? 1 : 0,
      recoveryCount: breaker.lastRecovery ? 1 : 0,
      autoHealScore: breaker.autoHealScore,
      calculatedAt: nowIso(),
    };

    this.circuitMetrics.set(metrics.id, metrics);
    return metrics;
  }

  // Start Monitoring
  startMonitoring(): void {
    if (this.checkInterval) return;

    this.checkInterval = setInterval(async () => {
      await this.detectStuckState();
    }, 30000); // Check every 30 seconds
  }

  // Stop Monitoring
  stopMonitoring(): void {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = null;
    }
  }

  // Getters
  listCircuitBreakers(): CircuitBreaker[] {
    return Array.from(this.circuitBreakers.values());
  }

  listConfigs(): CircuitBreakerConfig[] {
    return Array.from(this.circuitConfigs.values());
  }

  listMetrics(): CircuitBreakerMetrics[] {
    return Array.from(this.circuitMetrics.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock circuit breakers
    const mockBreakers: CircuitBreaker[] = [
      {
        id: createId("circuit-breaker"),
        name: "API Gateway Breaker",
        service: "api_gateway",
        state: "closed",
        failureThreshold: 5,
        currentFailures: 0,
        errorRate: 0,
        errorRateThreshold: 50,
        latencyThreshold: 5000,
        currentLatency: 150,
        totalCalls: 1000,
        rejectedCalls: 0,
        cooldownPeriod: 60,
        lastStateChange: nowIso(),
        manualResetCount: 0,
        isStuck: false,
        autoHealScore: 100,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("circuit-breaker"),
        name: "Database Breaker",
        service: "database",
        state: "closed",
        failureThreshold: 3,
        currentFailures: 0,
        errorRate: 0,
        errorRateThreshold: 30,
        latencyThreshold: 2000,
        currentLatency: 50,
        totalCalls: 500,
        rejectedCalls: 0,
        cooldownPeriod: 30,
        lastStateChange: nowIso(),
        manualResetCount: 0,
        isStuck: false,
        autoHealScore: 100,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockBreakers.forEach((b) => this.circuitBreakers.set(b.id, b));
  }
}

export const circuitBreakerService = new CircuitBreakerService();

// ============================================
// BACKUP HISTORY SERVICE
// ============================================
class BackupHistoryService {
  private backups: Map<string, Backup> = new Map();
  private restoreLogs: Map<string, RestoreLog> = new Map();
  private downloadLogs: Map<string, DownloadLog> = new Map();
  private backupChains: Map<string, BackupChain> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Create Backup
  async createBackup(input: {
    name: string;
    type: BackupType;
    parentBackupId?: string;
  }): Promise<Backup> {
    const backup: Backup = {
      id: createId("backup"),
      name: input.name,
      type: input.type,
      status: "in_progress",
      timestamp: nowIso(),
      duration: 0,
      size: 0,
      checksum: "",
      isCorrupt: false,
      parentBackupId: input.parentBackupId,
      storageLocation: "/backups/" + input.name,
      encrypted: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.backups.set(backup.id, backup);

    // Simulate backup completion
    setTimeout(async () => {
      await this.completeBackup(backup.id);
    }, 2000);

    return backup;
  }

  // Complete Backup
  private async completeBackup(backupId: string): Promise<void> {
    const backup = this.backups.get(backupId);
    if (!backup) return;

    backup.status = "completed";
    backup.duration = Math.floor(Math.random() * 300) + 60; // 1-5 minutes
    backup.size = Math.floor(Math.random() * 1000000000) + 100000000; // 100MB-1GB
    backup.checksum = createId("checksum");
    backup.updatedAt = nowIso();
    this.backups.set(backupId, backup);

    // Validate chain
    if (backup.type === "incremental") {
      await this.validateBackupChain(backup.parentBackupId!);
    }
  }

  // Restore Backup
  async restoreBackup(backupId: string, userId: string): Promise<RestoreLog> {
    const backup = this.backups.get(backupId);
    if (!backup) {
      throw new Error("Backup not found");
    }

    if (backup.isCorrupt) {
      throw new Error("Backup is corrupt and cannot be restored");
    }

    // Validate chain for incremental
    if (backup.type === "incremental" && backup.parentBackupId) {
      const chain = this.backupChains.get(backup.parentBackupId);
      if (!chain || !chain.chainValid) {
        throw new Error("Backup chain is invalid");
      }
    }

    // Create temp snapshot
    const tempSnapshotId = createId("snapshot");

    const restoreLog: RestoreLog = {
      id: createId("restore-log"),
      backupId,
      restoredBy: userId,
      restoredAt: nowIso(),
      duration: 0,
      status: "success",
      rollbackTriggered: false,
      tempSnapshotId,
    };

    // Simulate restore
    await new Promise((resolve) => setTimeout(resolve, 1000));

    // Mock restore (90% success rate)
    const success = Math.random() > 0.1;
    if (!success) {
      restoreLog.status = "failed";
      restoreLog.errorMessage = "Restore failed";
      restoreLog.rollbackTriggered = true;
      restoreLog.rollbackAt = nowIso();

      await this.auditService.create({
        entityType: "backup_restore",
        entityId: restoreLog.id,
        action: "rolled_back",
        userId: "system",
        changes: {
          status: { from: "failed", to: "rolled_back" },
        },
      });
    } else {
      restoreLog.duration = Math.floor(Math.random() * 600) + 120; // 2-10 minutes
    }

    this.restoreLogs.set(restoreLog.id, restoreLog);

    await this.auditService.create({
      entityType: "backup_restore",
      entityId: restoreLog.id,
      action: "restored",
      userId,
      changes: {
        backupId: { from: null, to: backupId },
        status: { from: null, to: restoreLog.status },
      },
    });

    return restoreLog;
  }

  // Download Backup
  async downloadBackup(backupId: string, userId: string, ipAddress?: string): Promise<DownloadLog> {
    const backup = this.backups.get(backupId);
    if (!backup) {
      throw new Error("Backup not found");
    }

    if (backup.isCorrupt) {
      throw new Error("Backup is corrupt and cannot be downloaded");
    }

    // Verify checksum
    const checksumValid = true; // Mock validation

    const downloadLog: DownloadLog = {
      id: createId("download-log"),
      backupId,
      downloadedBy: userId,
      downloadedAt: nowIso(),
      ipAddress,
      success: checksumValid,
    };

    if (!checksumValid) {
      downloadLog.success = false;
      downloadLog.errorMessage = "Checksum verification failed";
    }

    this.downloadLogs.set(downloadLog.id, downloadLog);

    await this.auditService.create({
      entityType: "backup_download",
      entityId: downloadLog.id,
      action: "downloaded",
      userId,
      changes: {
        backupId: { from: null, to: backupId },
        success: { from: null, to: downloadLog.success.toString() },
      },
    });

    return downloadLog;
  }

  // Validate Backup Chain
  private async validateBackupChain(fullBackupId: string): Promise<void> {
    const fullBackup = this.backups.get(fullBackupId);
    if (!fullBackup) return;

    const incrementals = Array.from(this.backups.values())
      .filter((b) => b.parentBackupId === fullBackupId && b.status === "completed");

    const chain: BackupChain = {
      fullBackupId,
      incrementalBackupIds: incrementals.map((b) => b.id),
      chainValid: true,
      lastValidated: nowIso(),
      missingBackups: [],
    };

    // Check for missing backups in chain
    if (incrementals.length === 0 && fullBackup.type === "full") {
      chain.chainValid = true;
    }

    this.backupChains.set(fullBackupId, chain);
  }

  // Detect Corrupt Backup
  async detectCorruptBackup(backupId: string): Promise<void> {
    const backup = this.backups.get(backupId);
    if (!backup) return;

    // Simulate corruption detection (5% chance)
    if (Math.random() < 0.05) {
      backup.isCorrupt = true;
      backup.corruptDetectedAt = nowIso();
      this.backups.set(backupId, backup);

      await this.auditService.create({
        entityType: "backup",
        entityId: backupId,
        action: "marked_corrupt",
        userId: "system",
        changes: {
          isCorrupt: { from: "false", to: "true" },
        },
      });
    }
  }

  // Auto Retry Failed Backup
  async autoRetryFailedBackup(backupId: string): Promise<void> {
    const backup = this.backups.get(backupId);
    if (!backup || backup.status !== "failed") return;

    backup.status = "in_progress";
    this.backups.set(backupId, backup);

    // Simulate retry
    setTimeout(async () => {
      await this.completeBackup(backupId);
    }, 2000);
  }

  // Getters
  listBackups(): Backup[] {
    return Array.from(this.backups.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  listRestoreLogs(): RestoreLog[] {
    return Array.from(this.restoreLogs.values()).sort((a, b) =>
      new Date(b.restoredAt).getTime() - new Date(a.restoredAt).getTime()
    );
  }

  listDownloadLogs(): DownloadLog[] {
    return Array.from(this.downloadLogs.values()).sort((a, b) =>
      new Date(b.downloadedAt).getTime() - new Date(a.downloadedAt).getTime()
    );
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock backups
    const mockBackups: Backup[] = [
      {
        id: createId("backup"),
        name: "full-backup-2024-04-20",
        type: "full",
        status: "completed",
        timestamp: new Date(Date.now() - 86400000 * 3).toISOString(),
        duration: 300,
        size: 500000000,
        checksum: createId("checksum"),
        isCorrupt: false,
        storageLocation: "/backups/full-backup-2024-04-20",
        encrypted: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("backup"),
        name: "incremental-backup-2024-04-21",
        type: "incremental",
        status: "completed",
        timestamp: new Date(Date.now() - 86400000 * 2).toISOString(),
        duration: 120,
        size: 100000000,
        checksum: createId("checksum"),
        isCorrupt: false,
        parentBackupId: mockBackups[0].id,
        storageLocation: "/backups/incremental-backup-2024-04-21",
        encrypted: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("backup"),
        name: "full-backup-2024-04-22",
        type: "full",
        status: "completed",
        timestamp: new Date(Date.now() - 86400000).toISOString(),
        duration: 320,
        size: 520000000,
        checksum: createId("checksum"),
        isCorrupt: false,
        storageLocation: "/backups/full-backup-2024-04-22",
        encrypted: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockBackups.forEach((b) => this.backups.set(b.id, b));
  }
}

