// ============================================
// INCIDENT MANAGEMENT SERVICE
// ============================================
class IncidentManagementService {
  private incidents: Map<string, Incident> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Create Incident
  async createIncident(input: {
    title: string;
    description: string;
    priority: IncidentPriority;
    service: string;
    affectedServices: string[];
  }, userId: string): Promise<Incident> {
    const incident: Incident = {
      id: createId("incident"),
      title: input.title,
      description: input.description,
      priority: input.priority,
      status: "open",
      service: input.service,
      startedAt: nowIso(),
      affectedServices: input.affectedServices,
      autoResolved: false,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.incidents.set(incident.id, incident);

    await this.auditService.create({
      entityType: "incident",
      entityId: incident.id,
      action: "created",
      userId,
      changes: {
        title: { from: null, to: input.title },
        priority: { from: null, to: input.priority },
      },
    });

    return incident;
  }

  // Resolve Incident
  async resolveIncident(incidentId: string, rootCause?: string, userId?: string): Promise<Incident> {
    const incident = this.incidents.get(incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    incident.status = "resolved";
    incident.resolvedAt = nowIso();
    incident.duration = Date.now() - new Date(incident.startedAt).getTime();
    incident.rootCause = rootCause;
    incident.updatedAt = nowIso();
    this.incidents.set(incidentId, incident);

    await this.auditService.create({
      entityType: "incident",
      entityId: incidentId,
      action: "resolved",
      userId: userId || "system",
      changes: {
        status: { from: "open", to: "resolved" },
        rootCause: { from: null, to: rootCause || "resolved" },
      },
    });

    return incident;
  }

  // Auto Resolve Incident
  async autoResolveIncident(incidentId: string): Promise<void> {
    const incident = this.incidents.get(incidentId);
    if (!incident) return;

    incident.status = "resolved";
    incident.resolvedAt = nowIso();
    incident.duration = Date.now() - new Date(incident.startedAt).getTime();
    incident.autoResolved = true;
    incident.updatedAt = nowIso();
    this.incidents.set(incidentId, incident);
  }

  // Getters
  listIncidents(): Incident[] {
    return Array.from(this.incidents.values()).sort((a, b) =>
      new Date(b.startedAt).getTime() - new Date(a.startedAt).getTime()
    );
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock incidents
    const mockIncidents: Incident[] = [
      {
        id: createId("incident"),
        title: "API Gateway Latency Spike",
        description: "API Gateway experiencing high latency",
        priority: "high",
        status: "resolved",
        service: "api-gateway",
        startedAt: new Date(Date.now() - 3600000).toISOString(),
        resolvedAt: new Date(Date.now() - 1800000).toISOString(),
        duration: 1800000,
        rootCause: "Database connection pool exhaustion",
        affectedServices: ["api-gateway", "database"],
        autoResolved: false,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockIncidents.forEach((i) => this.incidents.set(i.id, i));
  }
}

