// ============================================
// SLO/SLA SERVICE
// ============================================
class SLOSLAService {
  private slos: Map<string, SLO> = new Map();
  private slas: Map<string, SLA> = new Map();

  // Create SLO
  async createSLO(input: {
    serviceName: string;
    metricName: string;
    targetValue: number;
    unit: string;
    period: string;
  }): Promise<SLO> {
    const slo: SLO = {
      id: createId("slo"),
      serviceName: input.serviceName,
      metricName: input.metricName,
      targetValue: input.targetValue,
      currentValue: 0,
      unit: input.unit,
      period: input.period,
      isBreached: false,
      lastCalculated: nowIso(),
    };

    this.slos.set(slo.id, slo);
    return slo;
  }

  // Update SLO Value
  async updateSLOValue(sloId: string, currentValue: number): Promise<SLO> {
    const slo = this.slos.get(sloId);
    if (!slo) {
      throw new Error("SLO not found");
    }

    slo.currentValue = currentValue;
    slo.isBreached = currentValue > slo.targetValue;
    if (slo.isBreached) {
      slo.breachDetectedAt = nowIso();
    }
    slo.lastCalculated = nowIso();
    this.slos.set(sloId, slo);

    return slo;
  }

  // Create SLA
  async createSLA(input: {
    customerName: string;
    sloIds: string[];
    period: string;
  }): Promise<SLA> {
    const sla: SLA = {
      id: createId("sla"),
      customerName: input.customerName,
      sloIds: input.sloIds,
      overallCompliance: 100,
      isBreached: false,
      period: input.period,
      lastCalculated: nowIso(),
    };

    this.slas.set(sla.id, sla);
    return sla;
  }

  // Calculate SLA Compliance
  async calculateSLACompliance(slaId: string): Promise<SLA> {
    const sla = this.slas.get(slaId);
    if (!sla) {
      throw new Error("SLA not found");
    }

    let totalCompliance = 0;
    let breachedCount = 0;

    for (const sloId of sla.sloIds) {
      const slo = this.slos.get(sloId);
      if (slo) {
        const compliance = slo.isBreached ? 0 : 100;
        totalCompliance += compliance;
        if (slo.isBreached) breachedCount++;
      }
    }

    sla.overallCompliance = sla.sloIds.length > 0 ? totalCompliance / sla.sloIds.length : 100;
    sla.isBreached = breachedCount > 0;
    sla.lastCalculated = nowIso();
    this.slas.set(slaId, sla);

    return sla;
  }

  // Getters
  listSLOs(): SLO[] {
    return Array.from(this.slos.values());
  }

  listSLAs(): SLA[] {
    return Array.from(this.slas.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock SLOs
    const mockSLOs: SLO[] = [
      {
        id: createId("slo"),
        serviceName: "api-gateway",
        metricName: "latency",
        targetValue: 200,
        currentValue: 150,
        unit: "ms",
        period: "24h",
        isBreached: false,
        lastCalculated: nowIso(),
      },
      {
        id: createId("slo"),
        serviceName: "database",
        metricName: "uptime",
        targetValue: 99.9,
        currentValue: 99.95,
        unit: "%",
        period: "7d",
        isBreached: false,
        lastCalculated: nowIso(),
      },
    ];

    mockSLOs.forEach((s) => this.slos.set(s.id, s));
  }
}

