// ============================================
// ALERT SERVICE
// ============================================
class AlertService {
  private alerts: Map<string, SystemAlert> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Create Alert
  async createAlert(input: {
    type: SystemAlertType;
    title: string;
    message: string;
    severity: "critical" | "high" | "medium" | "low";
    service: string;
    channels: AlertChannel[];
    metadata?: Record<string, unknown>;
  }): Promise<SystemAlert> {
    const alert: SystemAlert = {
      id: createId("alert"),
      type: input.type,
      title: input.title,
      message: input.message,
      severity: input.severity,
      status: "open",
      service: input.service,
      triggeredAt: nowIso(),
      channels: input.channels,
      sentCount: 0,
      metadata: input.metadata || {},
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.alerts.set(alert.id, alert);

    // Send notifications
    await this.sendNotifications(alert.id);

    return alert;
  }

  // Send Notifications
  private async sendNotifications(alertId: string): Promise<void> {
    const alert = this.alerts.get(alertId);
    if (!alert) return;

    // Simulate sending notifications
    await new Promise((resolve) => setTimeout(resolve, 500));

    alert.sentCount = alert.channels.length;
    this.alerts.set(alertId, alert);
  }

  // Acknowledge Alert
  async acknowledgeAlert(alertId: string, userId: string): Promise<SystemAlert> {
    const alert = this.alerts.get(alertId);
    if (!alert) {
      throw new Error("Alert not found");
    }

    alert.status = "acknowledged";
    alert.acknowledgedAt = nowIso();
    alert.acknowledgedBy = userId;
    alert.updatedAt = nowIso();
    this.alerts.set(alertId, alert);

    await this.auditService.create({
      entityType: "alert",
      entityId: alertId,
      action: "acknowledged",
      userId,
      changes: {
        status: { from: "open", to: "acknowledged" },
      },
    });

    return alert;
  }

  // Resolve Alert
  async resolveAlert(alertId: string, userId?: string): Promise<SystemAlert> {
    const alert = this.alerts.get(alertId);
    if (!alert) {
      throw new Error("Alert not found");
    }

    alert.status = "resolved";
    alert.resolvedAt = nowIso();
    alert.updatedAt = nowIso();
    this.alerts.set(alertId, alert);

    await this.auditService.create({
      entityType: "alert",
      entityId: alertId,
      action: "resolved",
      userId: userId || "system",
      changes: {
        status: { from: alert.acknowledgedAt ? "acknowledged" : "open", to: "resolved" },
      },
    });

    return alert;
  }

  // Getters
  listAlerts(): SystemAlert[] {
    return Array.from(this.alerts.values()).sort((a, b) =>
      new Date(b.triggeredAt).getTime() - new Date(a.triggeredAt).getTime()
    );
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock alerts
    const mockAlerts: SystemAlert[] = [
      {
        id: createId("alert"),
        type: "latency_spike",
        title: "High Latency Detected",
        message: "API Gateway latency exceeded threshold",
        severity: "high",
        status: "resolved",
        service: "api-gateway",
        triggeredAt: new Date(Date.now() - 3600000).toISOString(),
        acknowledgedAt: new Date(Date.now() - 3500000).toISOString(),
        acknowledgedBy: "admin",
        resolvedAt: new Date(Date.now() - 1800000).toISOString(),
        channels: ["email", "slack"],
        sentCount: 2,
        metadata: { threshold: 500, actual: 650 },
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockAlerts.forEach((a) => this.alerts.set(a.id, a));
  }
}

