// ============================================
// NOTIFICATION SERVICE
// ============================================
class NotificationService {
  private notifications: Map<string, Notification> = new Map();
  private notificationGroups: Map<string, NotificationGroup> = new Map();
  private auditService: AuditLogService;
  private eventFilter: Set<string> = new Set(); // Duplicate event filter

  constructor() {
    this.auditService = auditService;
  }

  // Create Notification
  async createNotification(input: {
    type: NotificationEventType;
    title: string;
    message: string;
    userId?: string;
    metadata?: Record<string, unknown>;
  }): Promise<Notification> {
    // Auto assign priority
    const priority = this.autoAssignPriority(input.type);

    const notification: Notification = {
      id: createId("notification"),
      type: input.type,
      title: input.title,
      message: input.message,
      priority,
      status: "unread",
      timestamp: nowIso(),
      userId: input.userId,
      metadata: input.metadata || {},
      linkedLogIds: [],
      autoResolved: false,
      retryCount: 0,
      escalated: false,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    // Check for duplicate
    const eventKey = `${input.type}-${input.title}-${Date.now()}`;
    if (this.eventFilter.has(eventKey)) {
      // Collapse duplicate
      return notification;
    }
    this.eventFilter.add(eventKey);

    this.notifications.set(notification.id, notification);

    // Link to logs
    await this.linkToLogs(notification.id);

    // Auto handle webhook failures
    if (input.type === "webhook_failed") {
      await this.handleWebhookFailure(notification.id);
    }

    return notification;
  }

  // Auto Assign Priority
  private autoAssignPriority(type: NotificationEventType): NotificationPriority {
    const criticalTypes: NotificationEventType[] = ["payment_dispute", "webhook_failed"];
    const highTypes: NotificationEventType[] = ["merchant_signup", "anomaly_detected"];
    const normalTypes: NotificationEventType[] = ["subscription_cancel", "report_generated"];

    if (criticalTypes.includes(type)) return "critical";
    if (highTypes.includes(type)) return "high";
    if (normalTypes.includes(type)) return "normal";
    return "low";
  }

  // Link to Logs
  private async linkToLogs(notificationId: string): Promise<void> {
    const notification = this.notifications.get(notificationId);
    if (!notification) return;

    // Simulate linking
    notification.linkedLogIds = [createId("api-log"), createId("audit-log")];
    this.notifications.set(notificationId, notification);
  }

  // Handle Webhook Failure
  private async handleWebhookFailure(notificationId: string): Promise<void> {
    const notification = this.notifications.get(notificationId);
    if (!notification) return;

    // Identify root cause
    const rootCauses: Array<"timeout" | "invalid_payload" | "auth_error" | "unknown"> = ["timeout", "invalid_payload", "auth_error", "unknown"];
    notification.failureRootCause = rootCauses[Math.floor(Math.random() * rootCauses.length)];

    // Auto retry
    notification.retryCount++;
    const success = Math.random() > 0.3; // 70% success rate

    if (success) {
      notification.autoResolved = true;
      notification.resolvedAt = nowIso();
      notification.status = "resolved";
    } else if (notification.retryCount >= 3) {
      // Escalate
      notification.escalated = true;
      notification.escalatedAt = nowIso();
      notification.priority = "critical";
    }

    this.notifications.set(notificationId, notification);
  }

  // Mark as Read
  async markAsRead(notificationId: string, userId: string): Promise<Notification> {
    const notification = this.notifications.get(notificationId);
    if (!notification) {
      throw new Error("Notification not found");
    }

    notification.status = "read";
    notification.updatedAt = nowIso();
    this.notifications.set(notificationId, notification);

    await this.auditService.create({
      entityType: "notification",
      entityId: notificationId,
      action: "marked_read",
      userId,
      changes: {
        status: { from: "unread", to: "read" },
      },
    });

    return notification;
  }

  // Resolve Notification
  async resolveNotification(notificationId: string, userId: string): Promise<Notification> {
    const notification = this.notifications.get(notificationId);
    if (!notification) {
      throw new Error("Notification not found");
    }

    notification.status = "resolved";
    notification.resolvedAt = nowIso();
    notification.updatedAt = nowIso();
    this.notifications.set(notificationId, notification);

    await this.auditService.create({
      entityType: "notification",
      entityId: notificationId,
      action: "resolved",
      userId,
      changes: {
        status: { from: notification.status, to: "resolved" },
      },
    });

    return notification;
  }

  // Delete Notification (UI only)
  async deleteNotification(notificationId: string, userId: string): Promise<void> {
    const notification = this.notifications.get(notificationId);
    if (!notification) {
      throw new Error("Notification not found");
    }

    this.notifications.delete(notificationId);

    await this.auditService.create({
      entityType: "notification",
      entityId: notificationId,
      action: "deleted",
      userId,
      changes: {},
    });
  }

  // Retrigger Notification
  async retriggerNotification(notificationId: string, userId: string): Promise<Notification> {
    const notification = this.notifications.get(notificationId);
    if (!notification) {
      throw new Error("Notification not found");
    }

    notification.retryCount++;
    notification.updatedAt = nowIso();
    this.notifications.set(notificationId, notification);

    // Re-handle webhook failure
    if (notification.type === "webhook_failed") {
      await this.handleWebhookFailure(notificationId);
    }

    await this.auditService.create({
      entityType: "notification",
      entityId: notificationId,
      action: "retriggered",
      userId,
      changes: {
        retryCount: { from: (notification.retryCount - 1).toString(), to: notification.retryCount.toString() },
      },
    });

    return notification;
  }

  // Group Notifications
  async groupNotifications(type: NotificationEventType, timeWindow: number): Promise<NotificationGroup> {
    const notifications = Array.from(this.notifications.values())
      .filter((n) => n.type === type && n.status !== "resolved")
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

    if (notifications.length === 0) {
      throw new Error("No notifications to group");
    }

    const group: NotificationGroup = {
      id: createId("notification-group"),
      type,
      title: `${type.replace(/_/g, " ").toUpperCase()} Group`,
      count: notifications.length,
      notificationIds: notifications.map((n) => n.id),
      earliestTimestamp: notifications[notifications.length - 1].timestamp,
      latestTimestamp: notifications[0].timestamp,
      priority: notifications[0].priority,
      status: "unread",
    };

    this.notificationGroups.set(group.id, group);
    return group;
  }

  // Get Analytics
  getAnalytics(): NotificationAnalytics {
    const notifications = Array.from(this.notifications.values());
    const eventFrequency: Record<NotificationEventType, number> = {
      merchant_signup: 0,
      payment_dispute: 0,
      subscription_cancel: 0,
      webhook_failed: 0,
      report_generated: 0,
      anomaly_detected: 0,
      system_alert: 0,
      custom: 0,
    };

    notifications.forEach((n) => {
      eventFrequency[n.type]++;
    });

    return {
      totalNotifications: notifications.length,
      unreadCount: notifications.filter((n) => n.status === "unread").length,
      criticalCount: notifications.filter((n) => n.priority === "critical").length,
      highCount: notifications.filter((n) => n.priority === "high").length,
      normalCount: notifications.filter((n) => n.priority === "normal").length,
      lowCount: notifications.filter((n) => n.priority === "low").length,
      eventFrequency,
      failureRate: notifications.length > 0 ? (notifications.filter((n) => n.type === "webhook_failed").length / notifications.length) * 100 : 0,
      avgAlertLatency: 0, // Would calculate from event creation to notification
    };
  }

  // Getters
  listNotifications(): Notification[] {
    return Array.from(this.notifications.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  listGroups(): NotificationGroup[] {
    return Array.from(this.notificationGroups.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock notifications
    const mockNotifications: Notification[] = [
      {
        id: createId("notification"),
        type: "merchant_signup",
        title: "New Merchant Signup",
        message: "Merchant ABC Inc. has signed up",
        priority: "high",
        status: "unread",
        timestamp: new Date(Date.now() - 3600000).toISOString(),
        metadata: { merchantId: "merchant-123" },
        linkedLogIds: [createId("log")],
        autoResolved: false,
        retryCount: 0,
        escalated: false,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("notification"),
        type: "webhook_failed",
        title: "Webhook Delivery Failed",
        message: "Webhook to https://example.com/webhook failed",
        priority: "critical",
        status: "unread",
        timestamp: new Date(Date.now() - 1800000).toISOString(),
        failureRootCause: "timeout",
        linkedLogIds: [createId("log")],
        autoResolved: false,
        retryCount: 1,
        escalated: false,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("notification"),
        type: "report_generated",
        title: "Monthly Report Ready",
        message: "April 2024 monthly report is ready for download",
        priority: "normal",
        status: "read",
        timestamp: new Date(Date.now() - 86400000).toISOString(),
        linkedLogIds: [createId("log")],
        autoResolved: false,
        retryCount: 0,
        escalated: false,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockNotifications.forEach((n) => this.notifications.set(n.id, n));
  }
}

export const notificationService = new NotificationService();

// ============================================
// BACKUP & RESTORE SERVICE
// ============================================
class BackupRestoreService {
  private backupOperations: Map<string, BackupOperation> = new Map();
  private restoreOperations: Map<string, RestoreOperation> = new Map();
  private backupSchedules: Map<string, BackupSchedule> = new Map();
  private auditService: AuditLogService;
  private schedulerInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditService;
  }

  // Create Backup
  async createBackup(input: {
    type: BackupOperationType;
    createdBy: string;
  }): Promise<BackupOperation> {
    const operation: BackupOperation = {
      id: createId("backup-operation"),
      type: input.type,
      status: "pending",
      startedAt: nowIso(),
      size: 0,
      checksum: "",
      isCorrupt: false,
      storageLocation: "/backups/" + input.type + "-" + Date.now(),
      encrypted: true,
      retryCount: 0,
      maxRetries: 3,
      fallbackUsed: false,
      createdBy: input.createdBy,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.backupOperations.set(operation.id, operation);

    // Simulate backup execution
    setTimeout(async () => {
      await this.executeBackup(operation.id);
    }, 1000);

    return operation;
  }

  // Execute Backup
  private async executeBackup(operationId: string): Promise<void> {
    const operation = this.backupOperations.get(operationId);
    if (!operation) return;

    operation.status = "running";
    this.backupOperations.set(operationId, operation);

    // Simulate backup
    await new Promise((resolve) => setTimeout(resolve, 2000));

    // Mock backup (90% success rate)
    const success = Math.random() > 0.1;
    if (success) {
      operation.status = "completed";
      operation.completedAt = nowIso();
      operation.duration = Date.now() - new Date(operation.startedAt).getTime();
      operation.size = Math.floor(Math.random() * 1000000000) + 100000000; // 100MB-1GB
      operation.checksum = createId("checksum");
    } else {
      operation.status = "failed";
      operation.completedAt = nowIso();
      operation.duration = Date.now() - new Date(operation.startedAt).getTime();

      // Auto retry
      if (operation.retryCount < operation.maxRetries) {
        await this.retryBackup(operationId);
      } else {
        // Use fallback
        await this.useFallbackBackup(operationId);
      }
    }

    operation.updatedAt = nowIso();
    this.backupOperations.set(operationId, operation);
  }

  // Retry Backup
  private async retryBackup(operationId: string): Promise<void> {
    const operation = this.backupOperations.get(operationId);
    if (!operation) return;

    operation.retryCount++;
    operation.status = "pending";
    this.backupOperations.set(operationId, operation);

    setTimeout(async () => {
      await this.executeBackup(operationId);
    }, 1000);
  }

  // Use Fallback Backup
  private async useFallbackBackup(operationId: string): Promise<void> {
    const operation = this.backupOperations.get(operationId);
    if (!operation) return;

    operation.fallbackUsed = true;
    operation.fallbackLocation = "/backups/fallback/" + Date.now();
    operation.status = "running";
    this.backupOperations.set(operationId, operation);

    setTimeout(async () => {
      await this.executeBackup(operationId);
    }, 1000);
  }

  // Restore Backup
  async restoreBackup(input: {
    backupOperationId: string;
    type: RestoreType;
    modules?: string[];
    restoredBy: string;
  }): Promise<RestoreOperation> {
    const backup = this.backupOperations.get(input.backupOperationId);
    if (!backup) {
      throw new Error("Backup not found");
    }

    if (backup.isCorrupt) {
      throw new Error("Backup is corrupt and cannot be restored");
    }

    // Create snapshot before restore
    const snapshotId = createId("snapshot");

    const restoreOperation: RestoreOperation = {
      id: createId("restore-operation"),
      backupOperationId: input.backupOperationId,
      type: input.type,
      status: "running",
      startedAt: nowIso(),
      snapshotId,
      modules: input.modules,
      rollbackTriggered: false,
      restoredBy: input.restoredBy,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.restoreOperations.set(restoreOperation.id, restoreOperation);

    // Simulate restore
    await new Promise((resolve) => setTimeout(resolve, 2000));

    // Mock restore (85% success rate)
    const success = Math.random() > 0.15;
    if (success) {
      restoreOperation.status = "completed";
      restoreOperation.completedAt = nowIso();
      restoreOperation.duration = Date.now() - new Date(restoreOperation.startedAt).getTime();
    } else {
      restoreOperation.status = "failed";
      restoreOperation.completedAt = nowIso();
      restoreOperation.duration = Date.now() - new Date(restoreOperation.startedAt).getTime();
      restoreOperation.errorMessage = "Restore failed";
      restoreOperation.rollbackTriggered = true;
      restoreOperation.rollbackAt = nowIso();
    }

    restoreOperation.updatedAt = nowIso();
    this.restoreOperations.set(restoreOperation.id, restoreOperation);

    await this.auditService.create({
      entityType: "backup_restore",
      entityId: restoreOperation.id,
      action: "restored",
      userId: input.restoredBy,
      changes: {
        backupOperationId: { from: null, to: input.backupOperationId },
        status: { from: null, to: restoreOperation.status },
      },
    });

    return restoreOperation;
  }

  // Detect Corrupt Backup
  async detectCorruptBackup(operationId: string): Promise<void> {
    const operation = this.backupOperations.get(operationId);
    if (!operation) return;

    // Simulate corruption detection (5% chance)
    if (Math.random() < 0.05) {
      operation.isCorrupt = true;
      operation.corruptDetectedAt = nowIso();
      this.backupOperations.set(operationId, operation);

      await this.auditService.create({
        entityType: "backup",
        entityId: operationId,
        action: "marked_corrupt",
        userId: "system",
        changes: {
          isCorrupt: { from: "false", to: "true" },
        },
      });
    }
  }

  // Create Schedule
  async createSchedule(input: {
    type: BackupOperationType;
    frequency: "daily" | "weekly" | "monthly";
    retentionDays: number;
  }): Promise<BackupSchedule> {
    const schedule: BackupSchedule = {
      id: createId("backup-schedule"),
      type: input.type,
      frequency: input.frequency,
      nextRun: this.calculateNextRun(input.frequency),
      enabled: true,
      retentionDays: input.retentionDays,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.backupSchedules.set(schedule.id, schedule);
    return schedule;
  }

  // Calculate Next Run
  private calculateNextRun(frequency: "daily" | "weekly" | "monthly"): string {
    const now = new Date();
    if (frequency === "daily") {
      now.setDate(now.getDate() + 1);
    } else if (frequency === "weekly") {
      now.setDate(now.getDate() + 7);
    } else if (frequency === "monthly") {
      now.setMonth(now.getMonth() + 1);
    }
    return now.toISOString();
  }

  // Start Scheduler
  startScheduler(): void {
    if (this.schedulerInterval) return;

    this.schedulerInterval = setInterval(async () => {
      for (const schedule of this.backupSchedules.values()) {
        if (schedule.enabled && new Date(schedule.nextRun) <= new Date()) {
          await this.createBackup({ type: schedule.type, createdBy: "system" });
          schedule.lastRun = nowIso();
          schedule.nextRun = this.calculateNextRun(schedule.frequency);
          schedule.updatedAt = nowIso();
          this.backupSchedules.set(schedule.id, schedule);
        }
      }
    }, 60000); // Check every minute
  }

  // Stop Scheduler
  stopScheduler(): void {
    if (this.schedulerInterval) {
      clearInterval(this.schedulerInterval);
      this.schedulerInterval = null;
    }
  }

  // Get Analytics
  getAnalytics(): BackupAnalytics {
    const backups = Array.from(this.backupOperations.values());
    return {
      totalBackups: backups.length,
      successfulBackups: backups.filter((b) => b.status === "completed").length,
      failedBackups: backups.filter((b) => b.status === "failed").length,
      partialBackups: backups.filter((b) => b.status === "partial").length,
      avgBackupTime: backups.length > 0 ? backups.filter((b) => b.duration).reduce((sum, b) => sum + (b.duration || 0), 0) / backups.length : 0,
      avgBackupSize: backups.length > 0 ? backups.reduce((sum, b) => sum + b.size, 0) / backups.length : 0,
      successRate: backups.length > 0 ? (backups.filter((b) => b.status === "completed").length / backups.length) * 100 : 100,
      storageUsed: backups.reduce((sum, b) => sum + b.size, 0),
      storageCapacity: 10000000000000, // 10TB
      retentionCompliance: 100,
    };
  }

  // Getters
  listBackupOperations(): BackupOperation[] {
    return Array.from(this.backupOperations.values()).sort((a, b) =>
      new Date(b.startedAt).getTime() - new Date(a.startedAt).getTime()
    );
  }

  listRestoreOperations(): RestoreOperation[] {
    return Array.from(this.restoreOperations.values()).sort((a, b) =>
      new Date(b.startedAt).getTime() - new Date(a.startedAt).getTime()
    );
  }

  listSchedules(): BackupSchedule[] {
    return Array.from(this.backupSchedules.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock backup operations
    const mockBackups: BackupOperation[] = [
      {
        id: createId("backup-operation"),
        type: "full",
        status: "completed",
        startedAt: new Date(Date.now() - 86400000 * 7).toISOString(),
        completedAt: new Date(Date.now() - 86400000 * 7 + 300000).toISOString(),
        duration: 300000,
        size: 500000000,
        checksum: createId("checksum"),
        isCorrupt: false,
        storageLocation: "/backups/full-weekly",
        encrypted: true,
        retryCount: 0,
        maxRetries: 3,
        fallbackUsed: false,
        createdBy: "system",
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("backup-operation"),
        type: "incremental",
        status: "completed",
        startedAt: new Date(Date.now() - 86400000).toISOString(),
        completedAt: new Date(Date.now() - 86400000 + 120000).toISOString(),
        duration: 120000,
        size: 100000000,
        checksum: createId("checksum"),
        isCorrupt: false,
        storageLocation: "/backups/incremental-daily",
        encrypted: true,
        retryCount: 0,
        maxRetries: 3,
        fallbackUsed: false,
        createdBy: "system",
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockBackups.forEach((b) => this.backupOperations.set(b.id, b));

    // Mock schedules
    const mockSchedules: BackupSchedule[] = [
      {
        id: createId("backup-schedule"),
        type: "full",
        frequency: "weekly",
        nextRun: new Date(Date.now() + 86400000).toISOString(),
        enabled: true,
        retentionDays: 30,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("backup-schedule"),
        type: "incremental",
        frequency: "daily",
        nextRun: new Date(Date.now() + 3600000).toISOString(),
        enabled: true,
        retentionDays: 7,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockSchedules.forEach((s) => this.backupSchedules.set(s.id, s));
  }
}

export const backupRestoreService = new BackupRestoreService();

// ============================================
// SECURITY SERVICE
// ============================================
class SecurityService {
  private ipAllowlist: Map<string, IPAllowlistEntry> = new Map();
  private hmacSecrets: Map<string, HMACSecret> = new Map();
  private hmacSignatures: Map<string, HMACSignature> = new Map();
  private fraudRules: Map<string, FraudRule> = new Map();
  private fraudDetections: Map<string, FraudDetection> = new Map();
  private securityEvents: Map<string, SecurityEvent> = new Map();
  private auditService: AuditLogService;
  private bruteForceAttempts: Map<string, number> = new Map(); // IP -> attempt count
  private apiAbuseAttempts: Map<string, number> = new Map(); // IP -> call count

  constructor() {
    this.auditService = auditService;
  }

  // IP Allowlist Methods
  async addIPToAllowlist(input: {
    ipAddress: string;
    type: IPType;
    userId?: string;
    description?: string;
    addedBy: string;
  }): Promise<IPAllowlistEntry> {
    // Validate IP format
    if (!this.validateIPFormat(input.ipAddress, input.type)) {
      throw new Error("Invalid IP format");
    }

    const entry: IPAllowlistEntry = {
      id: createId("ip-entry"),
      ipAddress: input.ipAddress,
      type: input.type,
      status: "active",
      userId: input.userId,
      description: input.description,
      addedBy: input.addedBy,
      addedAt: nowIso(),
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.ipAllowlist.set(entry.id, entry);

    await this.auditService.create({
      entityType: "ip_allowlist",
      entityId: entry.id,
      action: "added",
      userId: input.addedBy,
      changes: {
        ipAddress: { from: null, to: input.ipAddress },
      },
    });

    return entry;
  }

  // Validate IP Format
  private validateIPFormat(ip: string, type: IPType): boolean {
    if (type === "ipv4") {
      const ipv4Regex = /^(\d{1,3}\.){3}\d{1,3}$/;
      return ipv4Regex.test(ip);
    } else {
      const ipv6Regex = /^([0-9a-fA-F]{1,4}:){7}[0-9a-fA-F]{1,4}$/;
      return ipv6Regex.test(ip);
    }
  }

  // Check IP Access
  async checkIPAccess(ipAddress: string): Promise<{ allowed: boolean; reason?: string }> {
    const entries = Array.from(this.ipAllowlist.values()).filter((e) => e.status === "active");
    const isAllowed = entries.some((e) => e.ipAddress === ipAddress);

    if (!isAllowed) {
      // Self-healing: if allowlist empty, fallback to safe mode
      if (entries.length === 0) {
        await this.logSecurityEvent("ip_block", "medium", ipAddress, "Allowlist empty - safe mode activated");
        return { allowed: false, reason: "Safe mode: allowlist empty" };
      }

      await this.logSecurityEvent("ip_block", "high", ipAddress, "IP not in allowlist");
      return { allowed: false, reason: "IP not in allowlist" };
    }

    // Update last used
    const entry = entries.find((e) => e.ipAddress === ipAddress);
    if (entry) {
      entry.lastUsed = nowIso();
      this.ipAllowlist.set(entry.id, entry);
    }

    return { allowed: true };
  }

  // Remove IP from Allowlist
  async removeIPFromAllowlist(entryId: string, userId: string): Promise<void> {
    const entry = this.ipAllowlist.get(entryId);
    if (!entry) {
      throw new Error("IP entry not found");
    }

    this.ipAllowlist.delete(entryId);

    await this.auditService.create({
      entityType: "ip_allowlist",
      entityId: entryId,
      action: "removed",
      userId,
      changes: {
        ipAddress: { from: entry.ipAddress, to: null },
      },
    });
  }

  // HMAC Methods
  async createHMACSecret(input: {
    name: string;
    algorithm: "sha256" | "sha512";
    createdBy: string;
  }): Promise<HMACSecret> {
    const secret = createId("hmac-secret"); // In production, this would be encrypted

    const hmacSecret: HMACSecret = {
      id: createId("hmac-secret-entry"),
      name: input.name,
      secret, // Encrypted in production
      algorithm: input.algorithm,
      isActive: true,
      lastRotated: nowIso(),
      nextRotation: new Date(Date.now() + 86400000 * 30).toISOString(), // 30 days
      createdBy: input.createdBy,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.hmacSecrets.set(hmacSecret.id, hmacSecret);
    return hmacSecret;
  }

  // Generate Signature
  async generateSignature(payload: string, secretId: string): Promise<HMACSignature> {
    const secret = this.hmacSecrets.get(secretId);
    if (!secret || !secret.isActive) {
      throw new Error("Secret not found or inactive");
    }

    // Simulate HMAC generation
    const signature = createId("signature");
    const timestamp = nowIso();
    const nonce = createId("nonce");

    const hmacSignature: HMACSignature = {
      id: createId("hmac-signature"),
      payload,
      signature,
      timestamp,
      nonce,
      secretId,
      verified: false,
      createdAt: nowIso(),
    };

    this.hmacSignatures.set(hmacSignature.id, hmacSignature);
    return hmacSignature;
  }

  // Verify Signature
  async verifySignature(signatureId: string, providedSignature: string): Promise<boolean> {
    const hmacSignature = this.hmacSignatures.get(signatureId);
    if (!hmacSignature) {
      throw new Error("Signature not found");
    }

    const verified = hmacSignature.signature === providedSignature;
    hmacSignature.verified = verified;
    this.hmacSignatures.set(signatureId, hmacSignature);

    if (!verified) {
      await this.logSecurityEvent("hmac_failure", "high", undefined, "Signature verification failed");
    }

    return verified;
  }

  // Rotate Secret
  async rotateSecret(secretId: string, userId: string): Promise<HMACSecret> {
    const secret = this.hmacSecrets.get(secretId);
    if (!secret) {
      throw new Error("Secret not found");
    }

    secret.secret = createId("hmac-secret"); // New encrypted secret
    secret.lastRotated = nowIso();
    secret.nextRotation = new Date(Date.now() + 86400000 * 30).toISOString();
    secret.updatedAt = nowIso();
    this.hmacSecrets.set(secretId, secret);

    await this.auditService.create({
      entityType: "hmac_secret",
      entityId: secretId,
      action: "rotated",
      userId,
      changes: {
        lastRotated: { from: "previous", to: nowIso() },
      },
    });

    return secret;
  }

  // Fraud Protection Methods
  async createFraudRule(input: {
    name: string;
    type: FraudRuleType;
    conditions: Record<string, unknown>;
    action: FraudAction;
    severity: "low" | "medium" | "high" | "critical";
    createdBy: string;
  }): Promise<FraudRule> {
    const rule: FraudRule = {
      id: createId("fraud-rule"),
      name: input.name,
      type: input.type,
      enabled: true,
      conditions: input.conditions,
      action: input.action,
      severity: input.severity,
      triggeredCount: 0,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.fraudRules.set(rule.id, rule);
    return rule;
  }

  // Check Fraud
  async checkFraud(userId?: string, transactionId?: string): Promise<FraudDetection | null> {
    const rules = Array.from(this.fraudRules.values()).filter((r) => r.enabled);

    for (const rule of rules) {
      // Simulate rule evaluation
      const triggered = Math.random() > 0.8; // 20% chance of triggering

      if (triggered) {
        rule.triggeredCount++;
        rule.lastTriggered = nowIso();
        this.fraudRules.set(rule.id, rule);

        const detection: FraudDetection = {
          id: createId("fraud-detection"),
          ruleId: rule.id,
          userId,
          transactionId,
          detectedAt: nowIso(),
          actionTaken: rule.action,
          reason: `Rule ${rule.name} triggered`,
          metadata: {},
          resolved: false,
        };

        this.fraudDetections.set(detection.id, detection);

        await this.logSecurityEvent("fraud_detected", rule.severity, undefined, `Fraud rule ${rule.name} triggered`);

        return detection;
      }
    }

    return null;
  }

  // Resolve Fraud Detection
  async resolveFraudDetection(detectionId: string, userId: string): Promise<FraudDetection> {
    const detection = this.fraudDetections.get(detectionId);
    if (!detection) {
      throw new Error("Fraud detection not found");
    }

    detection.resolved = true;
    detection.resolvedAt = nowIso();
    detection.resolvedBy = userId;
    this.fraudDetections.set(detectionId, detection);

    return detection;
  }

  // Attack Prevention
  async checkBruteForce(ip: string): Promise<boolean> {
    const attempts = this.bruteForceAttempts.get(ip) || 0;
    this.bruteForceAttempts.set(ip, attempts + 1);

    if (attempts >= 5) {
      await this.logSecurityEvent("brute_force", "critical", ip, "Brute force detected");
      return false; // Block
    }

    return true; // Allow
  }

  async checkAPIAbuse(ip: string): Promise<boolean> {
    const attempts = this.apiAbuseAttempts.get(ip) || 0;
    this.apiAbuseAttempts.set(ip, attempts + 1);

    if (attempts >= 100) {
      await this.logSecurityEvent("api_abuse", "high", ip, "API abuse detected");
      return false; // Block
    }

    return true; // Allow
  }

  // Log Security Event
  private async logSecurityEvent(
    type: "ip_block" | "hmac_failure" | "fraud_detected" | "brute_force" | "api_abuse" | "token_misuse",
    severity: "low" | "medium" | "high" | "critical",
    sourceIp?: string,
    description?: string
  ): Promise<void> {
    const event: SecurityEvent = {
      id: createId("security-event"),
      type,
      severity,
      sourceIp,
      description: description || "",
      metadata: {},
      createdAt: nowIso(),
    };

    this.securityEvents.set(event.id, event);
  }

  // Getters
  listIPAllowlist(): IPAllowlistEntry[] {
    return Array.from(this.ipAllowlist.values());
  }

  listHMACSecrets(): HMACSecret[] {
    return Array.from(this.hmacSecrets.values());
  }

  listFraudRules(): FraudRule[] {
    return Array.from(this.fraudRules.values());
  }

  listFraudDetections(): FraudDetection[] {
    return Array.from(this.fraudDetections.values());
  }

  listSecurityEvents(): SecurityEvent[] {
    return Array.from(this.securityEvents.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock IP allowlist
    const mockIPs: IPAllowlistEntry[] = [
      {
        id: createId("ip-entry"),
        ipAddress: "192.168.1.1",
        type: "ipv4",
        status: "active",
        addedBy: "admin",
        addedAt: nowIso(),
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("ip-entry"),
        ipAddress: "10.0.0.1",
        type: "ipv4",
        status: "active",
        addedBy: "admin",
        addedAt: nowIso(),
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockIPs.forEach((ip) => this.ipAllowlist.set(ip.id, ip));

    // Mock HMAC secrets
    const mockSecrets: HMACSecret[] = [
      {
        id: createId("hmac-secret-entry"),
        name: "Webhook Secret",
        secret: createId("hmac-secret"),
        algorithm: "sha256",
        isActive: true,
        lastRotated: nowIso(),
        nextRotation: new Date(Date.now() + 86400000 * 30).toISOString(),
        createdBy: "admin",
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockSecrets.forEach((s) => this.hmacSecrets.set(s.id, s));

    // Mock fraud rules
    const mockRules: FraudRule[] = [
      {
        id: createId("fraud-rule"),
        name: "Transaction Limit",
        type: "transaction_limit",
        enabled: true,
        conditions: { limit: 10000 },
        action: "block",
        severity: "high",
        triggeredCount: 0,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("fraud-rule"),
        name: "Rapid Retry",
        type: "rapid_retry",
        enabled: true,
        conditions: { maxAttempts: 5, timeWindow: 60 },
        action: "flag",
        severity: "medium",
        triggeredCount: 0,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockRules.forEach((r) => this.fraudRules.set(r.id, r));
  }
}

