// ============================================
// ALERT ORCHESTRATION SERVICE
// ============================================
class AlertOrchestrationService {
  private alertEvents: Map<string, AlertEvent> = new Map();
  private alertDeliveries: Map<string, AlertDelivery> = new Map();
  private channelConfigs: Map<string, AlertChannelConfig> = new Map();
  private auditService: AuditLogService;
  private deliveryQueue: NodeJS.Timeout | null = null;
  private eventFilter: Set<string> = new Set(); // Duplicate prevention

  constructor() {
    this.auditService = auditService;
  }

  // Create Alert Event
  async createAlertEvent(input: {
    eventType: string;
    priority: AlertDeliveryPriority;
    payload: Record<string, unknown>;
    channels: AlertChannelType[];
    scheduledFor?: string;
  }): Promise<AlertEvent> {
    // Check for duplicate
    const eventKey = `${input.eventType}-${JSON.stringify(input.payload)}`;
    if (this.eventFilter.has(eventKey)) {
      throw new Error("Duplicate event detected");
    }
    this.eventFilter.add(eventKey);

    const event: AlertEvent = {
      id: createId("alert-event"),
      eventType: input.eventType,
      priority: input.priority,
      payload: input.payload,
      channels: input.channels,
      scheduledFor: input.scheduledFor,
      createdAt: nowIso(),
    };

    this.alertEvents.set(event.id, event);

    // Create deliveries for each channel
    for (const channel of input.channels) {
      await this.createAlertDelivery(event.id, channel, input.priority);
    }

    return event;
  }

  // Create Alert Delivery
  private async createAlertDelivery(eventId: string, channel: AlertChannelType, priority: AlertDeliveryPriority): Promise<AlertDelivery> {
    const config = Array.from(this.channelConfigs.values()).find((c) => c.type === channel && c.enabled);
    if (!config) {
      throw new Error(`Channel ${channel} not configured or disabled`);
    }

    const recipient = this.getRecipientForChannel(channel, priority);

    const delivery: AlertDelivery = {
      id: createId("alert-delivery"),
      alertEventId: eventId,
      channel,
      status: "queued",
      recipient,
      attemptCount: 0,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.alertDeliveries.set(delivery.id, delivery);

    // Process delivery
    if (priority === "critical") {
      await this.processDelivery(delivery.id);
    }

    return delivery;
  }

  // Get Recipient for Channel
  private getRecipientForChannel(channel: AlertChannelType, priority: AlertDeliveryPriority): string {
    switch (channel) {
      case "email":
        return priority === "critical" ? "admin@company.com" : "team@company.com";
      case "webhook":
        return "https://hooks.example.com/alert";
      case "slack":
        return "#alerts-channel";
      default:
        return "unknown";
    }
  }

  // Process Delivery
  private async processDelivery(deliveryId: string): Promise<void> {
    const delivery = this.alertDeliveries.get(deliveryId);
    if (!delivery) return;

    delivery.status = "sent";
    delivery.lastAttemptAt = nowIso();
    delivery.attemptCount++;
    this.alertDeliveries.set(deliveryId, delivery);

    // Simulate delivery (85% success rate)
    const success = Math.random() > 0.15;
    if (success) {
      delivery.status = "delivered";
      delivery.deliveredAt = nowIso();
    } else {
      delivery.status = "failed";
      delivery.errorMessage = "Delivery failed";

      // Auto retry
      if (delivery.attemptCount < 3) {
        delivery.status = "retrying";
        delivery.nextRetryAt = new Date(Date.now() + 60000).toISOString(); // 1 minute
        this.alertDeliveries.set(deliveryId, delivery);

        setTimeout(async () => {
          await this.processDelivery(deliveryId);
        }, 60000);
      } else {
        // Channel failover
        await this.channelFailover(deliveryId);
      }
    }

    delivery.updatedAt = nowIso();
    this.alertDeliveries.set(deliveryId, delivery);
  }

  // Channel Failover
  private async channelFailover(deliveryId: string): Promise<void> {
    const delivery = this.alertDeliveries.get(deliveryId);
    if (!delivery) return;

    const failoverChannels: Record<AlertChannelType, AlertChannelType> = {
      email: "webhook",
      webhook: "slack",
      slack: "email",
    };

    const newChannel = failoverChannels[delivery.channel];
    const event = this.alertEvents.get(delivery.alertEventId);

    if (event) {
      await this.createAlertDelivery(delivery.alertEventId, newChannel, event.priority);
    }
  }

  // Create Channel Config
  async createChannelConfig(input: {
    type: AlertChannelType;
    name: string;
    config: Record<string, unknown>;
  }): Promise<AlertChannelConfig> {
    const config: AlertChannelConfig = {
      id: createId("channel-config"),
      type: input.type,
      name: input.name,
      enabled: true,
      config: input.config,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.channelConfigs.set(config.id, config);
    return config;
  }

  // Start Delivery Queue
  startDeliveryQueue(): void {
    if (this.deliveryQueue) return;

    this.deliveryQueue = setInterval(async () => {
      const queuedDeliveries = Array.from(this.alertDeliveries.values())
        .filter((d) => d.status === "queued" || (d.status === "retrying" && d.nextRetryAt && new Date(d.nextRetryAt) <= new Date()));

      for (const delivery of queuedDeliveries) {
        await this.processDelivery(delivery.id);
      }
    }, 30000); // Check every 30 seconds
  }

  // Stop Delivery Queue
  stopDeliveryQueue(): void {
    if (this.deliveryQueue) {
      clearInterval(this.deliveryQueue);
      this.deliveryQueue = null;
    }
  }

  // Get Analytics
  getAnalytics(): AlertAnalytics {
    const deliveries = Array.from(this.alertDeliveries.values());
    const channelPerformance: Record<AlertChannelType, { sent: number; failed: number; successRate: number }> = {
      email: { sent: 0, failed: 0, successRate: 100 },
      webhook: { sent: 0, failed: 0, successRate: 100 },
      slack: { sent: 0, failed: 0, successRate: 100 },
    };

    deliveries.forEach((d) => {
      if (channelPerformance[d.channel]) {
        channelPerformance[d.channel].sent++;
        if (d.status === "failed") {
          channelPerformance[d.channel].failed++;
        }
      }
    });

    Object.keys(channelPerformance).forEach((channel) => {
      const ch = channel as AlertChannelType;
      const perf = channelPerformance[ch];
      perf.successRate = perf.sent > 0 ? ((perf.sent - perf.failed) / perf.sent) * 100 : 100;
    });

    return {
      totalAlerts: this.alertEvents.size,
      sentCount: deliveries.filter((d) => d.status === "sent").length,
      failedCount: deliveries.filter((d) => d.status === "failed").length,
      retryingCount: deliveries.filter((d) => d.status === "retrying").length,
      deliveredCount: deliveries.filter((d) => d.status === "delivered").length,
      deliveryRate: deliveries.length > 0 ? (deliveries.filter((d) => d.status === "delivered").length / deliveries.length) * 100 : 100,
      avgDeliveryTime: 0, // Would calculate from sent to delivered
      channelPerformance,
    };
  }

  // Getters
  listAlertEvents(): AlertEvent[] {
    return Array.from(this.alertEvents.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  listAlertDeliveries(): AlertDelivery[] {
    return Array.from(this.alertDeliveries.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  listChannelConfigs(): AlertChannelConfig[] {
    return Array.from(this.channelConfigs.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock channel configs
    const mockConfigs: AlertChannelConfig[] = [
      {
        id: createId("channel-config"),
        type: "email",
        name: "SMTP Email",
        enabled: true,
        config: { host: "smtp.example.com", port: 587 },
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("channel-config"),
        type: "webhook",
        name: "Alert Webhook",
        enabled: true,
        config: { url: "https://hooks.example.com/alert" },
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("channel-config"),
        type: "slack",
        name: "Slack Alerts",
        enabled: true,
        config: { channel: "#alerts" },
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    mockConfigs.forEach((c) => this.channelConfigs.set(c.id, c));
  }
}

export const alertOrchestrationService = new AlertOrchestrationService();

// ============================================
// AUDIT LOG TABLE SERVICE
// ============================================
class AuditLogTableService {
  private auditEntries: Map<string, AuditLogEntry> = new Map();
  private auditChains: Map<string, AuditLogChain> = new Map();
  private archivedEntries: Map<string, AuditLogEntry> = new Map();
  private auditService: AuditLogService;
  private retentionDays: number = 90;

  constructor() {
    this.auditService = auditService;
  }

  // Create Audit Entry
  async createAuditEntry(input: {
    action: string;
    entityType: string;
    entityId: string;
    actorType: ActorType;
    actorId: string;
    actorName: string;
    origin: AuditOrigin;
    changes: Record<string, { from: unknown; to: unknown }>;
    versionBefore?: string;
    versionAfter?: string;
    ipAddress?: string;
    deviceFingerprint?: string;
    country?: string;
    region?: string;
    headers?: Record<string, string>;
    payload?: Record<string, unknown>;
  }): Promise<AuditLogEntry> {
    const eventId = createId("event");
    const traceId = createId("trace");
    const sessionId = createId("session");
    const correlationId = createId("correlation");

    // Auto calculate risk level
    const riskLevel = this.calculateRiskLevel(input.action, input.actorType, input.changes);

    // Detect anomaly
    const { isAnomalous, anomalyReason } = this.detectAnomaly(input);

    const entry: AuditLogEntry = {
      id: createId("audit-entry"),
      eventId,
      traceId,
      sessionId,
      correlationId,
      action: input.action,
      entityType: input.entityType,
      entityId: input.entityId,
      actorType: input.actorType,
      actorId: input.actorId,
      actorName: input.actorName,
      origin: input.origin,
      changes: input.changes,
      versionBefore: input.versionBefore,
      versionAfter: input.versionAfter,
      riskLevel,
      ipAddress: input.ipAddress,
      deviceFingerprint: input.deviceFingerprint,
      country: input.country,
      region: input.region,
      headers: input.headers,
      payload: input.payload,
      isAnomalous,
      anomalyReason,
      autoLocked: false,
      timestamp: nowIso(),
      timezone: "UTC",
      isArchived: false,
      createdAt: nowIso(),
    };

    this.auditEntries.set(entry.id, entry);

    // Auto lock if high risk
    if (riskLevel === "critical" || isAnomalous) {
      entry.autoLocked = true;
      this.auditEntries.set(entry.id, entry);
    }

    // Build action chain
    await this.buildActionChain(traceId, entry);

    return entry;
  }

  // Calculate Risk Level
  private calculateRiskLevel(action: string, actorType: ActorType, changes: Record<string, { from: unknown; to: unknown }>): RiskLevel {
    const criticalActions = ["delete", "destroy", "revoke", "block"];
    const highRiskActions = ["update", "modify", "change"];

    if (criticalActions.some((a) => action.toLowerCase().includes(a))) return "critical";
    if (highRiskActions.some((a) => action.toLowerCase().includes(a))) return "high";
    if (actorType === "system") return "low";
    return "medium";
  }

  // Detect Anomaly
  private detectAnomaly(input: {
    action: string;
    actorType: ActorType;
    actorId: string;
    ipAddress?: string;
    country?: string;
  }): { isAnomalous: boolean; anomalyReason?: string } {
    // Simulate anomaly detection
    const isOffHour = new Date().getHours() < 6 || new Date().getHours() > 22;
    const isUnusualCountry = input.country && input.country !== "US";

    if (isOffHour && input.action === "delete") {
      return { isAnomalous: true, anomalyReason: "Off-hour delete action" };
    }

    if (isUnusualCountry && input.actorType === "admin") {
      return { isAnomalous: true, anomalyReason: "Unusual geo location for admin" };
    }

    return { isAnomalous: false };
  }

  // Build Action Chain
  private async buildActionChain(traceId: string, entry: AuditLogEntry): Promise<void> {
    const existingChain = this.auditChains.get(traceId);

    if (existingChain) {
      existingChain.entryIds.push(entry.id);
      existingChain.actionSequence.push(entry.action);
      existingChain.endTime = entry.timestamp;
      existingChain.duration = Date.now() - new Date(existingChain.startTime).getTime();
      this.auditChains.set(traceId, existingChain);
    } else {
      const chain: AuditLogChain = {
        id: createId("audit-chain"),
        traceId,
        entryIds: [entry.id],
        actionSequence: [entry.action],
        startTime: entry.timestamp,
        endTime: entry.timestamp,
        duration: 0,
        isComplete: false,
        missingActions: [],
      };
      this.auditChains.set(traceId, chain);
    }
  }

  // Get Diff
  getDiff(entryId: string): AuditLogDiff[] {
    const entry = this.auditEntries.get(entryId);
    if (!entry) return [];

    const diffs: AuditLogDiff[] = [];
    for (const [field, change] of Object.entries(entry.changes)) {
      const changeType: "added" | "removed" | "modified" =
        change.from === null ? "added" : change.to === null ? "removed" : "modified";
      diffs.push({
        field,
        before: change.from,
        after: change.to,
        changeType,
      });
    }
    return diffs;
  }

  // Reconstruct Broken Trace
  async reconstructTrace(traceId: string): Promise<AuditLogChain> {
    const chain = this.auditChains.get(traceId);
    if (!chain) {
      throw new Error("Trace not found");
    }

    // Simulate reconstruction
    chain.isComplete = true;
    chain.missingActions = [];
    this.auditChains.set(traceId, chain);

    return chain;
  }

  // Archive Old Entries
  async archiveOldEntries(): Promise<void> {
    const cutoffDate = new Date(Date.now() - this.retentionDays * 86400000);

    for (const [id, entry] of this.auditEntries.entries()) {
      if (new Date(entry.timestamp) < cutoffDate && !entry.isArchived) {
        entry.isArchived = true;
        entry.archivedAt = nowIso();
        this.archivedEntries.set(id, entry);
        this.auditEntries.delete(id);
      }
    }
  }

  // Search Entries
  searchEntries(query: {
    actorId?: string;
    entityType?: string;
    action?: string;
    riskLevel?: RiskLevel;
    startDate?: string;
    endDate?: string;
  }): AuditLogEntry[] {
    let entries = Array.from(this.auditEntries.values());

    if (query.actorId) {
      entries = entries.filter((e) => e.actorId === query.actorId);
    }
    if (query.entityType) {
      entries = entries.filter((e) => e.entityType === query.entityType);
    }
    if (query.action) {
      entries = entries.filter((e) => e.action === query.action);
    }
    if (query.riskLevel) {
      entries = entries.filter((e) => e.riskLevel === query.riskLevel);
    }
    if (query.startDate) {
      entries = entries.filter((e) => new Date(e.timestamp) >= new Date(query.startDate));
    }
    if (query.endDate) {
      entries = entries.filter((e) => new Date(e.timestamp) <= new Date(query.endDate));
    }

    return entries.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }

  // Get Analytics
  getAnalytics(): AuditLogAnalytics {
    const entries = Array.from(this.auditEntries.values());
    const archived = Array.from(this.archivedEntries.values());

    const actorBreakdown: Record<ActorType, number> = {
      user: 0,
      admin: 0,
      system: 0,
      ai: 0,
    };

    const originBreakdown: Record<AuditOrigin, number> = {
      api: 0,
      ui: 0,
      system: 0,
      webhook: 0,
    };

    const actionFrequency: Record<string, number> = {};

    entries.forEach((e) => {
      actorBreakdown[e.actorType]++;
      originBreakdown[e.origin]++;
      actionFrequency[e.action] = (actionFrequency[e.action] || 0) + 1;
    });

    return {
      totalEntries: entries.length + archived.length,
      archivedEntries: archived.length,
      activeEntries: entries.length,
      highRiskCount: entries.filter((e) => e.riskLevel === "high" || e.riskLevel === "critical").length,
      anomalousCount: entries.filter((e) => e.isAnomalous).length,
      autoLockedCount: entries.filter((e) => e.autoLocked).length,
      actorBreakdown,
      originBreakdown,
      actionFrequency,
    };
  }

  // Getters
  listEntries(): AuditLogEntry[] {
    return Array.from(this.auditEntries.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  listChains(): AuditLogChain[] {
    return Array.from(this.auditChains.values());
  }

  listArchived(): AuditLogEntry[] {
    return Array.from(this.archivedEntries.values()).sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock audit entries
    const mockEntries: AuditLogEntry[] = [
      {
        id: createId("audit-entry"),
        eventId: createId("event"),
        traceId: createId("trace"),
        sessionId: createId("session"),
        correlationId: createId("correlation"),
        action: "create",
        entityType: "user",
        entityId: "user-123",
        actorType: "admin",
        actorId: "admin-1",
        actorName: "Admin User",
        origin: "ui",
        changes: { status: { from: null, to: "active" } },
        versionBefore: "v1",
        versionAfter: "v2",
        riskLevel: "medium",
        ipAddress: "192.168.1.1",
        deviceFingerprint: "fp-123",
        country: "US",
        region: "California",
        isAnomalous: false,
        autoLocked: false,
        timestamp: nowIso(),
        timezone: "UTC",
        isArchived: false,
        createdAt: nowIso(),
      },
      {
        id: createId("audit-entry"),
        eventId: createId("event"),
        traceId: createId("trace"),
        sessionId: createId("session"),
        correlationId: createId("correlation"),
        action: "delete",
        entityType: "subscription",
        entityId: "sub-456",
        actorType: "admin",
        actorId: "admin-1",
        actorName: "Admin User",
        origin: "api",
        changes: { status: { from: "active", to: "deleted" } },
        versionBefore: "v2",
        versionAfter: "v3",
        riskLevel: "critical",
        ipAddress: "192.168.1.1",
        deviceFingerprint: "fp-123",
        country: "US",
        region: "California",
        isAnomalous: false,
        autoLocked: true,
        timestamp: new Date(Date.now() - 3600000).toISOString(),
        timezone: "UTC",
        isArchived: false,
        createdAt: nowIso(),
      },
    ];

    mockEntries.forEach((e) => this.auditEntries.set(e.id, e));
  }
}

