// ============================================
// FRAUD & RISK SERVICE
// ============================================
class FraudRiskService {
  private fraudAlerts: Map<string, FraudAlert> = new Map();
  private fraudRules: Map<string, FraudDetectionRule> = new Map();
  private riskScores: Map<string, RiskScore> = new Map();
  private auditService: AuditLogService;
  private detectionInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditService;
    this.initializeDefaultRules();
    this.startDetection();
  }

  // Initialize Default Fraud Rules
  private initializeDefaultRules(): void {
    const defaultRules: FraudDetectionRule[] = [
      {
        id: createId("fraud-rule"),
        name: "Velocity Attack Detection",
        type: "velocity_attack",
        threshold: 10,
        action: "block",
        isActive: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("fraud-rule"),
        name: "Card Testing Detection",
        type: "card_testing",
        threshold: 5,
        action: "block",
        isActive: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("fraud-rule"),
        name: "Chargeback Pattern Detection",
        type: "chargeback_pattern",
        threshold: 3,
        action: "investigate",
        isActive: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("fraud-rule"),
        name: "Geo Mismatch Detection",
        type: "geo_mismatch",
        threshold: 1,
        action: "investigate",
        isActive: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("fraud-rule"),
        name: "Amount Anomaly Detection",
        type: "amount_anomaly",
        threshold: 5000,
        action: "investigate",
        isActive: true,
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    defaultRules.forEach((r) => this.fraudRules.set(r.id, r));
  }

  // Start Detection
  private startDetection(): void {
    this.detectionInterval = setInterval(() => {
      this.performDetection();
    }, 5000); // Every 5 seconds
  }

  // Perform Detection
  private performDetection(): void {
    // Simulate detection by checking rules
    // In real implementation, this would analyze actual transactions
  }

  // Calculate Risk Score
  calculateRiskScore(customerId: string, factors: { ip: string; deviceId?: string; country: string; amount: number }): RiskScore {
    const riskFactors: RiskFactor[] = [
      { factor: "ip_reputation", value: Math.random() * 100, weight: 0.3 },
      { factor: "device_fingerprint", value: Math.random() * 100, weight: 0.2 },
      { factor: "geo_risk", value: Math.random() * 100, weight: 0.2 },
      { factor: "amount_risk", value: factors.amount > 1000 ? 80 : 20, weight: 0.2 },
      { factor: "behavior_pattern", value: Math.random() * 100, weight: 0.1 },
    ];

    const score = riskFactors.reduce((sum, f) => sum + f.value * f.weight, 0);

    const riskScore: RiskScore = {
      customerId,
      score: Math.round(score),
      factors: riskFactors,
      lastUpdated: nowIso(),
    };

    this.riskScores.set(customerId, riskScore);
    return riskScore;
  }

  // Detect Fraud
  detectFraud(transaction: {
    customerId: string;
    customerEmail: string;
    amount: number;
    currency: string;
    country: string;
    ip: string;
    deviceId?: string;
  }): FraudAlert | null {
    const riskScore = this.calculateRiskScore(transaction.customerId, transaction);

    // Check if risk score triggers any rule
    const triggeredRule = Array.from(this.fraudRules.values()).find(
      (r) => r.isActive && riskScore.score >= r.threshold
    );

    if (!triggeredRule) {
      return null;
    }

    const priority = riskScore.score >= 70 ? "critical" : riskScore.score >= 50 ? "high" : riskScore.score >= 30 ? "medium" : "low";

    const alert: FraudAlert = {
      id: createId("fraud-alert"),
      type: triggeredRule.type,
      customerId: transaction.customerId,
      customerEmail: transaction.customerEmail,
      riskScore: riskScore.score,
      amount: transaction.amount,
      currency: transaction.currency,
      country: transaction.country,
      ip: transaction.ip,
      deviceId: transaction.deviceId,
      status: triggeredRule.action === "block" ? "blocked" : "pending",
      priority,
      action: triggeredRule.action,
      reason: `${triggeredRule.name} triggered. Risk score: ${riskScore.score}`,
      detectedAt: nowIso(),
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.fraudAlerts.set(alert.id, alert);
    return alert;
  }

  // Resolve Fraud Alert
  async resolveFraudAlert(alertId: string, action: FraudDetectionAction, userId: string): Promise<FraudAlert> {
    const alert = this.fraudAlerts.get(alertId);
    if (!alert) {
      throw new Error("Alert not found");
    }

    alert.status = action === "block" ? "blocked" : action === "allow" ? "approved" : "flagged";
    alert.action = action;
    alert.resolvedAt = nowIso();
    alert.resolvedBy = userId;
    alert.updatedAt = nowIso();
    this.fraudAlerts.set(alertId, alert);

    return alert;
  }

  // Create Fraud Rule
  async createFraudRule(input: {
    name: string;
    type: FraudType;
    threshold: number;
    action: FraudDetectionAction;
  }): Promise<FraudDetectionRule> {
    const rule: FraudDetectionRule = {
      id: createId("fraud-rule"),
      name: input.name,
      type: input.type,
      threshold: input.threshold,
      action: input.action,
      isActive: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.fraudRules.set(rule.id, rule);
    return rule;
  }

  // Toggle Fraud Rule
  async toggleFraudRule(ruleId: string, isActive: boolean, userId: string): Promise<FraudDetectionRule> {
    const rule = this.fraudRules.get(ruleId);
    if (!rule) {
      throw new Error("Rule not found");
    }

    rule.isActive = isActive;
    rule.updatedAt = nowIso();
    this.fraudRules.set(ruleId, rule);

    await this.auditService.create({
      entityType: "fraud_rule",
      entityId: ruleId,
      action: isActive ? "enabled" : "disabled",
      userId,
      changes: {
        isActive: { from: (!isActive).toString(), to: isActive.toString() },
      },
    });

    return rule;
  }

  // Get Analytics
  getAnalytics(): FraudAnalytics {
    const alerts = Array.from(this.fraudAlerts.values());

    const byType: Record<FraudType, number> = {
      velocity_attack: 0,
      card_testing: 0,
      chargeback_pattern: 0,
      multi_account_abuse: 0,
      geo_mismatch: 0,
      amount_anomaly: 0,
      bot_pattern: 0,
    };
    alerts.forEach((a) => byType[a.type]++);

    const byStatus: Record<FraudStatus, number> = {
      blocked: 0,
      pending: 0,
      approved: 0,
      flagged: 0,
    };
    alerts.forEach((a) => byStatus[a.status]++);

    const scores = Array.from(this.riskScores.values());
    const avgRiskScore = scores.length > 0
      ? scores.reduce((sum, s) => sum + s.score, 0) / scores.length
      : 0;

    return {
      totalAlerts: alerts.length,
      blockedTransactions: alerts.filter((a) => a.status === "blocked").length,
      avgRiskScore: Math.round(avgRiskScore),
      underReview: alerts.filter((a) => a.status === "pending").length,
      byType,
      byStatus,
    };
  }

  // Getters
  listFraudAlerts(): FraudAlert[] {
    return Array.from(this.fraudAlerts.values()).sort((a, b) =>
      new Date(b.detectedAt).getTime() - new Date(a.detectedAt).getTime()
    );
  }

  listFraudRules(): FraudDetectionRule[] {
    return Array.from(this.fraudRules.values());
  }

  listRiskScores(): RiskScore[] {
    return Array.from(this.riskScores.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock fraud alert
    const mockAlert: FraudAlert = {
      id: createId("fraud-alert"),
      type: "geo_mismatch",
      customerId: "customer-1",
      customerEmail: "suspicious@example.com",
      riskScore: 65,
      amount: 2500,
      currency: "USD",
      country: "US",
      ip: "192.168.1.100",
      status: "pending",
      priority: "high",
      action: "investigate",
      reason: "Geo mismatch detected. Billing country: US, IP country: RU",
      detectedAt: new Date(Date.now() - 3600000).toISOString(),
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.fraudAlerts.set(mockAlert.id, mockAlert);
  }
}

export const fraudRiskService = new FraudRiskService();

