class BlockedIPsService {
  private blockedIPs: Map<string, BlockedIP> = new Map();
  private ipAttempts: Map<string, IPAttempt[]> = new Map();
  private chargebackEvents: Map<string, ChargebackEvent> = new Map();
  private duplicatePaymentEvents: Map<string, DuplicatePaymentEvent> = new Map();
  private blockList: Map<string, BlockListEntry> = new Map();
  private whitelist: Map<string, WhitelistEntry> = new Map();
  private auditService: AuditLogService;
  private cleanupInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditService;
    this.startCleanup();
  }

  // Start Cleanup
  private startCleanup(): void {
    this.cleanupInterval = setInterval(() => {
      this.cleanupExpiredBlocks();
    }, 60000); // Every minute
  }

  // Cleanup Expired Blocks
  private cleanupExpiredBlocks(): void {
    const now = Date.now();
    this.blockedIPs.forEach((block, id) => {
      if (block.expiresAt && new Date(block.expiresAt).getTime() < now) {
        block.isActive = false;
        this.blockedIPs.set(id, block);
      }
    });
  }

  // Block IP
  async blockIP(input: {
    ipAddress: string;
    reason: BlockReason;
    duration: BlockDuration;
    blockedBy: string;
    notes?: string;
  }): Promise<BlockedIP> {
    // Check if already blocked
    const existing = Array.from(this.blockedIPs.values()).find(
      (b) => b.ipAddress === input.ipAddress && b.isActive
    );

    if (existing) {
      return existing;
    }

    const expiresAt = input.duration === "permanent"
      ? undefined
      : new Date(Date.now() + (input.duration === "temporary_24h" ? 24 : 7 * 24) * 60 * 60 * 1000).toISOString();

    const block: BlockedIP = {
      id: createId("blocked-ip"),
      ipAddress: input.ipAddress,
      reason: input.reason,
      attempts: 0,
      blockedAt: nowIso(),
      duration: input.duration,
      expiresAt,
      blockedBy: input.blockedBy,
      notes: input.notes,
      isActive: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.blockedIPs.set(block.id, block);

    // Add to block list
    this.blockList.set(block.id, {
      id: block.id,
      type: "ip",
      value: input.ipAddress,
      reason: input.reason,
      addedAt: nowIso(),
      addedBy: input.blockedBy,
      isActive: true,
    });

    return block;
  }

  // Unblock IP
  async unblockIP(blockId: string, userId: string): Promise<BlockedIP> {
    const block = this.blockedIPs.get(blockId);
    if (!block) {
      throw new Error("Block not found");
    }

    block.isActive = false;
    block.updatedAt = nowIso();
    this.blockedIPs.set(blockId, block);

    // Update block list
    const blockListEntry = this.blockList.get(blockId);
    if (blockListEntry) {
      blockListEntry.isActive = false;
      this.blockList.set(blockId, blockListEntry);
    }

    return block;
  }

  // Record IP Attempt
  recordIPAttempt(input: {
    ipAddress: string;
    type: "login" | "payment" | "api";
    success: boolean;
    userId?: string;
  }): IPAttempt {
    const attempt: IPAttempt = {
      id: createId("ip-attempt"),
      ipAddress: input.ipAddress,
      type: input.type,
      success: input.success,
      timestamp: nowIso(),
      userId: input.userId,
    };

    if (!this.ipAttempts.has(input.ipAddress)) {
      this.ipAttempts.set(input.ipAddress, []);
    }
    const attempts = this.ipAttempts.get(input.ipAddress)!;
    attempts.push(attempt);

    // Keep only last 100 attempts
    if (attempts.length > 100) {
      attempts.shift();
    }

    // Check for auto-block
    this.checkAutoBlock(input.ipAddress);

    return attempt;
  }

  // Check Auto Block
  private checkAutoBlock(ipAddress: string): void {
    const attempts = this.ipAttempts.get(ipAddress) || [];
    const failedAttempts = attempts.filter((a) => !a.success).length;

    // Auto-block if >5 failed attempts
    if (failedAttempts >= 5) {
      const existing = Array.from(this.blockedIPs.values()).find(
        (b) => b.ipAddress === ipAddress && b.isActive
      );

      if (!existing) {
        this.blockIP({
          ipAddress,
          reason: "repeated_attempts",
          duration: "temporary_24h",
          blockedBy: "system",
          notes: `Auto-blocked after ${failedAttempts} failed attempts`,
        });
      }
    }
  }

  // Detect Duplicate Payment
  detectDuplicatePayment(transaction: {
    customerId: string;
    amount: number;
    currency: string;
    transactionId: string;
  }): DuplicatePaymentEvent | null {
    // Check for recent duplicate
    const recent = Array.from(this.duplicatePaymentEvents.values()).find(
      (d) => d.customerId === transaction.customerId &&
            d.amount === transaction.amount &&
            d.currency === transaction.currency &&
            new Date(d.detectedAt).getTime() > Date.now() - 300000 // 5 minutes ago
    );

    if (recent) {
      return recent;
    }

    // In real implementation, would check against actual payment records
    return null;
  }

  // Create Chargeback Event
  async createChargebackEvent(input: {
    customerId: string;
    transactionId: string;
    amount: number;
    reason: string;
  }): Promise<ChargebackEvent> {
    const event: ChargebackEvent = {
      id: createId("chargeback-event"),
      customerId: input.customerId,
      transactionId: input.transactionId,
      amount: input.amount,
      reason: input.reason,
      status: "pending",
      flagged: false,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.chargebackEvents.set(event.id, event);

    // Check for chargeback pattern
    this.checkChargebackPattern(input.customerId);

    return event;
  }

  // Check Chargeback Pattern
  private checkChargebackPattern(customerId: string): void {
    const events = Array.from(this.chargebackEvents.values()).filter(
      (e) => e.customerId === customerId
    );

    if (events.length >= 3) {
      // Flag user for chargeback pattern
      events.forEach((e) => {
        e.flagged = true;
        this.chargebackEvents.set(e.id, e);
      });

      // Create fraud alert
      fraudRiskService.detectFraud({
        customerId,
        customerEmail: "customer@example.com",
        amount: 0,
        currency: "USD",
        country: "US",
        ip: "0.0.0.0",
      });
    }
  }

  // Add to Whitelist
  async addToWhitelist(input: {
    type: "ip" | "email" | "user";
    value: string;
    addedBy: string;
  }): Promise<WhitelistEntry> {
    const entry: WhitelistEntry = {
      id: createId("whitelist-entry"),
      type: input.type,
      value: input.value,
      addedAt: nowIso(),
      addedBy: input.addedBy,
      isActive: true,
    };

    this.whitelist.set(entry.id, entry);
    return entry;
  }

  // Check if Whitelisted
  isWhitelisted(type: "ip" | "email" | "user", value: string): boolean {
    return Array.from(this.whitelist.values()).some(
      (w) => w.type === type && w.value === value && w.isActive
    );
  }

  // Get Analytics
  getAnalytics(): IPBlockAnalytics {
    const blocks = Array.from(this.blockedIPs.values());
    const attempts = Array.from(this.ipAttempts.values()).flat();

    const byReason: Record<BlockReason, number> = {
      fraud_score: 0,
      repeated_attempts: 0,
      chargeback: 0,
      ip_mismatch: 0,
      proxy_vpn: 0,
      geo_block: 0,
    };
    blocks.forEach((b) => byReason[b.reason]++);

    return {
      totalBlocked: blocks.length,
      activeBlocks: blocks.filter((b) => b.isActive).length,
      temporaryBlocks: blocks.filter((b) => b.duration.startsWith("temporary")).length,
      permanentBlocks: blocks.filter((b) => b.duration === "permanent").length,
      totalAttempts: attempts.length,
      blockedAttempts: attempts.filter((a) => !a.success).length,
      byReason,
    };
  }

  // Getters
  listBlockedIPs(): BlockedIP[] {
    return Array.from(this.blockedIPs.values()).sort((a, b) =>
      new Date(b.blockedAt).getTime() - new Date(a.blockedAt).getTime()
    );
  }

  listIPAttempts(ipAddress?: string): IPAttempt[] {
    if (ipAddress) {
      return this.ipAttempts.get(ipAddress) || [];
    }
    return Array.from(this.ipAttempts.values()).flat().sort((a, b) =>
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  listChargebackEvents(): ChargebackEvent[] {
    return Array.from(this.chargebackEvents.values()).sort((a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  listDuplicatePaymentEvents(): DuplicatePaymentEvent[] {
    return Array.from(this.duplicatePaymentEvents.values()).sort((a, b) =>
      new Date(b.detectedAt).getTime() - new Date(a.detectedAt).getTime()
    );
  }

  listBlockList(): BlockListEntry[] {
    return Array.from(this.blockList.values());
  }

  listWhitelist(): WhitelistEntry[] {
    return Array.from(this.whitelist.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock blocked IP
    const mockBlock: BlockedIP = {
      id: createId("blocked-ip"),
      ipAddress: "192.168.1.100",
      reason: "fraud_score",
      attempts: 12,
      blockedAt: new Date(Date.now() - 86400000).toISOString(),
      duration: "temporary_7d",
      expiresAt: new Date(Date.now() + 6 * 24 * 60 * 60 * 1000).toISOString(),
      blockedBy: "system",
      notes: "High fraud score detected",
      isActive: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.blockedIPs.set(mockBlock.id, mockBlock);

    // Mock chargeback event
    const mockChargeback: ChargebackEvent = {
      id: createId("chargeback-event"),
      customerId: "customer-1",
      transactionId: "txn-12345",
      amount: 500,
      reason: "unauthorized",
      status: "pending",
      flagged: true,
      createdAt: new Date(Date.now() - 172800000).toISOString(),
      updatedAt: nowIso(),
    };

    this.chargebackEvents.set(mockChargeback.id, mockChargeback);
  }
}

