// ============================================
// REVIEW POLICY MODERATION ENGINE SERVICE
// ============================================
class ReviewModerationService {
  private submissions: Map<string, ReviewSubmission> = new Map();
  private reviewers: Map<string, Reviewer> = new Map();
  private comments: Map<string, ReviewComment> = new Map();
  private policy: ReviewPolicy;
  private auditService: AuditLogService;
  private slaCheckInterval: NodeJS.Timeout | null = null;
  private submissionSequence: number = 0;

  constructor() {
    this.auditService = auditService;
    this.policy = {
      id: createId("review-policy"),
      avgReviewSLA: 48,
      maxSoftRejectCycles: 3,
      standardRejectionNote: "Your submission has been rejected. Please review the feedback and make necessary changes before resubmitting.",
      requireLivePreview: true,
      requireDocumentation: true,
      autoApprovalEnabled: false,
      autoApprovalThreshold: 90,
      aiPreScreenEnabled: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };
    this.initializeDefaultReviewers();
    this.startSLACheck();
  }

  // Start SLA Check
  private startSLACheck(): void {
    this.slaCheckInterval = setInterval(() => {
      this.checkSLA();
    }, 3600000); // Every hour
  }

  // Check SLA
  private checkSLA(): void {
    const now = Date.now();
    const slaHours = this.policy.avgReviewSLA;
    const slaMs = slaHours * 60 * 60 * 1000;

    this.submissions.forEach((submission) => {
      if (submission.status === "pending" || submission.status === "in_review") {
        const submittedAt = new Date(submission.submittedAt).getTime();
        const elapsed = now - submittedAt;

        if (elapsed > slaMs) {
          // Auto escalate
          this.escalateSubmission(submission.id, "SLA exceeded - auto-escalated");
        }
      }
    });
  }

  // Initialize Default Reviewers
  private initializeDefaultReviewers(): void {
    const defaultReviewers: Reviewer[] = [
      {
        id: createId("reviewer"),
        name: "John Smith",
        email: "john.smith@example.com",
        expertise: ["templates", "plugins", "themes"],
        isActive: true,
        currentWorkload: 0,
        totalReviews: 150,
        avgReviewTime: 12,
        approvalRate: 85,
        rejectionAccuracy: 92,
        lastActiveAt: nowIso(),
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("reviewer"),
        name: "Sarah Johnson",
        email: "sarah.johnson@example.com",
        expertise: ["graphics", "audio", "video"],
        isActive: true,
        currentWorkload: 0,
        totalReviews: 200,
        avgReviewTime: 10,
        approvalRate: 88,
        rejectionAccuracy: 95,
        lastActiveAt: nowIso(),
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
      {
        id: createId("reviewer"),
        name: "Mike Wilson",
        email: "mike.wilson@example.com",
        expertise: ["scripts", "code", "tools"],
        isActive: true,
        currentWorkload: 0,
        totalReviews: 180,
        avgReviewTime: 14,
        approvalRate: 82,
        rejectionAccuracy: 90,
        lastActiveAt: nowIso(),
        createdAt: nowIso(),
        updatedAt: nowIso(),
      },
    ];

    defaultReviewers.forEach((r) => {
      this.reviewers.set(r.id, r);
    });
  }

  // Submit Item for Review
  async submitItem(input: {
    itemId: string;
    itemName: string;
    authorId: string;
    authorName: string;
    category: string;
    livePreviewUrl: string;
    documentationUrl: string;
    priority?: ModerationPriority;
  }): Promise<ReviewSubmission> {
    this.submissionSequence++;
    const version = 1;

    // Check for existing submission
    const existing = Array.from(this.submissions.values()).find(
      (s) => s.itemId === input.itemId && s.status !== "hard_rejected"
    );

    if (existing) {
      throw new Error("Item already has an active submission");
    }

    // AI Pre-screen
    const aiResult = await this.runAIPreScreen(input);

    // Validate live preview
    const previewValid = this.policy.requireLivePreview ? await this.validateLivePreview(input.livePreviewUrl) : true;

    // Validate documentation
    const docValid = this.policy.requireDocumentation ? await this.validateDocumentation(input.documentationUrl) : true;

    // Block if validation fails
    if (!previewValid && this.policy.requireLivePreview) {
      throw new Error("Live preview validation failed");
    }

    if (!docValid && this.policy.requireDocumentation) {
      throw new Error("Documentation validation failed");
    }

    const submittedAt = nowIso();
    const slaDue = new Date(Date.now() + this.policy.avgReviewSLA * 60 * 60 * 1000).toISOString();

    const submission: ReviewSubmission = {
      id: createId("review-submission"),
      itemId: input.itemId,
      itemName: input.itemName,
      authorId: input.authorId,
      authorName: input.authorName,
      category: input.category,
      version,
      status: "pending",
      priority: input.priority || "normal",
      submittedAt,
      slaDue,
      softRejectCount: 0,
      livePreviewUrl: input.livePreviewUrl,
      documentationUrl: input.documentationUrl,
      previewValid,
      documentationValid: docValid,
      aiPreScreenPassed: aiResult.passed,
      aiPreScreenIssues: aiResult.issues,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.submissions.set(submission.id, submission);

    // Auto assign reviewer
    await this.autoAssignReviewer(submission.id);

    return submission;
  }

  // AI Pre-screen
  private async runAIPreScreen(input: {
    itemId: string;
    itemName: string;
    livePreviewUrl: string;
    documentationUrl: string;
  }): Promise<{ passed: boolean; issues: string[] }> {
    if (!this.policy.aiPreScreenEnabled) {
      return { passed: true, issues: [] };
    }

    const issues: string[] = [];

    // Simulated AI checks
    // In real implementation, this would:
    // - Scan for malware
    // - Detect duplicate code
    // - Detect fake demo
    // - Check for plagiarism

    // For now, we simulate
    const hasMalware = false;
    const hasDuplicate = false;
    const hasFakeDemo = false;

    if (hasMalware) {
      issues.push("Potential malware detected");
    }

    if (hasDuplicate) {
      issues.push("Duplicate code detected");
    }

    if (hasFakeDemo) {
      issues.push("Fake demo detected");
    }

    return {
      passed: issues.length === 0,
      issues,
    };
  }

  // Validate Live Preview
  private async validateLivePreview(url: string): Promise<boolean> {
    // In real implementation, this would:
    // - Check if link is working
    // - Check if page loads
    // - Check for errors
    // For now, we simulate
    return true;
  }

  // Validate Documentation
  private async validateDocumentation(url: string): Promise<boolean> {
    // In real implementation, this would:
    // - Check if PDF/URL is present
    // - Check if accessible
    // For now, we simulate
    return true;
  }

  // Auto Assign Reviewer
  private async autoAssignReviewer(submissionId: string): Promise<void> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    // Find reviewer with matching expertise and lowest workload
    const eligibleReviewers = Array.from(this.reviewers.values()).filter(
      (r) => r.isActive && r.expertise.includes(submission.category)
    );

    if (eligibleReviewers.length === 0) {
      // Fallback to any active reviewer
      const anyReviewer = Array.from(this.reviewers.values()).find((r) => r.isActive);
      if (anyReviewer) {
        eligibleReviewers.push(anyReviewer);
      }
    }

    if (eligibleReviewers.length === 0) {
      throw new Error("No active reviewers available");
    }

    // Sort by workload
    eligibleReviewers.sort((a, b) => a.currentWorkload - b.currentWorkload);

    const assignedReviewer = eligibleReviewers[0];

    submission.assignedTo = assignedReviewer.id;
    submission.assignedAt = nowIso();
    submission.status = "in_review";
    submission.updatedAt = nowIso();
    this.submissions.set(submissionId, submission);

    // Update reviewer workload
    assignedReviewer.currentWorkload++;
    assignedReviewer.lastActiveAt = nowIso();
    this.reviewers.set(assignedReviewer.id, assignedReviewer);
  }

  // Approve Submission
  async approveSubmission(submissionId: string, reviewerId: string, qualityScore: number, comments?: string): Promise<ReviewSubmission> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    if (submission.status !== "in_review") {
      throw new Error("Submission must be in review");
    }

    // Check quality score
    if (qualityScore < 50) {
      throw new Error("Quality score too low for approval");
    }

    submission.status = "approved";
    submission.decisionAt = nowIso();
    submission.decidedBy = reviewerId;
    submission.qualityScore = qualityScore;
    submission.reviewComments = comments;
    submission.updatedAt = nowIso();
    this.submissions.set(submissionId, submission);

    // Update reviewer stats
    const reviewer = this.reviewers.get(reviewerId);
    if (reviewer) {
      reviewer.totalReviews++;
      reviewer.currentWorkload--;
      reviewer.approvalRate = ((reviewer.approvalRate * (reviewer.totalReviews - 1)) + 100) / reviewer.totalReviews;
      this.reviewers.set(reviewerId, reviewer);
    }

    // Add comment
    if (comments) {
      await this.addComment({
        submissionId,
        reviewerId,
        reviewerName: reviewer?.name || "Unknown",
        comment: comments,
        isInternal: false,
      });
    }

    await this.auditService.create({
      entityType: "review_submission",
      entityId: submissionId,
      action: "approved",
      userId: reviewerId,
      changes: {
        status: { from: submission.status, to: "approved" },
        qualityScore: { from: 0, to: qualityScore },
      },
    });

    return submission;
  }

  // Soft Reject Submission
  async softRejectSubmission(submissionId: string, reviewerId: string, reason: RejectReason, comments: string): Promise<ReviewSubmission> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    if (submission.status !== "in_review") {
      throw new Error("Submission must be in review");
    }

    // Check soft reject count
    if (submission.softRejectCount >= this.policy.maxSoftRejectCycles) {
      // Auto hard reject
      return this.hardRejectSubmission(submissionId, reviewerId, "quality", "Max soft reject cycles exceeded");
    }

    submission.status = "soft_rejected";
    submission.decisionAt = nowIso();
    submission.decidedBy = reviewerId;
    submission.rejectReason = reason;
    submission.reviewComments = comments;
    submission.softRejectCount++;
    submission.lastSoftRejectAt = nowIso();
    submission.version++;
    submission.updatedAt = nowIso();
    this.submissions.set(submissionId, submission);

    // Update reviewer stats
    const reviewer = this.reviewers.get(reviewerId);
    if (reviewer) {
      reviewer.totalReviews++;
      reviewer.currentWorkload--;
      this.reviewers.set(reviewerId, reviewer);
    }

    // Add comment
    await this.addComment({
      submissionId,
      reviewerId,
      reviewerName: reviewer?.name || "Unknown",
      comment: comments,
      isInternal: false,
    });

    await this.auditService.create({
      entityType: "review_submission",
      entityId: submissionId,
      action: "soft_rejected",
      userId: reviewerId,
      changes: {
        status: { from: "in_review", to: "soft_rejected" },
        rejectReason: { from: "", to: reason },
      },
    });

    return submission;
  }

  // Hard Reject Submission
  async hardRejectSubmission(submissionId: string, reviewerId: string, reason: RejectReason, comments: string): Promise<ReviewSubmission> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    submission.status = "hard_rejected";
    submission.decisionAt = nowIso();
    submission.decidedBy = reviewerId;
    submission.rejectReason = reason;
    submission.reviewComments = comments;
    submission.updatedAt = nowIso();
    this.submissions.set(submissionId, submission);

    // Update reviewer stats
    const reviewer = this.reviewers.get(reviewerId);
    if (reviewer) {
      reviewer.totalReviews++;
      reviewer.currentWorkload--;
      reviewer.rejectionAccuracy = ((reviewer.rejectionAccuracy * (reviewer.totalReviews - 1)) + 100) / reviewer.totalReviews;
      this.reviewers.set(reviewerId, reviewer);
    }

    // Add comment
    await this.addComment({
      submissionId,
      reviewerId,
      reviewerName: reviewer?.name || "Unknown",
      comment: comments,
      isInternal: false,
    });

    await this.auditService.create({
      entityType: "review_submission",
      entityId: submissionId,
      action: "hard_rejected",
      userId: reviewerId,
      changes: {
        status: { from: submission.status, to: "hard_rejected" },
        rejectReason: { from: "", to: reason },
      },
    });

    return submission;
  }

  // Resubmit after Soft Reject
  async resubmitItem(submissionId: string, livePreviewUrl?: string, documentationUrl?: string): Promise<ReviewSubmission> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    if (submission.status !== "soft_rejected") {
      throw new Error("Can only resubmit soft rejected items");
    }

    // Update URLs if provided
    if (livePreviewUrl) {
      submission.livePreviewUrl = livePreviewUrl;
      submission.previewValid = await this.validateLivePreview(livePreviewUrl);
    }

    if (documentationUrl) {
      submission.documentationUrl = documentationUrl;
      submission.documentationValid = await this.validateDocumentation(documentationUrl);
    }

    // Re-run AI pre-screen
    const aiResult = await this.runAIPreScreen({
      itemId: submission.itemId,
      itemName: submission.itemName,
      livePreviewUrl: submission.livePreviewUrl,
      documentationUrl: submission.documentationUrl,
    });

    submission.aiPreScreenPassed = aiResult.passed;
    submission.aiPreScreenIssues = aiResult.issues;

    // Reset status
    submission.status = "pending";
    submission.submittedAt = nowIso();
    submission.slaDue = new Date(Date.now() + this.policy.avgReviewSLA * 60 * 60 * 1000).toISOString();
    submission.version++;
    submission.updatedAt = nowIso();
    this.submissions.set(submissionId, submission);

    // Auto assign reviewer
    await this.autoAssignReviewer(submissionId);

    return submission;
  }

  // Escalate Submission
  private async escalateSubmission(submissionId: string, reason: string): Promise<ReviewSubmission> {
    const submission = this.submissions.get(submissionId);
    if (!submission) {
      throw new Error("Submission not found");
    }

    // Reassign to different reviewer
    const currentReviewerId = submission.assignedTo;
    if (currentReviewerId) {
      const currentReviewer = this.reviewers.get(currentReviewerId);
      if (currentReviewer) {
        currentReviewer.currentWorkload--;
        this.reviewers.set(currentReviewerId, currentReviewer);
      }
    }

    // Assign to next available reviewer
    await this.autoAssignReviewer(submissionId);

    // Add internal comment
    await this.addComment({
      submissionId,
      reviewerId: "system",
      reviewerName: "System",
      comment: `Escalated: ${reason}`,
      isInternal: true,
    });

    return submission;
  }

  // Add Comment
  async addComment(input: {
    submissionId: string;
    reviewerId: string;
    reviewerName: string;
    comment: string;
    isInternal: boolean;
  }): Promise<ReviewComment> {
    const comment: ReviewComment = {
      id: createId("review-comment"),
      submissionId: input.submissionId,
      reviewerId: input.reviewerId,
      reviewerName: input.reviewerName,
      comment: input.comment,
      isInternal: input.isInternal,
      createdAt: nowIso(),
    };

    this.comments.set(comment.id, comment);
    return comment;
  }

  // Update Policy
  async updatePolicy(input: {
    avgReviewSLA?: number;
    maxSoftRejectCycles?: number;
    standardRejectionNote?: string;
    requireLivePreview?: boolean;
    requireDocumentation?: boolean;
    autoApprovalEnabled?: boolean;
    autoApprovalThreshold?: number;
    aiPreScreenEnabled?: boolean;
  }): Promise<ReviewPolicy> {
    if (input.avgReviewSLA !== undefined) this.policy.avgReviewSLA = input.avgReviewSLA;
    if (input.maxSoftRejectCycles !== undefined) this.policy.maxSoftRejectCycles = input.maxSoftRejectCycles;
    if (input.standardRejectionNote !== undefined) this.policy.standardRejectionNote = input.standardRejectionNote;
    if (input.requireLivePreview !== undefined) this.policy.requireLivePreview = input.requireLivePreview;
    if (input.requireDocumentation !== undefined) this.policy.requireDocumentation = input.requireDocumentation;
    if (input.autoApprovalEnabled !== undefined) this.policy.autoApprovalEnabled = input.autoApprovalEnabled;
    if (input.autoApprovalThreshold !== undefined) this.policy.autoApprovalThreshold = input.autoApprovalThreshold;
    if (input.aiPreScreenEnabled !== undefined) this.policy.aiPreScreenEnabled = input.aiPreScreenEnabled;

    this.policy.updatedAt = nowIso();
    return this.policy;
  }

  // Get Analytics
  getAnalytics(): ReviewAnalytics {
    const submissions = Array.from(this.submissions.values());
    const reviewers = Array.from(this.reviewers.values());

    const totalSubmissions = submissions.length;
    const pendingSubmissions = submissions.filter((s) => s.status === "pending").length;
    const inReviewSubmissions = submissions.filter((s) => s.status === "in_review").length;
    const approvedSubmissions = submissions.filter((s) => s.status === "approved").length;
    const softRejectedSubmissions = submissions.filter((s) => s.status === "soft_rejected").length;
    const hardRejectedSubmissions = submissions.filter((s) => s.status === "hard_rejected").length;

    const completedSubmissions = submissions.filter((s) => s.status === "approved" || s.status === "hard_rejected");
    const avgReviewTime = completedSubmissions.length > 0
      ? completedSubmissions.reduce((sum, s) => {
          if (s.decisionAt && s.assignedAt) {
            return sum + (new Date(s.decisionAt).getTime() - new Date(s.assignedAt).getTime()) / (1000 * 60 * 60);
          }
          return sum;
        }, 0) / completedSubmissions.length
      : 0;

    const slaCompliant = completedSubmissions.filter((s) => {
      if (s.decisionAt && s.submittedAt) {
        const elapsed = new Date(s.decisionAt).getTime() - new Date(s.submittedAt).getTime();
        const slaMs = this.policy.avgReviewSLA * 60 * 60 * 1000;
        return elapsed <= slaMs;
      }
      return false;
    }).length;

    const avgSLACompliance = completedSubmissions.length > 0 ? (slaCompliant / completedSubmissions.length) * 100 : 100;

    const activeReviewers = reviewers.filter((r) => r.isActive).length;
    const avgReviewerWorkload = activeReviewers > 0
      ? reviewers.reduce((sum, r) => sum + r.currentWorkload, 0) / activeReviewers
      : 0;

    const qualityScores = submissions.filter((s) => s.qualityScore !== undefined).map((s) => s.qualityScore!);
    const qualityScoreAvg = qualityScores.length > 0
      ? qualityScores.reduce((sum, s) => sum + s, 0) / qualityScores.length
      : 0;

    return {
      totalSubmissions,
      pendingSubmissions,
      inReviewSubmissions,
      approvedSubmissions,
      softRejectedSubmissions,
      hardRejectedSubmissions,
      avgReviewTime: Math.round(avgReviewTime * 10) / 10,
      avgSLACompliance: Math.round(avgSLACompliance),
      activeReviewers,
      avgReviewerWorkload: Math.round(avgReviewerWorkload * 10) / 10,
      qualityScoreAvg: Math.round(qualityScoreAvg),
    };
  }

  // Getters
  listSubmissions(): ReviewSubmission[] {
    return Array.from(this.submissions.values()).sort((a, b) => new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime());
  }

  listReviewers(): Reviewer[] {
    return Array.from(this.reviewers.values()).sort((a, b) => a.name.localeCompare(b.name));
  }

  listComments(submissionId?: string): ReviewComment[] {
    if (submissionId) {
      return Array.from(this.comments.values())
        .filter((c) => c.submissionId === submissionId)
        .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
    }
    return Array.from(this.comments.values()).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
  }

  getPolicy(): ReviewPolicy {
    return this.policy;
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock submission
    const mockSubmission: ReviewSubmission = {
      id: createId("review-submission"),
      itemId: "item-1",
      itemName: "Premium Template",
      authorId: "author-1",
      authorName: "John Doe",
      category: "templates",
      version: 1,
      status: "in_review",
      priority: "normal",
      submittedAt: new Date(Date.now() - 86400000).toISOString(),
      assignedTo: Array.from(this.reviewers.keys())[0],
      assignedAt: new Date(Date.now() - 43200000).toISOString(),
      slaDue: new Date(Date.now() + 47 * 60 * 60 * 1000).toISOString(),
      softRejectCount: 0,
      livePreviewUrl: "https://example.com/preview",
      documentationUrl: "https://example.com/docs",
      previewValid: true,
      documentationValid: true,
      aiPreScreenPassed: true,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.submissions.set(mockSubmission.id, mockSubmission);
  }
}

export const reviewModerationService = new ReviewModerationService();

