class CriticalSecurityReportService {
  private incidents: Map<string, CriticalSecurityIncident> = new Map();
  private alerts: Map<string, CriticalSecurityAlert> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Create Critical Security Incident
  async createIncident(input: {
    itemId: string;
    itemName: string;
    vulnerabilityType: "sql_injection" | "xss" | "auth_bypass" | "api_leak" | "other";
    affectedEndpoint?: string;
    description: string;
    requestPayload?: string;
    endpointLogs?: string;
    reproductionSteps?: string;
    reporterId: string;
  }): Promise<CriticalSecurityIncident> {
    const incidentId = createId("security-incident");

    // IMMEDIATE ACTION: Auto disable item
    await this.autoDisableItem(input.itemId);

    // Create incident
    const incident: CriticalSecurityIncident = {
      id: incidentId,
      itemId: input.itemId,
      itemName: input.itemName,
      severity: "critical",
      vulnerabilityType: input.vulnerabilityType,
      affectedEndpoint: input.affectedEndpoint,
      description: input.description,
      status: "disabled",
      actionTaken: "auto_disable",
      actionTakenAt: nowIso(),
      actionTakenBy: "system",
      evidence: {
        requestPayload: input.requestPayload,
        endpointLogs: input.endpointLogs,
        reproductionSteps: input.reproductionSteps,
        isImmutable: true,
      },
      userImpact: {
        affectedUsers: 0,
        transactionsBlocked: 0,
      },
      globalScanTriggered: false,
      slaResponse: nowIso(), // Immediate
      slaFix: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(), // 24h max
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.incidents.set(incidentId, incident);

    // Auto escalate to security team
    await this.sendSecurityAlert(incidentId);

    // Trigger global scan if pattern detected
    if (await this.isPatternDetected(input.vulnerabilityType)) {
      await this.triggerGlobalScan(input.vulnerabilityType);
      incident.globalScanTriggered = true;
      this.incidents.set(incidentId, incident);
    }

    await this.auditService.create({
      entityType: "security_incident",
      entityId: incidentId,
      action: "created",
      userId: input.reporterId,
      changes: {},
    });

    return incident;
  }

  // Auto Disable Item
  private async autoDisableItem(itemId: string): Promise<void> {
    // In real implementation, disable item in listing system
    // Block public access, freeze sales
  }

  // Send Security Alert
  private async sendSecurityAlert(incidentId: string): Promise<void> {
    const incident = this.incidents.get(incidentId);
    if (!incident) return;

    const alert: CriticalSecurityAlert = {
      id: createId("security-alert"),
      incidentId,
      severity: "critical",
      sentTo: ["security-team@company.com", "admin@company.com"],
      sentAt: nowIso(),
      message: `CRITICAL SECURITY INCIDENT: ${incident.vulnerabilityType} detected in ${incident.itemName}. Item has been auto-disabled.`,
      acknowledged: false,
    };

    this.alerts.set(alert.id, alert);
  }

  // Check if Pattern Detected
  private async isPatternDetected(vulnerabilityType: string): Promise<boolean> {
    // Check if similar vulnerabilities detected recently
    const recentIncidents = Array.from(this.incidents.values()).filter(
      (i) => i.vulnerabilityType === vulnerabilityType && new Date(i.createdAt).getTime() > Date.now() - 7 * 24 * 60 * 60 * 1000
    );
    return recentIncidents.length >= 3;
  }

  // Trigger Global Scan
  private async triggerGlobalScan(vulnerabilityType: string): Promise<void> {
    // In real implementation, scan all items for similar vulnerabilities
  }

  // Request Security Patch
  async requestPatch(input: {
    incidentId: string;
    vulnerabilityDetails: string;
    deadline?: string;
  }): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(input.incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    const deadline = input.deadline || new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();

    incident.patchRequest = {
      sentAt: nowIso(),
      deadline,
      vulnerabilityDetails: input.vulnerabilityDetails,
    };

    incident.status = "patch_requested";
    incident.actionTaken = "request_patch";
    incident.actionTakenAt = nowIso();
    incident.updatedAt = nowIso();

    this.incidents.set(input.incidentId, incident);

    await this.auditService.create({
      entityType: "security_incident",
      entityId: incidentId,
      action: "patch_requested",
      userId: "system",
      changes: {},
    });

    return incident;
  }

  // Acknowledge Patch
  async acknowledgePatch(incidentId: string): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(incidentId);
    if (!incident || !incident.patchRequest) {
      throw new Error("Incident or patch request not found");
    }

    incident.patchRequest.acknowledgedAt = nowIso();
    incident.updatedAt = nowIso();

    this.incidents.set(incidentId, incident);
    return incident;
  }

  // Retest After Patch
  async retestIncident(incidentId: string): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    // Run automated security test
    const passed = await this.runSecurityTest(incidentId);

    incident.retestResult = {
      testedAt: nowIso(),
      passed,
      details: passed ? "All security tests passed" : "Security test failed: vulnerability still present",
    };

    if (passed) {
      incident.status = "patched";
      incident.actionTaken = "restore";
      incident.actionTakenAt = nowIso();
      incident.updatedAt = nowIso();

      // Restore item
      await this.restoreItem(incident.itemId);
    } else {
      incident.status = "retest_failed";
      incident.updatedAt = nowIso();
    }

    this.incidents.set(incidentId, incident);

    await this.auditService.create({
      entityType: "security_incident",
      entityId: incidentId,
      action: "retest_completed",
      userId: "system",
      changes: { passed },
    });

    return incident;
  }

  // Run Security Test
  private async runSecurityTest(incidentId: string): Promise<boolean> {
    const incident = this.incidents.get(incidentId);
    if (!incident) return false;

    // Simulate security test based on vulnerability type
    // In real implementation, run actual security scanning
    return Math.random() > 0.3; // 70% pass rate
  }

  // Restore Item
  private async restoreItem(itemId: string): Promise<void> {
    // In real implementation, restore item in listing system
  }

  // Force Takedown (if no fix in SLA)
  async forceTakedown(incidentId: string): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    incident.status = "permanently_removed";
    incident.actionTaken = "force_takedown";
    incident.actionTakenAt = nowIso();
    incident.updatedAt = nowIso();

    // Apply developer penalty
    incident.developerPenalty = {
      trustScoreReduction: 50,
      rankingReduction: 30,
      possibleSuspension: true,
    };

    this.incidents.set(incidentId, incident);

    await this.auditService.create({
      entityType: "security_incident",
      entityId: incidentId,
      action: "force_takedown",
      userId: "system",
      changes: {},
    });

    return incident;
  }

  // Notify Affected Users
  async notifyAffectedUsers(incidentId: string): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    // In real implementation, notify users who purchased the item
    incident.userImpact.affectedUsers = 100; // Simulated
    incident.userImpact.notifiedAt = nowIso();
    incident.updatedAt = nowIso();

    this.incidents.set(incidentId, incident);
    return incident;
  }

  // Block Transactions
  async blockTransactions(incidentId: string): Promise<CriticalSecurityIncident> {
    const incident = this.incidents.get(incidentId);
    if (!incident) {
      throw new Error("Incident not found");
    }

    // In real implementation, block transactions for the item
    incident.userImpact.transactionsBlocked = 50; // Simulated
    incident.updatedAt = nowIso();

    this.incidents.set(incidentId, incident);
    return incident;
  }

  // Acknowledge Alert
  async acknowledgeAlert(alertId: string, userId: string): Promise<CriticalSecurityAlert> {
    const alert = this.alerts.get(alertId);
    if (!alert) {
      throw new Error("Alert not found");
    }

    alert.acknowledged = true;
    alert.acknowledgedBy = userId;
    alert.acknowledgedAt = nowIso();

    this.alerts.set(alertId, alert);
    return alert;
  }

  // Check SLA Exceeded
  async checkSLAExceeded(): Promise<void> {
    const now = new Date();

    for (const [incidentId, incident] of this.incidents.entries()) {
      if (incident.status === "patch_requested" || incident.status === "disabled") {
        const fixDeadline = new Date(incident.slaFix);
        if (now > fixDeadline) {
          // Auto force takedown
          await this.forceTakedown(incidentId);
        }
      }
    }
  }

  // Get Analytics
  getAnalytics(): CriticalSecurityAnalytics {
    const incidents = Array.from(this.incidents.values());

    const byVulnerabilityType: Record<string, number> = {
      sql_injection: 0,
      xss: 0,
      auth_bypass: 0,
      api_leak: 0,
      other: 0,
    };

    let totalResponseTime = 0;
    let totalFixTime = 0;
    let resolvedCount = 0;

    for (const incident of incidents) {
      byVulnerabilityType[incident.vulnerabilityType]++;

      const created = new Date(incident.createdAt).getTime();
      const actionTaken = new Date(incident.actionTakenAt).getTime();
      totalResponseTime += (actionTaken - created) / 1000; // seconds

      if (incident.status === "patched" || incident.status === "permanently_removed") {
        const updated = new Date(incident.updatedAt).getTime();
        totalFixTime += (updated - created) / (1000 * 60 * 60); // hours
        resolvedCount++;
      }
    }

    const avgResponseTime = incidents.length > 0 ? totalResponseTime / incidents.length : 0;
    const avgFixTime = resolvedCount > 0 ? totalFixTime / resolvedCount : 0;

    return {
      totalIncidents: incidents.length,
      activeIncidents: incidents.filter((i) => i.status !== "patched" && i.status !== "permanently_removed").length,
      resolvedIncidents: resolvedCount,
      avgResponseTime: Math.round(avgResponseTime * 10) / 10,
      avgFixTime: Math.round(avgFixTime * 10) / 10,
      byVulnerabilityType,
      developerPenalties: incidents.filter((i) => i.developerPenalty).length,
      globalScansTriggered: incidents.filter((i) => i.globalScanTriggered).length,
    };
  }

  // Getters
  listIncidents(): CriticalSecurityIncident[] {
    return Array.from(this.incidents.values()).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  listAlerts(): CriticalSecurityAlert[] {
    return Array.from(this.alerts.values()).sort((a, b) => new Date(b.sentAt).getTime() - new Date(a.sentAt).getTime());
  }

  // Initialize mock data
  initializeMockData(): void {
    // No mock data for critical security incidents
  }
}

export const criticalSecurityReportService = new CriticalSecurityReportService();

// ============================================
// TOP SELLING ITEMS RANKING ENGINE SERVICE
// ============================================
class TopSellingItemsService {
  private rankingCache: Map<string, TopSellingItem[]> = new Map();
  private cacheTimestamp: Map<string, number> = new Map();
  private authorPerformance: Map<string, AuthorPerformance> = new Map();
  private categoryRankings: Map<string, CategoryRanking> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Get Top Selling Items
  async getTopSellingItems(input: {
    timeFilter: TimeFilter;
    limit?: number;
    categoryId?: string;
    excludeFlagged?: boolean;
  }): Promise<TopSellingItem[]> {
    const cacheKey = `${input.timeFilter}-${input.limit || 5}-${input.categoryId || 'all'}-${input.excludeFlagged || false}`;
    const cached = this.rankingCache.get(cacheKey);
    const cachedTime = this.cacheTimestamp.get(cacheKey) || 0;

    // Return cached if less than 5 minutes old
    if (cached && Date.now() - cachedTime < 5 * 60 * 1000) {
      return cached;
    }

    // Calculate date range
    const { startDate, endDate } = this.getDateRange(input.timeFilter);

    // Simulate fetching from orders, items, authors tables
    const items = await this.fetchItemSales(startDate, endDate, input.categoryId);

    // Calculate revenue
    const itemsWithRevenue = items.map((item) => ({
      ...item,
      revenue: this.calculateRevenue(item),
    }));

    // Filter flagged items if requested
    const filteredItems = input.excludeFlagged
      ? itemsWithRevenue.filter((item) => !item.isFlagged)
      : itemsWithRevenue;

    // Filter low quality items (high refund rate)
    const qualityFiltered = filteredItems.filter((item) => item.refundRate < 0.3); // 30% threshold

    // Sort by ranking criteria
    const sorted = this.sortByRanking(qualityFiltered);

    // Assign ranks
    const ranked = sorted.map((item, index) => ({
      ...item,
      rank: index + 1,
    }));

    // Detect trends
    const withTrends = ranked.map((item) => ({
      ...item,
      trendStatus: this.detectTrend(item),
    }));

    // Cache result
    this.rankingCache.set(cacheKey, withTrends.slice(0, input.limit || 5));
    this.cacheTimestamp.set(cacheKey, Date.now());

    return withTrends.slice(0, input.limit || 5);
  }

  // Get Date Range
  private getDateRange(filter: TimeFilter): { startDate: Date; endDate: Date } {
    const now = new Date();
    const endDate = new Date(now.setHours(23, 59, 59, 999));

    let startDate: Date;
    switch (filter) {
      case "today":
        startDate = new Date(now.setHours(0, 0, 0, 0));
        break;
      case "this_week":
        startDate = new Date(now);
        startDate.setDate(startDate.getDate() - startDate.getDay());
        startDate.setHours(0, 0, 0, 0);
        break;
      case "this_month":
        startDate = new Date(now.getFullYear(), now.getMonth(), 1);
        break;
      case "custom_range":
        // Default to this month for now
        startDate = new Date(now.getFullYear(), now.getMonth(), 1);
        break;
      default:
        startDate = new Date(now.getFullYear(), now.getMonth(), 1);
    }

    return { startDate, endDate };
  }

  // Fetch Item Sales (simulated)
  private async fetchItemSales(startDate: Date, endDate: Date, categoryId?: string): Promise<TopSellingItem[]> {
    // In real implementation, query orders, items, authors tables
    // For now, return mock data
    return [
      {
        rank: 0,
        itemId: "item-1",
        itemName: "Premium WordPress Plugin",
        authorId: "author-1",
        authorName: "John Author",
        categoryId: "cat-1",
        categoryName: "WordPress",
        salesCount: 150,
        revenue: 0,
        rating: 4.8,
        latestSaleAt: nowIso(),
        trendStatus: "stable",
        refundRate: 0.05,
        conversionRate: 0.12,
        isFlagged: false,
      },
      {
        rank: 0,
        itemId: "item-2",
        itemName: "React Dashboard Template",
        authorId: "author-2",
        authorName: "Jane Developer",
        categoryId: "cat-2",
        categoryName: "React",
        salesCount: 120,
        revenue: 0,
        rating: 4.9,
        latestSaleAt: nowIso(),
        trendStatus: "trending",
        refundRate: 0.03,
        conversionRate: 0.15,
        isFlagged: false,
      },
      {
        rank: 0,
        itemId: "item-3",
        itemName: "E-commerce Theme",
        authorId: "author-3",
        authorName: "Bob Designer",
        categoryId: "cat-3",
        categoryName: "Themes",
        salesCount: 95,
        revenue: 0,
        rating: 4.7,
        latestSaleAt: nowIso(),
        trendStatus: "fast_growing",
        refundRate: 0.08,
        conversionRate: 0.10,
        isFlagged: false,
      },
    ];
  }

  // Calculate Revenue
  private calculateRevenue(item: TopSellingItem): number {
    // revenue = (item_price × quantity) - refunds - discounts
    // In real implementation, calculate from order data
    const avgPrice = 29; // Simulated
    const refunds = item.salesCount * item.refundRate * avgPrice;
    const discounts = item.salesCount * 0.1 * avgPrice; // 10% discount rate
    return (item.salesCount * avgPrice) - refunds - discounts;
  }

  // Sort by Ranking Criteria
  private sortByRanking(items: TopSellingItem[]): TopSellingItem[] {
    return items.sort((a, b) => {
      // Primary: sales_count DESC
      if (b.salesCount !== a.salesCount) {
        return b.salesCount - a.salesCount;
      }

      // Tie breaker 1: revenue DESC
      if (b.revenue !== a.revenue) {
        return b.revenue - a.revenue;
      }

      // Tie breaker 2: rating DESC
      if (b.rating !== a.rating) {
        return b.rating - a.rating;
      }

      // Tie breaker 3: latest sale activity
      return new Date(b.latestSaleAt).getTime() - new Date(a.latestSaleAt).getTime();
    });
  }

  // Detect Trend
  private detectTrend(item: TopSellingItem): TrendStatus {
    // In real implementation, analyze sales growth over time
    if (item.salesCount > 100 && item.conversionRate > 0.15) {
      return "trending";
    }
    if (item.salesCount > 50 && item.conversionRate > 0.12) {
      return "fast_growing";
    }
    if (item.refundRate > 0.15) {
      return "declining";
    }
    return "stable";
  }

  // Get Item Drill Down
  async getItemDrillDown(itemId: string): Promise<ItemDrillDown> {
    // In real implementation, fetch detailed data
    return {
      itemId,
      itemName: "Premium WordPress Plugin",
      salesTrend: [
        { date: "2024-01-01", sales: 10, revenue: 290 },
        { date: "2024-01-02", sales: 15, revenue: 435 },
        { date: "2024-01-03", sales: 20, revenue: 580 },
      ],
      buyersList: [
        { buyerId: "buyer-1", buyerName: "Alice", purchaseDate: nowIso(), amount: 29 },
        { buyerId: "buyer-2", buyerName: "Bob", purchaseDate: nowIso(), amount: 29 },
      ],
      refundRate: 0.05,
      conversionRate: 0.12,
      totalRefunds: 7,
      totalSales: 150,
      avgOrderValue: 29,
    };
  }

  // Get Author Performance
  async getAuthorPerformance(authorId: string): Promise<AuthorPerformance> {
    const cached = this.authorPerformance.get(authorId);
    if (cached) {
      return cached;
    }

    // In real implementation, calculate from data
    const performance: AuthorPerformance = {
      authorId,
      authorName: "John Author",
      totalEarnings: 4350,
      totalItems: 5,
      totalSales: 150,
      performanceScore: 85,
      avgRating: 4.8,
      topSellingItemId: "item-1",
      topSellingItemName: "Premium WordPress Plugin",
    };

    this.authorPerformance.set(authorId, performance);
    return performance;
  }

  // Get Category Ranking
  async getCategoryRanking(categoryId: string): Promise<CategoryRanking> {
    const cached = this.categoryRankings.get(categoryId);
    if (cached) {
      return cached;
    }

    const items = await this.getTopSellingItems({
      timeFilter: "this_month",
      limit: 10,
      categoryId,
    });

    const categoryItems = items.filter((item) => item.categoryId === categoryId);

    const ranking: CategoryRanking = {
      categoryId,
      categoryName: categoryItems[0]?.categoryName || "Unknown",
      topItems: categoryItems,
      totalSales: categoryItems.reduce((sum, item) => sum + item.salesCount, 0),
      totalRevenue: categoryItems.reduce((sum, item) => sum + item.revenue, 0),
    };

    this.categoryRankings.set(categoryId, ranking);
    return ranking;
  }

  // Real-time Sync on New Order
  async onNewOrder(orderData: {
    itemId: string;
    quantity: number;
    price: number;
  }): Promise<void> {
    // Invalidate cache
    this.invalidateCache();

    await this.auditService.create({
      entityType: "ranking",
      entityId: orderData.itemId,
      action: "order_sync",
      userId: "system",
      changes: { quantity: orderData.quantity, price: orderData.price },
    });
  }

  // Real-time Sync on Refund
  async onRefund(refundData: {
    itemId: string;
    amount: number;
  }): Promise<void> {
    // Invalidate cache
    this.invalidateCache();

    await this.auditService.create({
      entityType: "ranking",
      entityId: refundData.itemId,
      action: "refund_sync",
      userId: "system",
      changes: { amount: refundData.amount },
    });
  }

  // Invalidate Cache
  private invalidateCache(): void {
    this.rankingCache.clear();
    this.cacheTimestamp.clear();
  }

  // Audit Validation
  async validateAudit(): Promise<{ valid: boolean; mismatches: string[] }> {
    const mismatches: string[] = [];

    // Cross-check sales vs revenue
    const items = await this.getTopSellingItems({ timeFilter: "this_month", limit: 100 });
    for (const item of items) {
      const expectedRevenue = item.salesCount * 29; // Simulated avg price
      if (Math.abs(item.revenue - expectedRevenue) > expectedRevenue * 0.1) {
        mismatches.push(`Item ${item.itemId}: revenue mismatch`);
      }
    }

    return {
      valid: mismatches.length === 0,
      mismatches,
    };
  }

  // Self-Healing
  async selfHeal(): Promise<void> {
    const validation = await this.validateAudit();
    if (!validation.valid) {
      // Recalculate ranking
      this.invalidateCache();
      await this.auditService.create({
        entityType: "ranking",
        entityId: "system",
        action: "self_heal",
        userId: "system",
        changes: { mismatches: validation.mismatches },
      });
    }
  }

  // Get Analytics
  getAnalytics(): RankingAnalytics {
    const items = Array.from(this.rankingCache.values()).flat();

    const totalSales = items.reduce((sum, item) => sum + item.salesCount, 0);
    const totalRevenue = items.reduce((sum, item) => sum + item.revenue, 0);
    const avgRefundRate = items.length > 0
      ? items.reduce((sum, item) => sum + item.refundRate, 0) / items.length
      : 0;
    const avgConversionRate = items.length > 0
      ? items.reduce((sum, item) => sum + item.conversionRate, 0) / items.length
      : 0;
    const trendingItems = items.filter((item) => item.trendStatus === "trending").length;
    const fastGrowingItems = items.filter((item) => item.trendStatus === "fast_growing").length;
    const flaggedItems = items.filter((item) => item.isFlagged).length;

    // Find top category
    const categoryCounts = new Map<string, number>();
    items.forEach((item) => {
      categoryCounts.set(item.categoryName, (categoryCounts.get(item.categoryName) || 0) + item.salesCount);
    });
    let topCategory = "None";
    let maxSales = 0;
    categoryCounts.forEach((sales, category) => {
      if (sales > maxSales) {
        maxSales = sales;
        topCategory = category;
      }
    });

    return {
      totalSales,
      totalRevenue,
      avgRefundRate: Math.round(avgRefundRate * 1000) / 1000,
      avgConversionRate: Math.round(avgConversionRate * 1000) / 1000,
      trendingItems,
      fastGrowingItems,
      flaggedItems,
      topCategory,
    };
  }

  // Initialize mock data
  initializeMockData(): void {
    // Mock data is generated on demand
  }
}

export const topSellingItemsService = new TopSellingItemsService();

// ============================================
// REPORTS & FLAGS MODERATION ENGINE SERVICE
// ============================================
class ReportsFlagsModerationService {
  private reports: Map<string, ModerationReport> = new Map();
  private reporterTrust: Map<string, ReporterTrust> = new Map();
  private authorWarnings: Map<string, AuthorWarning> = new Map();
  private autoFlags: Map<string, AutoFlag> = new Map();
  private itemHistory: Map<string, ItemReportHistory> = new Map();
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
  }

  // Create Report
  async createReport(input: {
    itemId: string;
    itemName: string;
    authorId: string;
    authorName: string;
    reportType: ModerationReportType;
    reason: string;
    reporterId: string;
    reporterName: string;
    description: string;
    evidence?: {
      screenshots?: string[];
      logs?: string[];
      files?: string[];
    };
  }): Promise<ModerationReport> {
    // Check for duplicate reports
    const duplicate = await this.checkDuplicate(input.itemId, input.reporterId, input.reportType);
    if (duplicate) {
      throw new Error("Duplicate report detected");
    }

    // Auto assign severity
    const severity = this.autoAssignSeverity(input.reportType);

    // Get reporter trust score
    const trust = this.getReporterTrust(input.reporterId);

    const report: ModerationReport = {
      id: createId("moderation-report"),
      itemId: input.itemId,
      itemName: input.itemName,
      authorId: input.authorId,
      authorName: input.authorName,
      severity,
      status: "open",
      reportType: input.reportType,
      reason: input.reason,
      reporterId: input.reporterId,
      reporterName: input.reporterName,
      description: input.description,
      evidence: input.evidence,
      isDuplicate: false,
      reporterTrustScore: trust.trustScore,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.reports.set(report.id, report);

    // Update item history
    await this.updateItemHistory(input.itemId, report);

    // Update reporter trust
    await this.updateReporterTrust(input.reporterId, true);

    await this.auditService.create({
      entityType: "moderation_report",
      entityId: report.id,
      action: "created",
      userId: input.reporterId,
      changes: {},
    });

    // Auto escalate if HIGH severity
    if (severity === "HIGH") {
      await this.escalateReport(report.id, "system");
    }

    return report;
  }

  // Auto Assign Severity
  private autoAssignSeverity(reportType: ModerationReportType): ModerationSeverity {
    const highSeverityTypes: ModerationReportType[] = ["copyright", "illegal", "malware"];
    const mediumSeverityTypes: ModerationReportType[] = ["misleading", "policy_violation", "suspicious_activity"];

    if (highSeverityTypes.includes(reportType)) {
      return "HIGH";
    }
    if (mediumSeverityTypes.includes(reportType)) {
      return "MEDIUM";
    }
    return "LOW";
  }

  // Check Duplicate
  private async checkDuplicate(itemId: string, reporterId: string, reportType: ModerationReportType): Promise<boolean> {
    const existing = Array.from(this.reports.values()).find(
      (r) => r.itemId === itemId && r.reporterId === reporterId && r.reportType === reportType && r.status === "open"
    );
    return !!existing;
  }

  // Get Reporter Trust
  private getReporterTrust(reporterId: string): ReporterTrust {
    const trust = this.reporterTrust.get(reporterId);
    if (trust) {
      return trust;
    }

    // Create new trust record
    const newTrust: ReporterTrust = {
      reporterId,
      reporterName: "Unknown",
      validReports: 0,
      falseReports: 0,
      trustScore: 50, // Start at 50
      isBlocked: false,
      lastReportAt: nowIso(),
    };

    this.reporterTrust.set(reporterId, newTrust);
    return newTrust;
  }

  // Update Reporter Trust
  private async updateReporterTrust(reporterId: string, isValid: boolean): Promise<void> {
    const trust = this.reporterTrust.get(reporterId);
    if (!trust) return;

    if (isValid) {
      trust.validReports++;
      trust.trustScore = Math.min(100, trust.trustScore + 5);
    } else {
      trust.falseReports++;
      trust.trustScore = Math.max(0, trust.trustScore - 10);
    }

    trust.lastReportAt = nowIso();

    // Block if trust score too low
    if (trust.trustScore < 20) {
      trust.isBlocked = true;
    }

    this.reporterTrust.set(reporterId, trust);
  }

  // Take Action
  async takeAction(input: {
    reportId: string;
    action: ModerationAction;
    userId: string;
    internalNotes?: string;
  }): Promise<ModerationReport> {
    const report = this.reports.get(input.reportId);
    if (!report) {
      throw new Error("Report not found");
    }

    report.actionTaken = input.action;
    report.actionTakenAt = nowIso();
    report.actionTakenBy = input.userId;
    report.status = "action_taken";
    report.updatedAt = nowIso();

    if (input.internalNotes) {
      report.internalNotes = input.internalNotes;
    }

    // Handle specific actions
    if (input.action === "take_down") {
      await this.executeTakedown(report);
    } else if (input.action === "warn_author") {
      await this.warnAuthor(report.authorId, report.authorName, input.userId);
    } else if (input.action === "dismiss") {
      report.status = "dismissed";
      report.dismissedAt = nowIso();
      report.dismissedBy = input.userId;
      report.dismissedReason = input.internalNotes || "No reason provided";
      // Update reporter trust (false report)
      await this.updateReporterTrust(report.reporterId, false);
    } else if (input.action === "escalate") {
      await this.escalateReport(report.id, input.userId);
    }

    this.reports.set(input.reportId, report);

    await this.auditService.create({
      entityType: "moderation_report",
      entityId: report.id,
      action: "action_taken",
      userId: input.userId,
      changes: { action: input.action },
    });

    return report;
  }

  // Execute Takedown
  private async executeTakedown(report: ModerationReport): Promise<void> {
    // In real implementation, call DMCA system
    // Item removed, access disabled, log created
    await this.auditService.create({
      entityType: "item_takedown",
      entityId: report.itemId,
      action: "taken_down",
      userId: report.actionTakenBy || "system",
      changes: { reason: report.reason },
    });
  }

  // Warn Author
  private async warnAuthor(authorId: string, authorName: string, userId: string): Promise<void> {
    const warning = this.authorWarnings.get(authorId);
    if (warning) {
      warning.warningCount++;
      warning.lastWarningAt = nowIso();

      // Check for suspension (3 warnings)
      if (warning.warningCount >= 3) {
        warning.isSuspended = true;
        warning.suspendedAt = nowIso();
        warning.suspensionReason = "3 warnings received";
      }

      this.authorWarnings.set(authorId, warning);
    } else {
      const newWarning: AuthorWarning = {
        id: createId("author-warning"),
        authorId,
        authorName,
        warningCount: 1,
        lastWarningAt: nowIso(),
        isSuspended: false,
      };
      this.authorWarnings.set(authorId, newWarning);
    }

    // In real implementation, send notification to author
  }

  // Escalate Report
  private async escalateReport(reportId: string, userId: string): Promise<void> {
    const report = this.reports.get(reportId);
    if (!report) return;

    report.status = "escalated";
    report.updatedAt = nowIso();
    this.reports.set(reportId, report);

    // In real implementation, send alert to senior moderators
  }

  // Update Item History
  private async updateItemHistory(itemId: string, report: ModerationReport): Promise<void> {
    const history = this.itemHistory.get(itemId);
    if (history) {
      history.totalReports++;
      history.reports.push(report);
      this.itemHistory.set(itemId, history);
    } else {
      const newHistory: ItemReportHistory = {
        itemId,
        itemName: report.itemName,
        totalReports: 1,
        reports: [report],
        pastViolations: 0,
        actionsTaken: 0,
        warningsIssued: 0,
        takedowns: 0,
      };
      this.itemHistory.set(itemId, newHistory);
    }
  }

  // Generate Auto Flag
  async generateAutoFlag(input: {
    itemId: string;
    itemName: string;
    flagType: "high_refund_rate" | "abnormal_sales" | "suspicious_activity";
    reason: string;
  }): Promise<AutoFlag> {
    const severity = this.autoAssignFlagSeverity(input.flagType);

    const flag: AutoFlag = {
      id: createId("auto-flag"),
      itemId: input.itemId,
      itemName: input.itemName,
      flagType: input.flagType,
      severity,
      reason: input.reason,
      autoGenerated: true,
      createdAt: nowIso(),
      reviewed: false,
    };

    this.autoFlags.set(flag.id, flag);

    await this.auditService.create({
      entityType: "auto_flag",
      entityId: flag.id,
      action: "generated",
      userId: "system",
      changes: {},
    });

    return flag;
  }

  // Auto Assign Flag Severity
  private autoAssignFlagSeverity(flagType: string): ModerationSeverity {
    if (flagType === "suspicious_activity") {
      return "HIGH";
    }
    if (flagType === "abnormal_sales") {
      return "MEDIUM";
    }
    return "LOW";
  }

  // Review Auto Flag
  async reviewAutoFlag(flagId: string, userId: string): Promise<AutoFlag> {
    const flag = this.autoFlags.get(flagId);
    if (!flag) {
      throw new Error("Auto flag not found");
    }

    flag.reviewed = true;
    flag.reviewedAt = nowIso();
    flag.reviewedBy = userId;

    this.autoFlags.set(flagId, flag);

    return flag;
  }

  // Get Item Report History
  getItemHistory(itemId: string): ItemReportHistory {
    return this.itemHistory.get(itemId) || {
      itemId,
      itemName: "Unknown",
      totalReports: 0,
      reports: [],
      pastViolations: 0,
      actionsTaken: 0,
      warningsIssued: 0,
      takedowns: 0,
    };
  }

  // Check SLA Exceeded
  async checkSLAExceeded(): Promise<void> {
    const now = new Date();
    const slaHours = 24; // 24h SLA for reports

    for (const [reportId, report] of this.reports.entries()) {
      if (report.status === "open" || report.status === "under_review") {
        const created = new Date(report.createdAt);
        const elapsed = (now.getTime() - created.getTime()) / (1000 * 60 * 60);

        if (elapsed > slaHours) {
          // Auto escalate
          await this.escalateReport(reportId, "system");
        }
      }
    }
  }

  // Self-Healing
  async selfHeal(): Promise<void> {
    // If item deleted, close report
    // If duplicate resolved, auto merge
    // If no action, auto escalate
    await this.checkSLAExceeded();
  }

  // Get Analytics
  getAnalytics(): ModerationAnalytics {
    const reports = Array.from(this.reports.values());

    const bySeverity: Record<ModerationSeverity, number> = {
      LOW: 0,
      MEDIUM: 0,
      HIGH: 0,
    };

    const byStatus: Record<ModerationReportStatus, number> = {
      open: 0,
      under_review: 0,
      action_taken: 0,
      dismissed: 0,
      escalated: 0,
    };

    const byType: Record<ModerationReportType, number> = {
      copyright: 0,
      illegal: 0,
      malware: 0,
      misleading: 0,
      policy_violation: 0,
      minor_issue: 0,
      suspicious_activity: 0,
    };

    let totalResolutionTime = 0;
    let resolvedCount = 0;

    for (const report of reports) {
      bySeverity[report.severity]++;
      byStatus[report.status]++;
      byType[report.reportType]++;

      if (report.status === "action_taken" || report.status === "dismissed") {
        const created = new Date(report.createdAt).getTime();
        const updated = new Date(report.updatedAt).getTime();
        totalResolutionTime += (updated - created) / (1000 * 60 * 60); // hours
        resolvedCount++;
      }
    }

    const avgResolutionTime = resolvedCount > 0 ? totalResolutionTime / resolvedCount : 0;

    return {
      totalReports: reports.length,
      bySeverity,
      byStatus,
      byType,
      avgResolutionTime: Math.round(avgResolutionTime * 10) / 10,
      autoFlags: this.autoFlags.size,
      reporterTrustScores: this.reporterTrust.size,
      authorWarnings: this.authorWarnings.size,
      authorSuspensions: Array.from(this.authorWarnings.values()).filter((w) => w.isSuspended).length,
      duplicateReports: reports.filter((r) => r.isDuplicate).length,
      falseReports: reports.filter((r) => r.status === "dismissed").length,
    };
  }

  // Getters
  listReports(): ModerationReport[] {
    return Array.from(this.reports.values()).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  listAutoFlags(): AutoFlag[] {
    return Array.from(this.autoFlags.values()).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  listReporterTrust(): ReporterTrust[] {
    return Array.from(this.reporterTrust.values()).sort((a, b) => b.trustScore - a.trustScore);
  }

  listAuthorWarnings(): AuthorWarning[] {
    return Array.from(this.authorWarnings.values()).sort((a, b) => b.warningCount - a.warningCount);
  }

  // Initialize mock data
  initializeMockData(): void {
    const mockReport: ModerationReport = {
      id: createId("moderation-report"),
      itemId: "item-1",
      itemName: "Premium WordPress Plugin",
      authorId: "author-1",
      authorName: "John Author",
      severity: "MEDIUM",
      status: "open",
      reportType: "policy_violation",
      reason: "Misleading description",
      reporterId: "reporter-1",
      reporterName: "Alice Reporter",
      description: "Item description does not match actual functionality",
      isDuplicate: false,
      reporterTrustScore: 75,
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.reports.set(mockReport.id, mockReport);
  }
}

