// ============================================
// REFUNDS MANAGEMENT ENGINE SERVICE
// ============================================
class RefundsManagementService {
  private refunds: Map<string, RefundManagementRequest> = new Map();
  private disputes: Map<string, DisputeCase> = new Map();
  private refundRules: Map<string, RefundRule> = new Map();
  private reconciliation: Map<string, FinancialReconciliation> = new Map();
  private authorBalances: Map<string, number> = new Map();
  private refundWindowDays: number = 7;
  private auditService: AuditLogService;

  constructor() {
    this.auditService = auditService;
    this.initializeDefaultRules();
  }

  // Initialize Default Rules
  private initializeDefaultRules(): void {
    const rules: RefundRule[] = [
      {
        id: "rule-1",
        name: "Auto-approve low amount within window",
        condition: "amount < 50 && days <= 7",
        action: "auto_approve",
        amountThreshold: 50,
        daysThreshold: 7,
        isActive: true,
      },
      {
        id: "rule-2",
        name: "Auto-deny abuse detected",
        condition: "abuse_detected",
        action: "auto_deny",
        isActive: true,
      },
      {
        id: "rule-3",
        name: "Manual review high value",
        condition: "amount >= 100",
        action: "manual_review",
        amountThreshold: 100,
        isActive: true,
      },
    ];

    rules.forEach((rule) => this.refundRules.set(rule.id, rule));
  }

  // Create Refund Request
  async createRefundRequest(input: {
    orderId: string;
    itemId: string;
    itemName: string;
    buyerId: string;
    buyerName: string;
    authorId: string;
    authorName: string;
    refundType: RefundManagementType;
    requestedAmount: number;
    reason: string;
    attachments?: string[];
  }): Promise<RefundManagementRequest> {
    // Check refund window
    const withinWindow = await this.checkRefundWindow(input.orderId);
    if (!withinWindow) {
      throw new Error("Refund window expired");
    }

    // Check for duplicate refund attempt
    const duplicate = await this.checkDuplicateRefund(input.orderId);
    if (duplicate) {
      throw new Error("Duplicate refund attempt blocked");
    }

    // Apply refund rules
    const ruleResult = await this.applyRefundRules(input);

    const refund: RefundManagementRequest = {
      id: createId("refund-request"),
      orderId: input.orderId,
      itemId: input.itemId,
      itemName: input.itemName,
      buyerId: input.buyerId,
      buyerName: input.buyerName,
      authorId: input.authorId,
      authorName: input.authorName,
      refundType: input.refundType,
      requestedAmount: input.requestedAmount,
      reason: input.reason,
      status: ruleResult.action === "auto_approve" ? "approved" : ruleResult.action === "auto_deny" ? "denied" : "pending",
      requestedAt: nowIso(),
      isDispute: false,
      fraudFlagged: false,
      autoApproved: ruleResult.action === "auto_approve",
      autoDenied: ruleResult.action === "auto_deny",
      attachments: input.attachments,
    };

    this.refunds.set(refund.id, refund);

    // If auto-approved, process refund
    if (refund.status === "approved") {
      refund.approvedAt = nowIso();
      refund.approvedBy = "system";
      await this.processRefund(refund.id);
    }

    await this.auditService.create({
      entityType: "refund_request",
      entityId: refund.id,
      action: "created",
      userId: input.buyerId,
      changes: { amount: input.requestedAmount, reason: input.reason },
    });

    return refund;
  }

  // Check Refund Window
  private async checkRefundWindow(orderId: string): Promise<boolean> {
    // In real implementation, check order date
    // For now, assume within window
    return true;
  }

  // Check Duplicate Refund
  private async checkDuplicateRefund(orderId: string): Promise<boolean> {
    const existing = Array.from(this.refunds.values()).find(
      (r) => r.orderId === orderId && r.status !== "denied" && r.status !== "refunded"
    );
    return !!existing;
  }

  // Apply Refund Rules
  private async applyRefundRules(input: { requestedAmount: number }): Promise<{ action: "auto_approve" | "auto_deny" | "manual_review" }> {
    for (const rule of this.refundRules.values()) {
      if (!rule.isActive) continue;

      if (rule.action === "auto_approve" && rule.amountThreshold && input.requestedAmount < rule.amountThreshold) {
        return { action: "auto_approve" };
      }

      if (rule.action === "manual_review" && rule.amountThreshold && input.requestedAmount >= rule.amountThreshold) {
        return { action: "manual_review" };
      }
    }

    return { action: "manual_review" };
  }

  // Take Action
  async takeAction(input: {
    refundId: string;
    action: RefundManagementAction;
    userId: string;
    reason?: string;
    partialAmount?: number;
  }): Promise<RefundManagementRequest> {
    const refund = this.refunds.get(input.refundId);
    if (!refund) {
      throw new Error("Refund request not found");
    }

    if (input.action === "approve") {
      refund.status = "approved";
      refund.approvedAt = nowIso();
      refund.approvedBy = input.userId;

      // Handle partial refund
      if (input.partialAmount && input.partialAmount < refund.requestedAmount) {
        refund.refundedAmount = input.partialAmount;
        refund.remainingAmount = refund.requestedAmount - input.partialAmount;
      } else {
        refund.refundedAmount = refund.requestedAmount;
      }

      await this.processRefund(refund.id);
    } else if (input.action === "deny") {
      refund.status = "denied";
      refund.deniedAt = nowIso();
      refund.deniedBy = input.userId;
      refund.deniedReason = input.reason || "No reason provided";
    } else if (input.action === "escalate") {
      refund.status = "escalated";
      refund.escalatedAt = nowIso();
      refund.escalatedBy = input.userId;
    }

    refund.updatedAt = nowIso();
    this.refunds.set(input.refundId, refund);

    await this.auditService.create({
      entityType: "refund_request",
      entityId: refund.id,
      action: "action_taken",
      userId: input.userId,
      changes: { action: input.action },
    });

    return refund;
  }

  // Process Refund
  private async processRefund(refundId: string): Promise<void> {
    const refund = this.refunds.get(refundId);
    if (!refund) return;

    // In real implementation, call payment gateway API
    // Simulate gateway call
    const gatewayTransactionId = `gw-${createId()}`;

    // Verify transaction
    const verified = await this.verifyTransaction(refund.orderId);
    if (!verified) {
      refund.status = "denied";
      refund.deniedReason = "Transaction verification failed";
      this.refunds.set(refundId, refund);
      return;
    }

    // Initiate refund
    const success = await this.initiateGatewayRefund(refund.refundedAmount || refund.requestedAmount);
    if (!success) {
      // Retry logic
      const retrySuccess = await this.retryGatewayRefund(refundId);
      if (!retrySuccess) {
        refund.status = "denied";
        refund.deniedReason = "Payment gateway failure";
        this.refunds.set(refundId, refund);
        return;
      }
    }

    // Update status
    refund.status = "refunded";
    refund.refundedAt = nowIso();
    refund.refundTransactionId = gatewayTransactionId;

    // Deduct from author earnings
    await this.deductFromAuthorEarnings(refund.authorId, refund.refundedAmount || refund.requestedAmount);

    // Revoke item access
    await this.revokeItemAccess(refund.buyerId, refund.itemId);

    // Add to reconciliation
    await this.addToReconciliation(refund.id, refund.refundedAmount || refund.requestedAmount, gatewayTransactionId);

    this.refunds.set(refundId, refund);

    await this.auditService.create({
      entityType: "refund_request",
      entityId: refund.id,
      action: "refunded",
      userId: "system",
      changes: { transactionId: gatewayTransactionId },
    });
  }

  // Verify Transaction
  private async verifyTransaction(orderId: string): Promise<boolean> {
    // In real implementation, verify with payment gateway
    return true;
  }

  // Initiate Gateway Refund
  private async initiateGatewayRefund(amount: number): Promise<boolean> {
    // In real implementation, call payment gateway API
    // Simulate success
    return true;
  }

  // Retry Gateway Refund
  private async retryGatewayRefund(refundId: string): Promise<boolean> {
    // In real implementation, retry logic with exponential backoff
    return true;
  }

  // Deduct from Author Earnings
  private async deductFromAuthorEarnings(authorId: string, amount: number): Promise<void> {
    const currentBalance = this.authorBalances.get(authorId) || 0;
    const newBalance = currentBalance - amount;
    this.authorBalances.set(authorId, newBalance);

    // If negative balance, hold future payouts
    if (newBalance < 0) {
      await this.auditService.create({
        entityType: "author_balance",
        entityId: authorId,
        action: "hold_payouts",
        userId: "system",
        changes: { balance: newBalance },
      });
    }
  }

  // Revoke Item Access
  private async revokeItemAccess(buyerId: string, itemId: string): Promise<void> {
    // In real implementation, disable download, revoke license
    await this.auditService.create({
      entityType: "item_access",
      entityId: itemId,
      action: "revoked",
      userId: "system",
      changes: { buyerId },
    });
  }

  // Add to Reconciliation
  private async addToReconciliation(refundId: string, amount: number, transactionId: string): Promise<void> {
    const recon: FinancialReconciliation = {
      refundId,
      refundAmount: amount,
      gatewayTransactionId: transactionId,
      gatewayStatus: "success",
      reconciled: true,
      reconciledAt: nowIso(),
    };

    this.reconciliation.set(refundId, recon);
  }

  // Create Dispute
  async createDispute(input: {
    refundId: string;
    buyerMessage: string;
    authorResponse: string;
    attachments?: string[];
  }): Promise<DisputeCase> {
    const refund = this.refunds.get(input.refundId);
    if (!refund) {
      throw new Error("Refund request not found");
    }

    refund.isDispute = true;
    refund.disputeMessage = input.buyerMessage;
    refund.authorResponse = input.authorResponse;
    refund.status = "escalated";
    this.refunds.set(input.refundId, refund);

    const dispute: DisputeCase = {
      id: createId("dispute"),
      refundId: input.refundId,
      buyerMessage: input.buyerMessage,
      authorResponse: input.authorResponse,
      attachments: input.attachments || [],
      createdAt: nowIso(),
      updatedAt: nowIso(),
    };

    this.disputes.set(dispute.id, dispute);

    await this.auditService.create({
      entityType: "dispute",
      entityId: dispute.id,
      action: "created",
      userId: "system",
      changes: {},
    });

    return dispute;
  }

  // Resolve Dispute
  async resolveDispute(input: {
    disputeId: string;
    decision: "buyer" | "author" | "partial";
    reason: string;
    userId: string;
  }): Promise<DisputeCase> {
    const dispute = this.disputes.get(input.disputeId);
    if (!dispute) {
      throw new Error("Dispute not found");
    }

    dispute.adminDecision = input.decision;
    dispute.decisionReason = input.reason;
    dispute.decidedAt = nowIso();
    dispute.decidedBy = input.userId;
    dispute.updatedAt = nowIso();

    this.disputes.set(input.disputeId, dispute);

    // Apply decision
    const refund = this.refunds.get(dispute.refundId);
    if (refund) {
      if (input.decision === "buyer") {
        refund.status = "approved";
        await this.processRefund(refund.id);
      } else if (input.decision === "author") {
        refund.status = "denied";
        refund.deniedReason = input.reason;
      }
      this.refunds.set(dispute.refundId, refund);
    }

    await this.auditService.create({
      entityType: "dispute",
      entityId: dispute.id,
      action: "resolved",
      userId: input.userId,
      changes: { decision: input.decision },
    });

    return dispute;
  }

  // Fraud Detection
  async detectFraud(buyerId: string): Promise<boolean> {
    const refunds = Array.from(this.refunds.values()).filter((r) => r.buyerId === buyerId);
    const last30Days = refunds.filter((r) => {
      const created = new Date(r.requestedAt);
      const now = new Date();
      const daysDiff = (now.getTime() - created.getTime()) / (1000 * 60 * 60 * 24);
      return daysDiff <= 30;
    });

    // Flag if more than 3 refunds in 30 days
    if (last30Days.length > 3) {
      return true;
    }

    return false;
  }

  // Get Metrics
  getMetrics(): RefundMetrics {
    const refunds = Array.from(this.refunds.values());

    const pending = refunds.filter((r) => r.status === "pending").length;
    const escalated = refunds.filter((r) => r.status === "escalated").length;

    const now = new Date();
    const approved30d = refunds.filter((r) => {
      if (r.status !== "approved" && r.status !== "refunded") return false;
      const approved = new Date(r.approvedAt || r.requestedAt);
      const daysDiff = (now.getTime() - approved.getTime()) / (1000 * 60 * 60 * 24);
      return daysDiff <= 30;
    }).length;

    const refundVolume = refunds
      .filter((r) => r.status === "refunded")
      .reduce((sum, r) => sum + (r.refundedAmount || r.requestedAmount), 0);

    const totalRefunds = refunds.filter((r) => r.status === "refunded").length;
    const avgRefundAmount = totalRefunds > 0 ? refundVolume / totalRefunds : 0;

    const fraudFlags = refunds.filter((r) => r.fraudFlagged).length;
    const disputes = refunds.filter((r) => r.isDispute).length;

    return {
      pending,
      escalated,
      approved30d,
      refundVolume,
      totalRefunds,
      avgRefundAmount: Math.round(avgRefundAmount * 100) / 100,
      fraudFlags,
      disputes,
    };
  }

  // Filter Refunds
  filterRefunds(input: {
    status?: RefundManagementStatus;
    authorId?: string;
    dateFrom?: string;
    dateTo?: string;
    minAmount?: number;
    maxAmount?: number;
  }): RefundManagementRequest[] {
    let refunds = Array.from(this.refunds.values());

    if (input.status) {
      refunds = refunds.filter((r) => r.status === input.status);
    }

    if (input.authorId) {
      refunds = refunds.filter((r) => r.authorId === input.authorId);
    }

    if (input.dateFrom) {
      refunds = refunds.filter((r) => new Date(r.requestedAt) >= new Date(input.dateFrom!));
    }

    if (input.dateTo) {
      refunds = refunds.filter((r) => new Date(r.requestedAt) <= new Date(input.dateTo!));
    }

    if (input.minAmount) {
      refunds = refunds.filter((r) => r.requestedAmount >= input.minAmount!);
    }

    if (input.maxAmount) {
      refunds = refunds.filter((r) => r.requestedAmount <= input.maxAmount!);
    }

    return refunds.sort((a, b) => new Date(b.requestedAt).getTime() - new Date(a.requestedAt).getTime());
  }

  // Self-Healing
  async selfHeal(): Promise<void> {
    // Retry stuck refunds
    for (const [refundId, refund] of this.refunds.entries()) {
      if (refund.status === "approved" && !refund.refundedAt) {
        await this.processRefund(refundId);
      }
    }

    // Check reconciliation mismatches
    for (const [refundId, recon] of this.reconciliation.entries()) {
      if (!recon.reconciled) {
        recon.mismatchReason = "Reconciliation failed";
        recon.reconciledAt = nowIso();
        this.reconciliation.set(refundId, recon);
      }
    }
  }

  // Getters
  listRefunds(): RefundManagementRequest[] {
    return Array.from(this.refunds.values()).sort((a, b) => new Date(b.requestedAt).getTime() - new Date(a.requestedAt).getTime());
  }

  listDisputes(): DisputeCase[] {
    return Array.from(this.disputes.values()).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  listReconciliation(): FinancialReconciliation[] {
    return Array.from(this.reconciliation.values());
  }

  // Initialize mock data
  initializeMockData(): void {
    const mockRefund: RefundManagementRequest = {
      id: createId("refund-request"),
      orderId: "order-1",
      itemId: "item-1",
      itemName: "Premium WordPress Plugin",
      buyerId: "buyer-1",
      buyerName: "Alice Buyer",
      authorId: "author-1",
      authorName: "John Author",
      refundType: "full",
      requestedAmount: 29,
      reason: "Item not as described",
      status: "pending",
      requestedAt: nowIso(),
      isDispute: false,
      fraudFlagged: false,
      autoApproved: false,
      autoDenied: false,
    };

    this.refunds.set(mockRefund.id, mockRefund);
  }
}

