export const customersManagementService = new CustomersManagementService();

// ============================================
// MARKETPLACE MANAGER SERVICE (LIVE KPI TRACKING)
// ============================================

class MarketplaceManagerService {
  private auditService: AuditLogService;
  private itemsService: MarketplaceItemsService;
  private authorsService: MarketplaceAuthorsService;
  private payoutsService: AuthorPayoutsService;
  private reviewQueueService: ReviewQueueService;
  private collectionsService: MarketplaceCollectionsService;
  private categoriesService: MarketplaceCategoriesService;
  
  // Real-time KPI cache
  private kpiCache: MarketplaceManagerKPI | null = null;
  private kpiLastUpdated: number = 0;
  private kpiUpdateInterval: number = 5000; // 5 seconds
  
  // Real-time listeners
  private listeners: Set<(kpi: MarketplaceManagerKPI) => void> = new Set();
  private pollingInterval: NodeJS.Timeout | null = null;

  constructor() {
    this.auditService = auditLogService;
    this.itemsService = marketplaceItemsService;
    this.authorsService = marketplaceAuthorsService;
    this.payoutsService = authorPayoutsService;
    this.reviewQueueService = reviewQueueService;
    this.collectionsService = marketplaceCollectionsService;
    this.categoriesService = marketplaceCategoriesService;
  }

  // ============================================
  // LIVE KPI TRACKING
  // ============================================

  // Get Live KPIs
  getLiveKPIs(): MarketplaceManagerKPI {
    // Check cache
    const now = Date.now();
    if (this.kpiCache && (now - this.kpiLastUpdated) < this.kpiUpdateInterval) {
      return this.kpiCache;
    }

    // Calculate fresh KPIs
    const kpi = this.calculateKPIs();
    this.kpiCache = kpi;
    this.kpiLastUpdated = now;

    return kpi;
  }

  // Calculate KPIs from source services
  private calculateKPIs(): MarketplaceManagerKPI {
    const items = this.itemsService.getAllItems();
    const authors = this.authorsService.getAllAuthors();
    const payouts = this.payoutsService.filterPayouts({});
    const reviewItems = this.reviewQueueService.getAllReviewItems();
    const collections = this.collectionsService.listCollections();
    const categories = this.categoriesService.listCategories();

    // GMV (Gross Merchandise Value)
    const activeItems = items.filter((i) => i.status === "active");
    const gmv = activeItems.reduce((sum, i) => sum + (i.salesCount * i.basePrice), 0);

    // Take Rate (platform commission percentage)
    const totalRevenue = activeItems.reduce((sum, i) => sum + i.totalRevenue, 0);
    const takeRate = totalRevenue > 0 ? (gmv - totalRevenue) / gmv : 0;

    // Active Items
    const activeItemsCount = activeItems.length;

    // Active Authors
    const activeAuthorsCount = authors.filter((a) => a.status === "active" && a.itemsCount > 0).length;

    // Pending Reviews
    const pendingReviewsCount = reviewItems.filter((r) => r.status === "pending").length;

    // Reported Items
    const reportedItemsCount = items.filter((i) => i.isFlagged).length;

    // Pending Payouts
    const pendingPayouts = payouts.filter((p) => p.status === "pending");
    const pendingPayoutsAmount = pendingPayouts.reduce((sum, p) => sum + p.amount, 0);

    // Refund Rate
    const totalSales = items.reduce((sum, i) => sum + i.salesCount, 0);
    const totalRefunds = items.reduce((sum, i) => sum + (i.refundCount || 0), 0);
    const refundRate = totalSales > 0 ? totalRefunds / totalSales : 0;

    // Additional KPIs
    const totalItems = items.length;
    const totalAuthors = authors.length;
    const totalCollections = collections.length;
    const totalCategories = categories.length;
    const activeCollections = collections.filter((c) => c.status === "live").length;

    // Revenue metrics
    const monthlyRevenue = this.calculateMonthlyRevenue(items);
    const yearlyRevenue = this.calculateYearlyRevenue(items);

    // Author metrics
    const newAuthorsThisMonth = this.calculateNewAuthorsThisMonth(authors);
    const topSellingAuthors = this.getTopSellingAuthors(authors, 5);

    // Item metrics
    const newItemsThisMonth = this.calculateNewItemsThisMonth(items);
    const topSellingItems = this.getTopSellingItems(items, 5);

    return {
      gmv,
      takeRate: Math.round(takeRate * 10000) / 100,
      activeItems: activeItemsCount,
      activeAuthors: activeAuthorsCount,
      pendingReviews: pendingReviewsCount,
      reportedItems: reportedItemsCount,
      pendingPayouts: pendingPayoutsAmount,
      refundRate: Math.round(refundRate * 10000) / 100,
      totalItems,
      totalAuthors,
      totalCollections,
      totalCategories,
      activeCollections,
      monthlyRevenue,
      yearlyRevenue,
      newAuthorsThisMonth,
      newItemsThisMonth,
      topSellingAuthors,
      topSellingItems,
      lastUpdated: nowIso(),
    };
  }

  // Calculate Monthly Revenue
  private calculateMonthlyRevenue(items: MarketplaceItemRecord[]): number {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    
    return items.reduce((sum, item) => {
      const itemLastSale = item.lastSaleAt ? new Date(item.lastSaleAt) : null;
      if (itemLastSale && itemLastSale >= startOfMonth) {
        return sum + (item.salesCount * item.basePrice);
      }
      return sum;
    }, 0);
  }

  // Calculate Yearly Revenue
  private calculateYearlyRevenue(items: MarketplaceItemRecord[]): number {
    const now = new Date();
    const startOfYear = new Date(now.getFullYear(), 0, 1);
    
    return items.reduce((sum, item) => {
      const itemLastSale = item.lastSaleAt ? new Date(item.lastSaleAt) : null;
      if (itemLastSale && itemLastSale >= startOfYear) {
        return sum + (item.salesCount * item.basePrice);
      }
      return sum;
    }, 0);
  }

  // Calculate New Authors This Month
  private calculateNewAuthorsThisMonth(authors: MarketplaceAuthorRecord[]): number {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    
    return authors.filter((a) => new Date(a.createdAt) >= startOfMonth).length;
  }

  // Calculate New Items This Month
  private calculateNewItemsThisMonth(items: MarketplaceItemRecord[]): number {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    
    return items.filter((i) => new Date(i.createdAt) >= startOfMonth).length;
  }

  // Get Top Selling Authors
  private getTopSellingAuthors(authors: MarketplaceAuthorRecord[], limit: number): Array<{ id: string; name: string; sales: number; revenue: number }> {
    return authors
      .map((a) => ({
        id: a.id,
        name: a.authorName,
        sales: a.salesCount,
        revenue: a.totalEarnings,
      }))
      .sort((a, b) => b.sales - a.sales)
      .slice(0, limit);
  }

  // Get Top Selling Items
  private getTopSellingItems(items: MarketplaceItemRecord[], limit: number): Array<{ id: string; name: string; sales: number; revenue: number }> {
    return items
      .map((i) => ({
        id: i.id,
        name: i.itemName,
        sales: i.salesCount,
        revenue: i.totalRevenue,
      }))
      .sort((a, b) => b.sales - a.sales)
      .slice(0, limit);
  }

  // ============================================
  // REAL-TIME ENGINE
  // ============================================

  // Start Real-time Updates (Polling)
  startRealTimeUpdates(intervalMs: number = 5000): void {
    if (this.pollingInterval) {
      this.stopRealTimeUpdates();
    }

    this.kpiUpdateInterval = intervalMs;
    this.pollingInterval = setInterval(() => {
      const kpi = this.getLiveKPIs();
      this.notifyListeners(kpi);
    }, intervalMs);
  }

  // Stop Real-time Updates
  stopRealTimeUpdates(): void {
    if (this.pollingInterval) {
      clearInterval(this.pollingInterval);
      this.pollingInterval = null;
    }
  }

  // Subscribe to KPI Updates
  subscribeToKPIUpdates(callback: (kpi: MarketplaceManagerKPI) => void): () => void {
    this.listeners.add(callback);
    
    // Return unsubscribe function
    return () => {
      this.listeners.delete(callback);
    };
  }

  // Notify Listeners
  private notifyListeners(kpi: MarketplaceManagerKPI): void {
    this.listeners.forEach((callback) => {
      try {
        callback(kpi);
      } catch (error) {
        console.error("Error notifying KPI listener:", error);
      }
    });
  }

  // ============================================
  // SELF-HEALING LOGIC
  // ============================================

  // Self-Heal All
  async selfHeal(): Promise<SelfHealResult> {
    const results: SelfHealResult = {
      itemMetadataRegenerated: 0,
      payoutsRecalculated: 0,
      kpiRebuilt: false,
      reportsEscalated: 0,
      timestamp: nowIso(),
    };

    // Regenerate item metadata
    results.itemMetadataRegenerated = await this.healItemMetadata();

    // Recalculate payouts
    results.payoutsRecalculated = await this.healPayouts();

    // Rebuild KPI cache
    this.kpiCache = null;
    this.getLiveKPIs();
    results.kpiRebuilt = true;

    // Escalate stale reports
    results.reportsEscalated = await this.healStaleReports();

    // Log self-heal action
    await this.auditService.create({
      entityType: "marketplace_manager",
      entityId: "self-heal",
      action: "self_heal_completed",
      userId: "system",
      changes: results,
    });

    return results;
  }

  // Heal Item Metadata
  private async healItemMetadata(): Promise<number> {
    let healed = 0;
    const items = this.itemsService.getAllItems();

    for (const item of items) {
      let needsUpdate = false;

      // Check for missing or invalid metadata
      if (!item.slug || item.slug === "") {
        item.slug = this.generateSlug(item.itemName);
        needsUpdate = true;
      }

      if (item.rating < 0 || item.rating > 5) {
        item.rating = 0;
        needsUpdate = true;
      }

      if (item.salesCount < 0) {
        item.salesCount = 0;
        needsUpdate = true;
      }

      if (item.reviewCount < 0) {
        item.reviewCount = 0;
        needsUpdate = true;
      }

      if (needsUpdate) {
        item.updatedAt = nowIso();
        await this.itemsService.updateItem({
          id: item.id,
          itemName: item.itemName,
          slug: item.slug,
          description: item.description,
          categoryId: item.categoryId,
          basePrice: item.basePrice,
          currency: item.currency,
          userId: "system",
        });
        healed++;
      }
    }

    return healed;
  }

  // Heal Payouts
  private async healPayouts(): Promise<number> {
    let healed = 0;
    const payouts = this.payoutsService.filterPayouts({});

    for (const payout of payouts) {
      const author = this.authorsService.getAuthor(payout.authorId);
      
      if (!author) {
        // Orphaned payout - mark for review
        // In real system, would handle differently
        healed++;
        continue;
      }

      // Recalculate payout amount from author's pending earnings
      const expectedAmount = author.pendingEarnings;
      
      if (Math.abs(payout.amount - expectedAmount) > 0.01) {
        // Mismatch detected - in real system would trigger reconciliation
        healed++;
      }
    }

    return healed;
  }

  // Heal Stale Reports
  private async healStaleReports(): Promise<number> {
    let escalated = 0;
    const reviewItems = this.reviewQueueService.getAllReviewItems();
    const now = new Date();

    for (const item of reviewItems) {
      if (item.status === "pending") {
        const age = now.getTime() - new Date(item.submittedAt).getTime();
        const daysOld = age / (1000 * 60 * 60 * 24);

        // Auto-escalate if older than 7 days
        if (daysOld > 7) {
          // In real system, would escalate to senior reviewer
          escalated++;
        }
      }
    }

    return escalated;
  }

  // ============================================
  // UTILITY METHODS
  // ============================================

  // Generate Slug
  private generateSlug(name: string): string {
    return name
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-|-$/g, "");
  }

  // Force KPI Refresh
  forceKPIRefresh(): MarketplaceManagerKPI {
    this.kpiCache = null;
    return this.getLiveKPIs();
  }

  // Get KPI History (Stub - would store historical data in real system)
  getKPIHistory(days: number = 30): MarketplaceManagerKPI[] {
    // In real system, would query historical KPI data
    // For now, return current KPI as placeholder
    return [this.getLiveKPIs()];
  }

  // Initialize mock data
  initializeMockData(): void {
    // KPI cache will be populated on first call
    this.kpiCache = null;
  }
}

// Type definitions for Marketplace Manager
interface MarketplaceManagerKPI {
  gmv: number;
  takeRate: number;
  activeItems: number;
  activeAuthors: number;
  pendingReviews: number;
  reportedItems: number;
  pendingPayouts: number;
  refundRate: number;
  totalItems: number;
  totalAuthors: number;
  totalCollections: number;
  totalCategories: number;
  activeCollections: number;
  monthlyRevenue: number;
  yearlyRevenue: number;
  newAuthorsThisMonth: number;
  newItemsThisMonth: number;
  topSellingAuthors: Array<{ id: string; name: string; sales: number; revenue: number }>;
  topSellingItems: Array<{ id: string; name: string; sales: number; revenue: number }>;
  lastUpdated: string;
}

interface SelfHealResult {
  itemMetadataRegenerated: number;
  payoutsRecalculated: number;
  kpiRebuilt: boolean;
  reportsEscalated: number;
  timestamp: string;
}

